import React, { useState } from 'react';
import { useAuth } from '../contexts/AuthContext';
import { registerUserInDb } from '../services/firestore';
import type { UserProfile, HealthData } from '../types';
import { avatars } from '../components/Icons';

// Steps: 0=Auth, 1=Personal, 2=Contact, 3=DiaryPrefs, 4=Legal, 5=Avatar

const LoginScreen: React.FC = () => {
  const { signIn } = useAuth(); // Use generic auth method
  const [isRegistering, setIsRegistering] = useState(false); 
  const [step, setStep] = useState(0); 
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // --- Form State ---
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');

  const [personalData, setPersonalData] = useState({
      displayName: '',
      birthDate: '',
      gender: 'male', 
      height: '',
  });

  const [contactData, setContactData] = useState({
      nationality: 'Española',
      language: 'Español',
      emergencyName: '',
      emergencyPhone: '',
  });

  const [diaryFields, setDiaryFields] = useState<(keyof HealthData)[]>([
      'weight', 'systolicBP', 'diastolicBP', 'pulse', 'oxygenSaturation', 'glucose', 'falls'
  ]);

  const [legalData, setLegalData] = useState({
      hasLegalConsent: false,
      dataProcessingConsent: false,
      hasTutor: false,
      tutorName: '',
      tutorPhone: '',
  });

  const [avatarId, setAvatarId] = useState(0);

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);
    setLoading(true);
    try {
        // TODO: Replace with Supabase Login
        // const { error } = await supabase.auth.signInWithPassword(...)
        await signIn(email); 
    } catch (err: any) {
        setError("Error al iniciar sesión (Simulación).");
    } finally {
        setLoading(false);
    }
  };

  const handleNextStep = (e: React.FormEvent) => {
      e.preventDefault();
      if (step === 0) {
          if (password.length < 6) { setError("La contraseña debe tener al menos 6 caracteres."); return; }
          if (!email.includes('@')) { setError("Email inválido."); return; }
      }
      if (step === 1) {
          if (!personalData.displayName || !personalData.birthDate || !personalData.height) {
              setError("Por favor, complete todos los campos obligatorios.");
              return;
          }
      }
      if (step === 4) {
          if (!legalData.hasLegalConsent || !legalData.dataProcessingConsent) {
              setError("Debe aceptar los consentimientos legales para continuar.");
              return;
          }
      }

      setError(null);
      setStep(prev => prev + 1);
  };

  const handleDiaryFieldToggle = (field: keyof HealthData) => {
      setDiaryFields(prev => 
          prev.includes(field) 
              ? prev.filter(f => f !== field)
              : [...prev, field]
      );
  };

  const handleFinalRegister = async () => {
      setLoading(true);
      setError(null);
      try {
          // 1. Create Auth User (Supabase TODO)
          // const { data } = await supabase.auth.signUp(...)
          const uid = 'mock-new-user-id'; 

          // 2. Prepare Profile Object
