                            <input type="email" placeholder="ejemplo@correo.com" className="w-full p-3 border rounded-lg" value={email} onChange={e => setEmail(e.target.value)} required />
                        </div>
                        <div>
                            <label className="block text-brand-gray-700 font-medium mb-1">Contraseña</label>
                            <input type="password" placeholder="Mínimo 6 carácteres" className="w-full p-3 border rounded-lg" value={password} onChange={e => setPassword(e.target.value)} required />
                        </div>
                    </div>
                 </>
             );
          case 1: // Personal
             return (
                 <>
                    <h2 className="text-xl font-bold mb-4">Datos Personales</h2>
                    <div className="space-y-4">
                        <div className="p-1">
                            <label className="block text-brand-gray-700 font-bold mb-1">Nombre y Apellidos</label>
                            <input type="text" placeholder="Ej. María García" className="w-full p-3 border rounded-lg" value={personalData.displayName} onChange={e => setPersonalData({...personalData, displayName: e.target.value})} required />
