                        </label>
                    </div>
                 </>
             );
          case 5: // Avatar
             return (
                 <>
                    <h2 className="text-xl font-bold mb-4">Elija su imagen de perfil</h2>
                    <div className="grid grid-cols-3 gap-6">
                        {avatars.map((AvatarComp, index) => (
                            <button 
                                key={index} 
                                onClick={() => setAvatarId(index)}
                                className={`p-2 rounded-full transition-all flex items-center justify-center ${avatarId === index ? 'ring-4 ring-brand-blue bg-blue-50' : 'hover:bg-gray-50'}`}
                            >
                                <AvatarComp className="w-20 h-20" />
                            </button>
                        ))}
                    </div>
                 </>
             );
      }
  };

  if (isRegistering) {
      return (
        <div className="min-h-screen bg-brand-gray-100 flex flex-col justify-center items-center p-4">
            <div className="bg-white p-6 rounded-2xl shadow-xl w-full max-w-lg">
                <div className="flex gap-2 mb-6">
                    {[0, 1, 2, 3, 4, 5].map(i => (
                        <div key={i} className={`h-2 flex-1 rounded-full ${i <= step ? 'bg-brand-blue' : 'bg-gray-200'}`}></div>
                    ))}
                </div>
                <form onSubmit={step === 5 ? (e) => { e.preventDefault(); handleFinalRegister(); } : handleNextStep}>
                    {renderStepContent()}
                    {error && <div className="mt-4 p-3 bg-red-50 text-red-700 rounded-lg text-sm">{error}</div>}
                    <div className="mt-8 flex gap-4">
                        {step > 0 && <button type="button" onClick={() => setStep(s => s - 1)} className="flex-1 py-3 bg-gray-100 rounded-xl">Atrás</button>}
                        <button type="submit" disabled={loading} className="flex-1 py-3 bg-brand-blue text-white rounded-xl">
                            {loading ? 'Guardando...' : (step === 5 ? 'Finalizar' : 'Siguiente')}
                        </button>
                    </div>
                </form>
            </div>
        </div>
      );
  }

  return (
    <div className="min-h-screen bg-brand-gray-100 flex flex-col justify-center items-center p-4">
      <div className="bg-white p-8 rounded-2xl shadow-xl w-full max-w-md text-center">
        <h1 className="text-3xl font-bold text-brand-blue mb-2">Fisiosilver</h1>
        <p className="text-brand-gray-600 mb-8">Su asistente de salud personal</p>
        <form onSubmit={handleLogin} className="space-y-6 text-left">
          <div><label className="block mb-2">Email</label><input type="email" required value={email} onChange={e => setEmail(e.target.value)} className="w-full p-3 border rounded-lg" /></div>
          <div><label className="block mb-2">Contraseña</label><input type="password" required value={password} onChange={e => setPassword(e.target.value)} className="w-full p-3 border rounded-lg" /></div>
          {error && <div className="p-3 bg-red-50 text-red-700 rounded text-sm">{error}</div>}
          <button type="submit" disabled={loading} className="w-full bg-brand-blue text-white font-bold py-3 px-4 rounded-xl hover:bg-sky-700">
            {loading ? 'Entrando...' : 'Iniciar Sesión'}
          </button>
        </form>
        <div className="mt-8 pt-6 border-t border-gray-100">
            <button onClick={() => setIsRegistering(true)} className="w-full py-3 border-2 border-brand-blue text-brand-blue font-bold rounded-xl">Crear Cuenta Nueva</button>
        </div>
      </div>
    </div>
  );
};

