const EditProfileModal: React.FC<{ onClose: (updatedProfile?: UserProfile) => void }> = ({ onClose }) => {
    const { user } = useAuth();
    const context = useContext(AppContext);
    const { setDiaryPreferences } = context!;
    const [profile, setProfile] = useState<UserProfile | null>(null);
    const [loading, setLoading] = useState(true);
    const [saving, setSaving] = useState(false);
    const [activeTab, setActiveTab] = useState<'personal' | 'diary' | 'legal'>('personal');

    useEffect(() => {
        const fetchProfile = async () => {
            if (!user) return;
            const data = await getUserProfile(user.uid);
            if (data) {
                if(!data.diaryPreferences) {
                    data.diaryPreferences = ['weight', 'systolicBP', 'diastolicBP', 'pulse', 'oxygenSaturation', 'glucose', 'falls', 'calfCircumference', 'abdominalCircumference'];
                }
                setProfile(data);
            }
            setLoading(false);
        };
        fetchProfile();
    }, [user]);

    const handleSave = async () => {
        if (!user || !profile) return;
        setSaving(true);
        try {
            const safeProfile = { ...profile };
            if (safeProfile.healthData && safeProfile.healthData.height) {
                if (isNaN(safeProfile.healthData.height)) {
                    safeProfile.healthData.height = null;
                }
            }
            await updateUserProfile(user.uid, safeProfile);
            setDiaryPreferences(safeProfile.diaryPreferences); 
            onClose(safeProfile); 
        } catch (e) {
            console.error(e);
            alert("Error al guardar perfil.");
        } finally {
            setSaving(false);
        }
    };

    const toggleDiaryPref = (field: keyof HealthData) => {
        if (!profile) return;
        const current = profile.diaryPreferences || [];
        const updated = current.includes(field) ? current.filter(f => f !== field) : [...current, field];
        setProfile({ ...profile, diaryPreferences: updated });
    };

    if (loading) return <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50"><div className="bg-white p-6 rounded-lg">Cargando...</div></div>;
    if (!profile) return null;

    const AvatarComp = avatars[profile.avatarId] || avatars[0];
    const diaryOptions: {id: keyof HealthData, label: string}[] = [
        { id: 'weight', label: 'Peso' }, { id: 'systolicBP', label: 'T. Sistólica' }, { id: 'diastolicBP', label: 'T. Diastólica' },
        { id: 'pulse', label: 'Pulso' }, { id: 'oxygenSaturation', label: 'Saturación O2' }, { id: 'glucose', label: 'Glucosa' },
        { id: 'falls', label: 'Caídas' }, { id: 'calfCircumference', label: 'Pantorrilla' }, { id: 'abdominalCircumference', label: 'Abdomen' },
    ];

    return (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm animate-fade-in">
            <div className="bg-white rounded-2xl shadow-2xl w-full max-w-2xl h-[90vh] flex flex-col overflow-hidden">
                <div className="flex justify-between items-center p-4 border-b border-gray-100 bg-gray-50">
                    <h3 className="text-2xl font-bold text-brand-gray-800">Editar Perfil</h3>
                    <button onClick={() => onClose()} className="text-gray-500 hover:text-red-500"><XMarkIcon /></button>
                </div>
                <div className="flex-1 overflow-y-auto p-6">
                    <div className="flex flex-col items-center mb-8">
                        <AvatarComp className="w-24 h-24 mb-4" />
                        <div className="flex gap-2 overflow-x-auto p-2 w-full justify-center">
                            {avatars.map((A, i) => (
                                <button key={i} onClick={() => setProfile({...profile, avatarId: i})} className={`p-1 rounded-full transition-all flex items-center justify-center ${profile.avatarId === i ? 'ring-4 ring-brand-blue bg-blue-50' : 'hover:bg-gray-50'}`}>
                                    <A className="w-12 h-12" />
                                </button>
                            ))}
                        </div>
                    </div>
                    <div className="flex border-b mb-6 overflow-x-auto">
                        <button onClick={() => setActiveTab('personal')} className={`flex-1 py-2 font-bold whitespace-nowrap px-4 ${activeTab === 'personal' ? 'text-brand-blue border-b-2 border-brand-blue' : 'text-gray-500'}`}>Datos Personales</button>
                        <button onClick={() => setActiveTab('diary')} className={`flex-1 py-2 font-bold whitespace-nowrap px-4 ${activeTab === 'diary' ? 'text-brand-blue border-b-2 border-brand-blue' : 'text-gray-500'}`}>Conf. Diario</button>
                        <button onClick={() => setActiveTab('legal')} className={`flex-1 py-2 font-bold whitespace-nowrap px-4 ${activeTab === 'legal' ? 'text-brand-blue border-b-2 border-brand-blue' : 'text-gray-500'}`}>Datos Legales</button>
                    </div>
                    {activeTab === 'personal' && (
                        <div className="space-y-4">
                            <div><label className="block text-sm font-bold text-gray-700">Nombre</label><input className="w-full border p-2 rounded" value={profile.displayName} onChange={e => setProfile({...profile, displayName: e.target.value})} /></div>
                            <div>
                                <label className="block text-sm font-bold text-gray-700">Altura (cm)</label>
                                <input type="number" className="w-full border p-2 rounded" value={profile.healthData.height || ''} onChange={e => { const val = parseFloat(e.target.value); setProfile({...profile, healthData: {...profile.healthData, height: isNaN(val) ? null : val}}); }} />
                            </div>
                        </div>
                    )}
                    {activeTab === 'diary' && (
                        <div className="space-y-4">
                            {diaryOptions.map(opt => (
                                <label key={opt.id} className={`flex items-center p-3 rounded-lg border cursor-pointer transition-colors ${profile.diaryPreferences?.includes(opt.id) ? 'bg-blue-50 border-brand-blue' : 'bg-gray-50'}`}>
                                    <input type="checkbox" checked={profile.diaryPreferences?.includes(opt.id)} onChange={() => toggleDiaryPref(opt.id)} className="w-5 h-5 text-brand-blue rounded"/>
                                    <span className="ml-3 font-bold text-gray-700">{opt.label}</span>
                                </label>
                            ))}
                        </div>
                    )}
                </div>
                <div className="p-4 border-t bg-gray-50 flex gap-4">
                    <button onClick={() => onClose()} className="flex-1 py-3 bg-gray-200 rounded-xl font-bold">Cancelar</button>
                    <button onClick={handleSave} disabled={saving} className="flex-1 py-3 bg-brand-blue text-white rounded-xl font-bold">{saving ? 'Guardando...' : 'Guardar Cambios'}</button>
                </div>
            </div>
        </div>
    );
};

