export const initializeUser = async (uid: string, email: string): Promise<UserProfile> => {
    try {
        const { data, error } = await supabase
            .from('profiles')
            .select('*')
            .eq('id', uid)
            .single();

        if (error || !data) {
            // If profile doesn't exist but auth does, we return a basic template
            // Note: Ideally you create profile on signup (see registerUserInDb)
            console.warn("Profile not found, returning default structure", error);
            return {
                email,
                displayName: 'Usuario',
                birthDate: '',
                gender: 'male',
                nationality: 'España',
                language: 'Español',
                emergencyContactName: '',
                emergencyContactPhone: '',
                hasLegalConsent: false,
                dataProcessingConsent: false,
                avatarId: 0,
                diaryPreferences: [],
                healthData: {
                    weight: null, falls: null, systolicBP: null, diastolicBP: null, pulse: null,
                    oxygenSaturation: null, glucose: null, calfCircumference: null, abdominalCircumference: null
                },
                vigsScore: { score: 0, category: 'Robusto' },
                alerts: []
            };
        }

        // Map snake_case DB columns to camelCase TS interface if needed
        // Assuming DB uses JSONB for complex objects: health_data, vigs_score, alerts
        return {
            email: data.email || email,
            displayName: data.display_name,
            birthDate: data.birth_date,
            gender: data.gender,
            nationality: data.nationality,
            language: data.language,
            emergencyContactName: data.emergency_contact_name,
            emergencyContactPhone: data.emergency_contact_phone,
            hasLegalConsent: data.has_legal_consent,
            dataProcessingConsent: data.data_processing_consent,
            avatarId: data.avatar_id,
            diaryPreferences: data.diary_preferences || [],
            healthData: data.health_data || {},
            vigsScore: data.vigs_score || { score: 0, category: 'Robusto' },
            alerts: data.alerts || []
        };
    } catch (e) {
        console.error("Error initializing user:", e);
        throw e;
    }
};

export const getUserProfile = async (uid: string): Promise<UserProfile | null> => {
    return initializeUser(uid, ""); // Email might be refreshed from context
}

export const registerUserInDb = async (uid: string, profileData: UserProfile) => {
    // Map TS object to DB columns
    const dbProfile = {
        id: uid,
        email: profileData.email,
        display_name: profileData.displayName,
        birth_date: profileData.birthDate,
        gender: profileData.gender,
        nationality: profileData.nationality,
        language: profileData.language,
        emergency_contact_name: profileData.emergencyContactName,
        emergency_contact_phone: profileData.emergencyContactPhone,
        has_legal_consent: profileData.hasLegalConsent,
        data_processing_consent: profileData.dataProcessingConsent,
        avatar_id: profileData.avatarId,
        diary_preferences: profileData.diaryPreferences,
        health_data: profileData.healthData,
        vigs_score: profileData.vigsScore,
        alerts: profileData.alerts,
        updated_at: new Date()
    };

    const { error } = await supabase.from('profiles').insert(dbProfile);
    if (error) throw error;
}

export const updateUserProfile = async (uid: string, data: Partial<UserProfile>) => {
    // Partial mapping
    const dbUpdate: any = { updated_at: new Date() };
    if (data.displayName) dbUpdate.display_name = data.displayName;
    if (data.healthData) dbUpdate.health_data = data.healthData;
    if (data.vigsScore) dbUpdate.vigs_score = data.vigsScore;
    if (data.alerts) dbUpdate.alerts = data.alerts;
    if (data.diaryPreferences) dbUpdate.diary_preferences = data.diaryPreferences;
    if (data.avatarId !== undefined) dbUpdate.avatar_id = data.avatarId;
    if (data.healthData?.height) {
        // We might want to merge healthData carefully if we don't want to overwrite
        // But for this simple implementation, we assume `data.healthData` contains the full object or we use jsonb_set in SQL.
        // Here we just send the object provided by the frontend.
        dbUpdate.health_data = data.healthData;
    }

    const { error } = await supabase.from('profiles').update(dbUpdate).eq('id', uid);
    if (error) throw error;
};

// --- Daily Logs (History) ---

export const saveDailyLog = async (uid: string, data: HealthData) => {
    // We save a history log AND update the current profile health data
    const logEntry = {
        user_id: uid,
        created_at: new Date(),
        weight: data.weight,
        systolic_bp: data.systolicBP,
        diastolic_bp: data.diastolicBP,
        pulse: data.pulse,
        oxygen_saturation: data.oxygenSaturation,
        glucose: data.glucose,
        falls: data.falls,
        calf_circumference: data.calfCircumference,
        abdominal_circumference: data.abdominalCircumference
    };

    const { error: logError } = await supabase.from('daily_logs').insert(logEntry);
    if (logError) throw logError;

    // Update current profile stats
    await updateUserProfile(uid, { healthData: data });
};

export const getDailyHistory = async (uid: string, limitCount = 30): Promise<(HealthData & { createdAt: Date })[]> => {
    const { data, error } = await supabase
        .from('daily_logs')
        .select('*')
        .eq('user_id', uid)
        .order('created_at', { ascending: true }) // Ascending for charts
        .limit(limitCount);

    if (error) throw error;

    return (data || []).map((row: any) => ({
        createdAt: new Date(row.created_at),
        weight: row.weight,
        systolicBP: row.systolic_bp,
        diastolicBP: row.diastolic_bp,
        pulse: row.pulse,
        oxygenSaturation: row.oxygen_saturation,
        glucose: row.glucose,
        falls: row.falls,
        calfCircumference: row.calf_circumference,
        abdominalCircumference: row.abdominal_circumference
    }));
};

