      if (step === 4) {
          if (!legalData.hasLegalConsent || !legalData.dataProcessingConsent) {
              setError("Debe aceptar los consentimientos legales para continuar.");
              return;
          }
      }

      setError(null);
      setStep(prev => prev + 1);
  };

  const handleDiaryFieldToggle = (field: keyof HealthData) => {
      setDiaryFields(prev => 
          prev.includes(field) 
              ? prev.filter(f => f !== field)
              : [...prev, field]
      );
  };

  const handleFinalRegister = async () => {
      setLoading(true);
      setError(null);
      try {
          // 1. Create Auth User in Supabase
          const authData = await signUp(email, password);

          const uid = authData.user?.id;
          if (!uid) throw new Error("No se pudo obtener el ID de usuario.");

          // 2. Prepare Profile Object
          const newProfile: UserProfile = {
              email: email,
              displayName: personalData.displayName,
              birthDate: personalData.birthDate,
              gender: personalData.gender as 'male' | 'female' | 'other',
              nationality: contactData.nationality,
              language: contactData.language,
