              },
              vigsScore: { score: 0, category: 'Robusto' },
              alerts: [{ id: 1, type: 'info', title: 'Bienvenido', message: 'Registro completado con éxito.' }]
          };

          // 3. Save Profile to DB 'profiles' table
          await registerUserInDb(uid, newProfile);

          // 4. Automatically logs in via AuthContext subscription usually, but just in case:
          // If email confirmation is off, the user session is active.

      } catch (err: any) {
          console.error(err);
          setError(err.message || "Error en el registro.");
          setLoading(false);
      }
  };

  const renderStepContent = () => {
      switch(step) {
          case 0: // Auth
             return (
                 <>
