          // If the AuthContext doesn't update (e.g. requires email verification), 
          // we might want to show a message.
          if (!authData.session) {
             setError("Cuenta creada. Por favor, confirme su email para entrar.");
             setLoading(false);
             // Return to login screen or show success message
             setIsRegistering(false); 
             return;
          }

