                            <select className="w-full p-3 border rounded-lg bg-white text-gray-900 focus:ring-brand-blue focus:border-brand-blue" value={personalData.gender} onChange={e => setPersonalData({...personalData, gender: e.target.value})}>
                                <option value="male" className="text-gray-900">Hombre</option>
                                <option value="female" className="text-gray-900">Mujer</option>
                                <option value="other" className="text-gray-900">Otro</option>
                            </select>
                        </div>
                        <div className="p-1">
                            <label className="block text-brand-gray-700 font-bold mb-1">Altura (cm)</label>
                            <input type="number" placeholder="Ej. 165" className="w-full p-3 border rounded-lg" value={personalData.height} onChange={e => setPersonalData({...personalData, height: e.target.value})} required />
                        </div>
                    </div>
                 </>
             );
          case 2: // Contact
             return (
                 <>
                    <h2 className="text-xl font-bold mb-4">Contacto</h2>
                    <div className="space-y-4">
                         <div>
                            <label className="block text-brand-gray-700 font-medium mb-1">Nacionalidad</label>
                            <input type="text" placeholder="Ej. Española" className="w-full p-3 border rounded-lg" value={contactData.nationality} onChange={e => setContactData({...contactData, nationality: e.target.value})} />
                         </div>
                         <div>
                            <label className="block text-brand-gray-700 font-medium mb-1">Idioma preferido</label>
                            <input type="text" placeholder="Ej. Español" className="w-full p-3 border rounded-lg" value={contactData.language} onChange={e => setContactData({...contactData, language: e.target.value})} />
                         </div>
                    </div>
                 </>
             );
          case 3: // Diary Preferences
            const fields: {id: keyof HealthData, label: string}[] = [
                { id: 'weight', label: 'Peso (kg)' },
                { id: 'systolicBP', label: 'T. Sistólica (Alta)' },
                { id: 'diastolicBP', label: 'T. Diastólica (Baja)' },
                { id: 'pulse', label: 'Pulso (lpm)' },
                { id: 'oxygenSaturation', label: 'Saturación O2' },
                { id: 'glucose', label: 'Glucosa (mg/dl)' },
                { id: 'falls', label: 'Registro de Caídas' },
                { id: 'calfCircumference', label: 'Perímetro Pantorrilla' },
                { id: 'abdominalCircumference', label: 'Perímetro Abdominal' },
            ];
            return (
                <>
