            <div className="bg-white p-6 rounded-2xl shadow-xl w-full max-w-lg">
                <div className="flex gap-2 mb-6">
                    {[0, 1, 2, 3, 4, 5].map(i => (
                        <div key={i} className={`h-2 flex-1 rounded-full ${i <= step ? 'bg-brand-blue' : 'bg-gray-200'}`}></div>
                    ))}
                </div>
                <form onSubmit={step === 5 ? (e) => { e.preventDefault(); handleFinalRegister(); } : handleNextStep}>
                    {renderStepContent()}
                    {error && <div className="mt-4 p-3 bg-red-50 text-red-700 rounded-lg text-sm">{error}</div>}
                    <div className="mt-8 flex gap-4">
                        {step > 0 && <button type="button" onClick={() => setStep(s => s - 1)} className="flex-1 py-3 bg-gray-100 rounded-xl">Atrás</button>}
