import { createClient } from '@supabase/supabase-js';

const supabaseUrl = (process.env as any).REACT_APP_SUPABASE_URL || 'https://your-project.supabase.co';
const supabaseKey = (process.env as any).REACT_APP_SUPABASE_ANON_KEY || 'your-anon-key';

export const supabase = createClient(supabaseUrl, supabaseKey);

import { supabase } from './supabaseClient';
import type { UserProfile, HealthData, ClinicalAnalysis, NutritionalAnalysis } from '../types';

const isDemo = !((process.env as any).REACT_APP_SUPABASE_URL);

const getLocal = (key: string) => {
    const val = localStorage.getItem(key);
    return val ? JSON.parse(val) : null;
};

const setLocal = (key: string, val: any) => {
    localStorage.setItem(key, JSON.stringify(val));
};

export const initializeUser = async (uid: string, email: string): Promise<UserProfile> => {
    if (isDemo) {
        const profile = getLocal(`profile_${uid}`);
        if (profile) return profile;
        const newProfile: UserProfile = {
            email,
            displayName: 'Usuario Demo',
            birthDate: '1955-06-15',
            gender: 'male',
            nationality: 'Española',
            language: 'Español',
            emergencyContactName: 'Hijo Pedro',
            emergencyContactPhone: '600000000',
            hasLegalConsent: true,
            dataProcessingConsent: true,
            avatarId: 0,
            diaryPreferences: ['weight', 'systolicBP', 'diastolicBP', 'pulse', 'glucose'],
            healthData: { weight: 75, falls: 0, systolicBP: 125, diastolicBP: 82, pulse: 72, oxygenSaturation: 97, glucose: 95, calfCircumference: 36, abdominalCircumference: 92 },
            vigsScore: { score: 2, category: 'Robusto' },
            alerts: []
        };
        setLocal(`profile_${uid}`, newProfile);
        return newProfile;
    }

    const { data, error } = await supabase.from('users').select('*').eq('id', uid).single();
    if (error || !data) throw new Error("User not found");
    return data as UserProfile;
};

export const getUserProfile = async (uid: string): Promise<UserProfile | null> => {
    if (isDemo) return getLocal(`profile_${uid}`);
    const { data } = await supabase.from('users').select('*').eq('id', uid).single();
    return data as UserProfile;
};

export const updateUserProfile = async (uid: string, profile: Partial<UserProfile>): Promise<void> => {
    if (isDemo) {
        const current = getLocal(`profile_${uid}`) || {};
        setLocal(`profile_${uid}`, { ...current, ...profile });
        return;
    }
    await supabase.from('users').update(profile).eq('id', uid);
};

export const registerUserInDb = async (uid: string, profile: UserProfile): Promise<void> => {
    if (isDemo) {
        setLocal(`profile_${uid}`, profile);
        return;
    }
    await supabase.from('users').insert({ id: uid, ...profile });
};

export const getClinicalReports = async (uid: string): Promise<ClinicalAnalysis[]> => {
    if (isDemo) return getLocal(`clinical_${uid}`) || [];
    const { data } = await supabase.from('clinical_reports').select('*').eq('user_id', uid).order('createdAt', { ascending: false });
    return (data || []).map(d => ({...d, createdAt: new Date(d.createdAt)}));
};

export const saveClinicalReport = async (uid: string, analysis: ClinicalAnalysis): Promise<void> => {
    if (isDemo) {
        const current = getLocal(`clinical_${uid}`) || [];
        setLocal(`clinical_${uid}`, [analysis, ...current]);
        return;
    }
    await supabase.from('clinical_reports').insert({ user_id: uid, ...analysis });
};

export const getNutritionLogs = async (uid: string): Promise<NutritionalAnalysis[]> => {
    if (isDemo) return getLocal(`nutrition_${uid}`) || [];
    const { data } = await supabase.from('nutrition_logs').select('*').eq('user_id', uid).order('createdAt', { ascending: false });
    return (data || []).map(d => ({...d, createdAt: new Date(d.createdAt)}));
};

export const saveNutritionLog = async (uid: string, analysis: NutritionalAnalysis): Promise<void> => {
    if (isDemo) {
        const current = getLocal(`nutrition_${uid}`) || [];
        setLocal(`nutrition_${uid}`, [analysis, ...current]);
        return;
    }
    await supabase.from('nutrition_logs').insert({ user_id: uid, ...analysis });
};

export const getDailyHistory = async (uid: string): Promise<(HealthData & { createdAt: Date })[]> => {
    if (isDemo) return (getLocal(`history_${uid}`) || []).map((d: any) => ({...d, createdAt: new Date(d.createdAt)}));
    const { data } = await supabase.from('daily_logs').select('*').eq('user_id', uid).order('createdAt', { ascending: false });
    return (data || []).map(d => ({...d, createdAt: new Date(d.createdAt)}));
};

export const saveDailyLog = async (uid: string, healthData: HealthData): Promise<void> => {
    const entry = { ...healthData, createdAt: new Date().toISOString() };
    if (isDemo) {
        const current = getLocal(`history_${uid}`) || [];
        setLocal(`history_${uid}`, [entry, ...current]);
        return;
    }
    await supabase.from('daily_logs').insert({ user_id: uid, ...entry });
};

export const saveAppointment = async (uid: string, title: string, description: string): Promise<void> => {
    const entry = { title, description, status: 'pending', createdAt: new Date().toISOString() };
    if (isDemo) {
        const current = getLocal(`appointments_${uid}`) || [];
        setLocal(`appointments_${uid}`, [entry, ...current]);
        return;
    }
    await supabase.from('appointments').insert({ user_id: uid, ...entry });
};

import React, { createContext, useState, useEffect, useContext } from 'react';
import { supabase } from '../services/supabaseClient';

interface User {
    uid: string;
    email: string | null;
}

interface AuthContextType {
  user: User | null;
  loading: boolean;
  signIn: (email: string, password?: string) => Promise<void>;
  signUp: (email: string, password: string) => Promise<{ uid: string } | null>;
  signOut: () => Promise<void>;
}

const AuthContext = createContext<AuthContextType>({ 
    user: null, 
    loading: true,
    signIn: async () => {},
    signUp: async () => null,
    signOut: async () => {} 
});

export const AuthProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<User | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const checkUser = async () => {
        const { data: { session } } = await supabase.auth.getSession();
        if (session?.user) {
            setUser({ uid: session.user.id, email: session.user.email || null });
        }
        setLoading(false);
    };

    checkUser();

    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      if (session?.user) {
        setUser({ uid: session.user.id, email: session.user.email || null });
      } else {
        setUser(null);
      }
    });

    return () => subscription.unsubscribe();
  }, []);

  const signIn = async (email: string, password?: string) => {
      if (!password) {
          // Demo/Mock logic if no password provided (for testing UI)
          setUser({ uid: 'mock-user-id', email });
          return;
      }
      const { error } = await supabase.auth.signInWithPassword({ email, password });
      if (error) throw error;
  };

  const signUp = async (email: string, password: string) => {
      const { data, error } = await supabase.auth.signUp({ email, password });
      if (error) throw error;
      return data.user ? { uid: data.user.id } : null;
  };

  const signOut = async () => {
      await supabase.auth.signOut();
      setUser(null);
  };

  return (
    <AuthContext.Provider value={{ user, loading, signIn, signUp, signOut }}>
      {!loading && children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => useContext(AuthContext);

import { GoogleGenAI, Type } from "@google/genai";
import type { ClinicalAnalysisResult, NutritionalAnalysisResult, HealthData, VigsScore } from "../types";

// Always use the named parameter `apiKey` and the environment variable directly.
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const fileToGenerativePart = async (file: File) => {
  const base64EncodedDataPromise = new Promise<string>((resolve) => {
    const reader = new FileReader();
    reader.onloadend = () => resolve((reader.result as string).split(',')[1]);
    reader.readAsDataURL(file);
  });
  return {
    inlineData: { data: await base64EncodedDataPromise, mimeType: file.type },
  };
};

export const analyzeClinicalReport = async (file: File): Promise<ClinicalAnalysisResult> => {
  try {
    const imagePart = await fileToGenerativePart(file);
    const prompt = `
      Eres un asistente médico especializado en geriatría.
      Analiza el siguiente informe clínico.
      Tu objetivo es EXTRAER EXCLUSIVAMENTE los valores de los siguientes 10 biomarcadores específicos.

      Lista de biomarcadores a extraer:
      1. Hemoglobina
      2. Albúmina
      3. Vitamina D (25-OH-D)
      4. Glucosa en Ayunas
      5. Tasa de Filtración Glomerular (eGFR)
      6. Sodio (Na+)
      7. Proteína C Reactiva (PCR)
      8. Vitamina B12
      9. TSH (Hormona Tiroidea)
      10. Creatinina sérica

      Instrucciones:
      - Si encuentras el valor, extrae el número y la unidad (ej. "12 g/dL").
      - Si NO encuentras el valor, escribe exactamente "No encontrado".
      - Proporciona un breve resumen general del estado del paciente basado en estos datos.
      - Proporciona 2-3 recomendaciones generales de salud.

      Devuelve los resultados SOLAMENTE en el formato JSON especificado.
    `;
    // Using 'gemini-3-pro-preview' for complex clinical data extraction task.
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: { parts: [imagePart, { text: prompt }] },
      config: {
