// --- Component ---

type ConversationTurn = {
    speaker: 'user' | 'model' | 'system';
    text: string;
};

interface VoiceAssistantScreenProps {
  onClose: () => void;
}

const VoiceAssistantScreen: React.FC<VoiceAssistantScreenProps> = ({ onClose }) => {
    const { user } = useAuth();
    const context = useContext(AppContext);
    // Access context setters to update UI in real-time
    const { healthData, vigsScore, setHealthData, setAlerts } = context!;

    const [connectionState, setConnectionState] = useState<'idle' | 'connecting' | 'connected' | 'error'>('idle');
    const [conversation, setConversation] = useState<ConversationTurn[]>([]);
    const [currentInput, setCurrentInput] = useState('');
    const [currentOutput, setCurrentOutput] = useState('');
    const [errorMessage, setErrorMessage] = useState('');

    // Removing LiveSession type as it is not exported.
    const sessionRef = useRef<any>(null);
    const mediaStreamRef = useRef<MediaStream | null>(null);
    const inputAudioContextRef = useRef<AudioContext | null>(null);
    const outputAudioContextRef = useRef<AudioContext | null>(null);
    const scriptProcessorRef = useRef<ScriptProcessorNode | null>(null);
    const mediaStreamSourceRef = useRef<MediaStreamAudioSourceNode | null>(null);

    const nextStartTimeRef = useRef(0);
    const outputSourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
    const conversationEndRef = useRef<HTMLDivElement>(null);

    // Keep latest healthData in ref for merging
    const healthDataRef = useRef(healthData);
    useEffect(() => { healthDataRef.current = healthData; }, [healthData]);


    const cleanup = () => {
        console.log("Cleaning up resources...");
        sessionRef.current?.close();
        sessionRef.current = null;

        mediaStreamRef.current?.getTracks().forEach(track => track.stop());
        mediaStreamRef.current = null;

        if (scriptProcessorRef.current) {
            scriptProcessorRef.current.onaudioprocess = null;
            scriptProcessorRef.current.disconnect();
            scriptProcessorRef.current = null;
        }
        mediaStreamSourceRef.current?.disconnect();
        mediaStreamSourceRef.current = null;

        inputAudioContextRef.current?.close().catch(console.error);
        inputAudioContextRef.current = null;
        outputAudioContextRef.current?.close().catch(console.error);
        outputAudioContextRef.current = null;

        outputSourcesRef.current.forEach(source => source.stop());
        outputSourcesRef.current.clear();
        nextStartTimeRef.current = 0;
    };

    const stopConversation = () => {
        cleanup();
        setConnectionState('idle');
    };

    const startConversation = async () => {
        if (!user) return;

        setConnectionState('connecting');
        setErrorMessage('');
        setConversation([]);
        setCurrentInput('');
        setCurrentOutput('');

        try {
            if (!navigator.mediaDevices || !navigator.mediaDevices.getUserMedia) {
                throw new Error("Su navegador no soporta el acceso al micrófono.");
            }
            const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
            mediaStreamRef.current = stream;

            inputAudioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
            outputAudioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });

            // Initializing with correct apiKey format as per guidelines.
            const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

            const sessionPromise = ai.live.connect({
                model: 'gemini-2.5-flash-native-audio-preview-12-2025',
                callbacks: {
                    onopen: () => {
                        console.log('Connection opened.');
                        const source = inputAudioContextRef.current!.createMediaStreamSource(stream);
                        mediaStreamSourceRef.current = source;
                        const scriptProcessor = inputAudioContextRef.current!.createScriptProcessor(4096, 1, 1);
                        scriptProcessorRef.current = scriptProcessor;

                        scriptProcessor.onaudioprocess = (audioProcessingEvent) => {
                            const inputData = audioProcessingEvent.inputBuffer.getChannelData(0);
                            const pcmBlob = createBlob(inputData);
                            // Initiating sendRealtimeInput after connect resolves.
                            sessionPromise.then((session) => {
                                session.sendRealtimeInput({ media: pcmBlob });
                            });
                        };
                        source.connect(scriptProcessor);
                        scriptProcessor.connect(inputAudioContextRef.current!.destination);
                    },
                    onmessage: async (message: LiveServerMessage) => {
                        // Handle Tool Calls (Saving Data & Appointments)
                        if (message.toolCall) {
                            for (const fc of message.toolCall.functionCalls) {
                                if (fc.name === 'saveHealthData') {
                                    try {
                                        // 1. Merge new data with existing
                                        const newData = fc.args as Partial<HealthData>;
                                        const mergedData = { ...healthDataRef.current, ...newData };

                                        // 2. Save to Firestore
                                        await saveDailyLog(user.uid, mergedData);
                                        const newAlerts = [
                                            { id: Date.now(), type: 'success' as const, title: 'Datos de Voz', message: 'Datos guardados por el asistente.' },
                                            ...context!.alerts.filter(a => a.type !== 'success')
                                        ];
                                        await updateUserProfile(user.uid, { alerts: newAlerts });

                                        // 3. Update Context
                                        setHealthData(mergedData);
                                        setAlerts(newAlerts);

                                        // 4. Show system message
                                        const savedText = Object.entries(newData)
                                            .map(([key, val]) => `${key}: ${val}`)
                                            .join(', ');

                                        setConversation(prev => [...prev, { 
                                            speaker: 'system', 
                                            text: `Datos guardados: ${savedText}` 
                                        }]);

                                        sessionPromise.then((session) => {
                                            session.sendToolResponse({
                                                functionResponses: {
                                                    id: fc.id,
                                                    name: fc.name,
                                                    response: { result: "Success. Data saved." }
                                                }
                                            });
                                        });

                                    } catch (err) {
                                        sessionPromise.then((session) => {
                                            session.sendToolResponse({
                                                functionResponses: {
                                                    id: fc.id,
                                                    name: fc.name,
                                                    response: { error: "Failed to save data." }
                                                }
                                            });
                                        });
                                    }
                                } else if (fc.name === 'scheduleAppointment') {
                                    try {
                                        const { title, dateTimeDescription } = fc.args as any;
                                        await saveAppointment(user.uid, title, dateTimeDescription);

                                        setConversation(prev => [...prev, { 
                                            speaker: 'system', 
                                            text: `Cita guardada: ${title} (${dateTimeDescription})` 
                                        }]);

                                        sessionPromise.then((session) => {
                                            session.sendToolResponse({
                                                functionResponses: {
                                                    id: fc.id,
                                                    name: fc.name,
                                                    response: { result: "Success. Appointment saved." }
                                                }
                                            });
                                        });
                                    } catch (err) {
                                         sessionPromise.then((session) => {
                                            session.sendToolResponse({
                                                functionResponses: {
                                                    id: fc.id,
                                                    name: fc.name,
                                                    response: { error: "Failed to save appointment." }
                                                }
                                            });
                                        });
                                    }
                                }
                            }
                        }

                        // Handle transcriptions
                        if (message.serverContent?.inputTranscription) {
                            setCurrentInput(prev => prev + message.serverContent!.inputTranscription!.text);
                        }
                        if (message.serverContent?.outputTranscription) {
                            setCurrentOutput(prev => prev + message.serverContent!.outputTranscription!.text);
                        }
                        if (message.serverContent?.turnComplete) {
                            const finalInput = currentInput + (message.serverContent.inputTranscription?.text || '');
                            const finalOutput = currentOutput + (message.serverContent.outputTranscription?.text || '');

                            if (finalInput.trim() || finalOutput.trim()) {
                                setConversation(prev => [
                                    ...prev,
                                    { speaker: 'user', text: finalInput },
                                    { speaker: 'model', text: finalOutput }
                                ]);
                            }
                            setCurrentInput('');
                            setCurrentOutput('');
                        }

                        // Handle audio output using recommended method.
                        const base64Audio = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
                        if (base64Audio) {
                            const outputCtx = outputAudioContextRef.current!;
                            // tracking playback queue.
                            nextStartTimeRef.current = Math.max(nextStartTimeRef.current, outputCtx.currentTime);
                            const audioBuffer = await decodeAudioData(decode(base64Audio), outputCtx, 24000, 1);

                            const source = outputCtx.createBufferSource();
                            source.buffer = audioBuffer;
                            source.connect(outputCtx.destination);

                            source.addEventListener('ended', () => {
                                outputSourcesRef.current.delete(source);
                            });

                            source.start(nextStartTimeRef.current);
                            nextStartTimeRef.current += audioBuffer.duration;
                            outputSourcesRef.current.add(source);
                        }

                        // Handle interruption
                         if (message.serverContent?.interrupted) {
                            for (const source of outputSourcesRef.current.values()) {
                                source.stop();
                                outputSourcesRef.current.delete(source);
                            }
                            nextStartTimeRef.current = 0;
                        }
                    },
                    onerror: (e: ErrorEvent) => {
                        console.error('Connection error:', e);
                        setErrorMessage('Se ha producido un error de conexión. Por favor, inténtelo de nuevo.');
                        setConnectionState('error');
                    },
                    onclose: (e: CloseEvent) => {
                        console.log('Connection closed.');
                    },
                },
                config: {
                    responseModalities: [Modality.AUDIO],
                    inputAudioTranscription: {},
                    outputAudioTranscription: {},
                    tools: [{ functionDeclarations: [saveHealthDataTool, scheduleAppointmentTool] }],
                    speechConfig: {
                        voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } },
                    },
                    systemInstruction: `
                        Eres un asistente de salud geriátrica amable, empático y paciente.
                        Tienes acceso a los datos de salud actuales del paciente.

                        CONTEXTO DEL PACIENTE:
                        - Peso actual: ${healthData.weight || 'Desconocido'} kg
                        - Tensión Sistólica: ${healthData.systolicBP || 'Desconocida'}
                        - Tensión Diastólica: ${healthData.diastolicBP || 'Desconocida'}
                        - Índice de Fragilidad (VIGS): ${vigsScore.score} (${vigsScore.category})
                        - Caídas recientes: ${healthData.falls || 0}

                        INSTRUCCIONES:
                        1. Si el usuario pregunta por su estado (ej. "¿Cómo está mi tensión?", "¿He engordado?"), responde usando los datos del CONTEXTO DEL PACIENTE.
                        2. Si el usuario te dice un nuevo dato de salud, USA la herramienta 'saveHealthData'.
                        3. Si el usuario quiere recordar una cita o evento médico, USA la herramienta 'scheduleAppointment'.
                        4. Habla despacio, claro y con un tono cálido. Sé breve en tus respuestas.
                    `,
                },
            });

            sessionRef.current = await sessionPromise;
            setConnectionState('connected');

        } catch (error: any) {
            console.error("Failed to start conversation:", error);
            let userMessage = 'No se pudo iniciar el asistente de voz. Inténtelo de nuevo.';
            if (error.name === 'NotAllowedError' || error.message.includes('permission denied')) {
                userMessage = 'Acceso al micrófono denegado. Por favor, permita el acceso en los ajustes de su navegador.';
            }
            setErrorMessage(userMessage);
            setConnectionState('error');
            cleanup();
        }
    };

    useEffect(() => {
        startConversation();
        return () => {
            stopConversation();
        };
    }, []);

    useEffect(() => {
        conversationEndRef.current?.scrollIntoView({ behavior: "smooth" });
    }, [conversation, currentInput, currentOutput]);

    const getButtonState = () => {
        switch (connectionState) {
            case 'idle':
            case 'error':
                return { text: 'Cerrar', color: 'bg-brand-gray-500', pulse: false };
            case 'connecting':
                return { text: 'Conectando...', color: 'bg-brand-yellow', pulse: true };
            case 'connected':
                return { text: 'Finalizar Conversación', color: 'bg-brand-red', pulse: true };
        }
    };

    const { text: buttonText, color: buttonColor, pulse: buttonPulse } = getButtonState();

    return (
        <div className="p-4 sm:p-6 flex flex-col h-full relative">
            <button
              onClick={onClose}
              className="absolute top-4 right-4 p-2 text-brand-gray-500 hover:text-brand-gray-900 z-10 rounded-full hover:bg-brand-gray-200 transition-colors"
              aria-label="Cerrar asistente de voz"
            >
              <XMarkIcon />
            </button>

            <header className="mb-8 text-center">
                <h1 className="text-4xl font-bold text-brand-gray-800">Asistente por Voz</h1>
                <p className="text-xl text-brand-gray-600">Dígame sus datos o programe citas médicas.</p>
            </header>

            <div className="flex-grow flex flex-col items-center bg-white p-6 rounded-2xl shadow-md">
                <div className="w-full flex-grow bg-brand-gray-100 rounded-lg p-4 overflow-y-auto mb-6 h-64">
                    {conversation.length === 0 && !currentInput && !currentOutput && connectionState !== 'connecting' && (
                        <div className="flex items-center justify-center h-full">
                            <p className="text-brand-gray-500 text-lg">La transcripción aparecerá aquí.</p>
                        </div>
                    )}
                    {conversation.map((turn, index) => {
                        if (turn.speaker === 'system') {
                             return (
                                <div key={index} className="mb-3 text-center">
                                    <span className="inline-flex items-center gap-2 px-4 py-2 rounded-full text-sm bg-green-100 text-green-800 border border-green-200">
                                        <CheckCircleIcon /> {turn.text}
                                    </span>
                                </div>
                             );
                        }
                        return (
                            turn.text.trim() && <div key={index} className={`mb-3 ${turn.speaker === 'user' ? 'text-right' : 'text-left'}`}>
                                <span className={`inline-block p-3 rounded-xl text-lg ${turn.speaker === 'user' ? 'bg-brand-blue text-white' : 'bg-brand-gray-200 text-brand-gray-800'}`}>
                                    <strong>{turn.speaker === 'user' ? 'Usted' : 'Asistente'}:</strong> {turn.text}
                                </span>
                            </div>
                        );
                    })}
                    {currentInput && (
                         <div className="text-right mb-3">
                            <span className="inline-block p-3 rounded-xl text-lg bg-brand-blue text-white opacity-75">
                                <strong>Usted:</strong> {currentInput}
                            </span>
                        </div>
                    )}
                     {currentOutput && (
                        <div className="text-left mb-3">
                            <span className="inline-block p-3 rounded-xl text-lg bg-brand-gray-200 text-brand-gray-800 opacity-75">
                                 <strong>Asistente:</strong> {currentOutput}
                            </span>
                        </div>
                    )}
                    <div ref={conversationEndRef} />
                </div>

                <button
                    onClick={onClose}
                    className={`rounded-full p-8 transition-all duration-300 ease-in-out ${buttonColor} ${buttonPulse ? 'animate-pulse' : ''}`}
                    aria-label={buttonText}
                >
                    <MicrophoneIcon />
                </button>

                <p className="text-2xl text-brand-gray-700 font-semibold mt-8 text-center h-16">
                    {errorMessage ? <span className="text-brand-red">{errorMessage}</span> : buttonText}
                </p>
            </div>
        </div>
    );
};

export default VoiceAssistantScreen;

import React, { useState } from 'react';
import { useAuth } from '../contexts/AuthContext';
import { registerUserInDb } from '../services/firestore';
import type { UserProfile, HealthData } from '../types';
import { avatars } from '../components/Icons';

const LoginScreen: React.FC = () => {
  const { signIn, signUp } = useAuth();
  const [isRegistering, setIsRegistering] = useState(false); 
  const [step, setStep] = useState(0); 
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [personalData, setPersonalData] = useState({ displayName: '', birthDate: '', gender: 'male', height: '' });
  const [contactData, setContactData] = useState({ nationality: 'Española', language: 'Español', emergencyName: '', emergencyPhone: '' });
  const [diaryFields, setDiaryFields] = useState<(keyof HealthData)[]>(['weight', 'systolicBP', 'diastolicBP', 'pulse', 'oxygenSaturation', 'glucose', 'falls']);
  const [legalData, setLegalData] = useState({ hasLegalConsent: false, dataProcessingConsent: false });
  const [avatarId, setAvatarId] = useState(0);

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);
    setLoading(true);
    try {
        await signIn(email, password); 
    } catch (err: any) {
        setError("Credenciales incorrectas o error de conexión.");
    } finally {
        setLoading(false);
    }
  };

  const handleNextStep = (e: React.FormEvent) => {
      e.preventDefault();
      setError(null);
      if (step === 0) {
          if (password.length < 6) { setError("La contraseña debe tener al menos 6 caracteres."); return; }
          if (!email.includes('@')) { setError("Email inválido."); return; }
      }
      if (step === 1 && (!personalData.displayName || !personalData.birthDate || !personalData.height)) {
          setError("Complete los campos obligatorios."); return;
      }
      if (step === 4 && (!legalData.hasLegalConsent || !legalData.dataProcessingConsent)) {
          setError("Acepte los términos legales."); return;
      }
      setStep(prev => prev + 1);
  };

  const handleFinalRegister = async () => {
      setLoading(true);
      setError(null);
      try {
          // 1. Crear usuario en Auth
          const authRes = await signUp(email, password);
          if (!authRes) throw new Error("No se pudo crear el usuario.");

          // 2. Crear Perfil en la DB
          const newProfile: UserProfile = {
              email: email,
              displayName: personalData.displayName,
              birthDate: personalData.birthDate,
              gender: personalData.gender as 'male' | 'female' | 'other',
              nationality: contactData.nationality,
              language: contactData.language,
              emergencyContactName: contactData.emergencyName,
              emergencyContactPhone: contactData.emergencyPhone,
              diaryPreferences: diaryFields, 
              hasLegalConsent: legalData.hasLegalConsent,
              dataProcessingConsent: legalData.dataProcessingConsent,
              avatarId: avatarId,
              healthData: {
                  weight: null, falls: null, systolicBP: null, diastolicBP: null, pulse: null,
                  oxygenSaturation: null, glucose: null, calfCircumference: null, abdominalCircumference: null,
                  height: parseFloat(personalData.height) || null
              },
              vigsScore: { score: 0, category: 'Robusto' },
              alerts: [{ id: Date.now(), type: 'success', title: 'Bienvenido', message: 'Su perfil ha sido creado correctamente.' }]
          };

          await registerUserInDb(authRes.uid, newProfile);
          // La app redirigirá automáticamente al cambiar el estado del usuario en AuthContext
      } catch (err: any) {
          setError(err.message || "Error en el registro.");
      } finally {
          setLoading(false);
      }
  };

  const renderStepContent = () => {
      switch(step) {
          case 0: return (
              <div className="space-y-4">
                  <h2 className="text-2xl font-bold text-brand-blue mb-4">Paso 1: Su Cuenta</h2>
                  <input type="email" placeholder="Email" className="w-full p-4 border-2 rounded-xl" value={email} onChange={e => setEmail(e.target.value)} required />
                  <input type="password" placeholder="Contraseña (6+ caracteres)" className="w-full p-4 border-2 rounded-xl" value={password} onChange={e => setPassword(e.target.value)} required />
              </div>
          );
          case 1: return (
              <div className="space-y-4">
                  <h2 className="text-2xl font-bold text-brand-blue mb-4">Paso 2: Datos Personales</h2>
                  <input type="text" placeholder="Nombre completo" className="w-full p-4 border-2 rounded-xl" value={personalData.displayName} onChange={e => setPersonalData({...personalData, displayName: e.target.value})} />
                  <input type="date" className="w-full p-4 border-2 rounded-xl" value={personalData.birthDate} onChange={e => setPersonalData({...personalData, birthDate: e.target.value})} />
                  <input type="number" placeholder="Altura (cm)" className="w-full p-4 border-2 rounded-xl" value={personalData.height} onChange={e => setPersonalData({...personalData, height: e.target.value})} />
              </div>
          );
          case 2: return (
            <div className="space-y-4">
                <h2 className="text-2xl font-bold text-brand-blue mb-4">Paso 3: Contacto</h2>
                <input type="text" placeholder="Nacionalidad" className="w-full p-4 border-2 rounded-xl" value={contactData.nationality} onChange={e => setContactData({...contactData, nationality: e.target.value})} />
                <input type="text" placeholder="Nombre contacto emergencia" className="w-full p-4 border-2 rounded-xl" value={contactData.emergencyName} onChange={e => setContactData({...contactData, emergencyName: e.target.value})} />
                <input type="tel" placeholder="Teléfono emergencia" className="w-full p-4 border-2 rounded-xl" value={contactData.emergencyPhone} onChange={e => setContactData({...contactData, emergencyPhone: e.target.value})} />
            </div>
          );
          case 3: return (
              <div className="space-y-2 max-h-80 overflow-y-auto">
                  <h2 className="text-2xl font-bold text-brand-blue mb-4">Paso 4: Su Diario</h2>
                  {['weight', 'systolicBP', 'diastolicBP', 'pulse', 'glucose', 'falls'].map((f: any) => (
                      <label key={f} className="flex items-center p-3 border rounded-xl cursor-pointer">
                          <input type="checkbox" checked={diaryFields.includes(f)} onChange={() => setDiaryFields(prev => prev.includes(f) ? prev.filter(x => x !== f) : [...prev, f])} className="w-6 h-6 mr-3" />
                          <span className="capitalize">{f}</span>
                      </label>
                  ))}
              </div>
          );
          case 4: return (
              <div className="space-y-4">
                  <h2 className="text-2xl font-bold text-brand-blue mb-4">Paso 5: Legal</h2>
                  <label className="flex items-start gap-3 p-3 border rounded-xl"><input type="checkbox" checked={legalData.hasLegalConsent} onChange={e => setLegalData({...legalData, hasLegalConsent: e.target.checked})} /><span>Acepto el consentimiento informado.</span></label>
                  <label className="flex items-start gap-3 p-3 border rounded-xl"><input type="checkbox" checked={legalData.dataProcessingConsent} onChange={e => setLegalData({...legalData, dataProcessingConsent: e.target.checked})} /><span>Autorizo el tratamiento de mis datos de salud.</span></label>
              </div>
          );
          case 5: return (
              <div className="grid grid-cols-3 gap-4">
                  <h2 className="col-span-3 text-2xl font-bold text-brand-blue mb-4 text-center">Paso 6: Avatar</h2>
                  {avatars.map((A, i) => (
                      <button key={i} onClick={() => setAvatarId(i)} className={`p-4 rounded-full flex justify-center ${avatarId === i ? 'ring-4 ring-brand-blue bg-blue-50' : ''}`}><A className="w-16 h-16" /></button>
                  ))}
              </div>
          );
          default: return null;
      }
  };

  if (isRegistering) {
      return (
        <div className="min-h-screen bg-brand-gray-100 flex flex-col justify-center items-center p-4">
            <div className="bg-white p-8 rounded-3xl shadow-2xl w-full max-w-lg">
                <div className="mb-8 flex gap-2">
                    {[0,1,2,3,4,5].map(i => <div key={i} className={`h-2 flex-1 rounded-full ${i <= step ? 'bg-brand-blue' : 'bg-gray-200'}`}></div>)}
                </div>
                {renderStepContent()}
                {error && <p className="mt-4 text-brand-red font-bold text-center">{error}</p>}
                <div className="mt-8 flex gap-4">
                    {step > 0 && <button onClick={() => setStep(s => s - 1)} className="flex-1 py-4 bg-gray-100 rounded-2xl font-bold">Atrás</button>}
                    <button onClick={step === 5 ? handleFinalRegister : handleNextStep} disabled={loading} className="flex-1 py-4 bg-brand-blue text-white rounded-2xl font-bold shadow-lg">
                        {loading ? 'Procesando...' : (step === 5 ? 'Finalizar' : 'Siguiente')}
                    </button>
                </div>
                <button onClick={() => setIsRegistering(false)} className="w-full mt-4 text-brand-gray-500 font-medium">¿Ya tiene cuenta? Entre aquí</button>
            </div>
        </div>
      );
  }

  return (
    <div className="min-h-screen bg-brand-gray-100 flex flex-col justify-center items-center p-4">
      <div className="bg-white p-10 rounded-3xl shadow-2xl w-full max-w-md text-center">
        <h1 className="text-4xl font-black text-brand-blue mb-2">Fisiosilver</h1>
        <p className="text-brand-gray-600 mb-10 text-lg">Asistente de Salud Senior</p>
        <form onSubmit={handleLogin} className="space-y-6">
          <input type="email" placeholder="Correo electrónico" required value={email} onChange={e => setEmail(e.target.value)} className="w-full p-4 border-2 rounded-2xl text-lg focus:border-brand-blue outline-none" />
          <input type="password" placeholder="Contraseña" required value={password} onChange={e => setPassword(e.target.value)} className="w-full p-4 border-2 rounded-2xl text-lg focus:border-brand-blue outline-none" />
          {error && <p className="text-brand-red font-bold">{error}</p>}
          <button type="submit" disabled={loading} className="w-full bg-brand-blue text-white font-bold py-4 rounded-2xl text-xl shadow-lg hover:bg-sky-700 transition-all">
            {loading ? 'Entrando...' : 'Iniciar Sesión'}
          </button>
        </form>
        <div className="mt-10 pt-8 border-t">
            <button onClick={() => setIsRegistering(true)} className="w-full py-4 border-2 border-brand-blue text-brand-blue font-bold rounded-2xl text-lg">Crear Cuenta Nueva</button>
        </div>
      </div>
    </div>
  );
};

