import React, { useState, useContext } from 'react';
import { AppContext } from '../contexts/AppContext';
import { useAuth } from '../contexts/AuthContext';
import { analyzeClinicalReport } from '../services/geminiService';
import { saveClinicalReport, uploadFile } from '../services/firestore';
import { UploadIcon, CheckCircleIcon } from '../components/Icons';
import AnalysisDisplay from '../components/AnalysisDisplay';
import type { ClinicalAnalysisResult } from '../types';

const LoadingSpinner = ({ message }: { message: string }) => (
    <div className="flex flex-col justify-center items-center p-8 text-center">
        <div className="animate-spin rounded-full h-16 w-16 border-b-4 border-brand-blue"></div>
        <p className="mt-4 text-xl text-brand-gray-700">{message}</p>
    </div>
);

const ClinicalScreen: React.FC = () => {
    const context = useContext(AppContext);
    const { user } = useAuth();
    const { clinicalAnalyses, setClinicalAnalyses } = context!;
    const [selectedFile, setSelectedFile] = useState<File | null>(null);
    const [isLoading, setIsLoading] = useState(false);
    const [loadingMessage, setLoadingMessage] = useState("");
    const [error, setError] = useState<string | null>(null);
    const [successMessage, setSuccessMessage] = useState<string | null>(null);

    const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
        if (event.target.files && event.target.files[0]) {
            setSelectedFile(event.target.files[0]);
            setError(null);
            setSuccessMessage(null);
        }
    };

    const handleUpload = async () => {
        if (!selectedFile || !user) {
            setError("Por favor, seleccione un archivo e inicie sesión.");
            return;
        }
        setIsLoading(true);
        setError(null);
        setSuccessMessage(null);

        try {
            setLoadingMessage("Leyendo informe con IA...");
            const analysisResult: ClinicalAnalysisResult = await analyzeClinicalReport(selectedFile);

            setLoadingMessage("Guardando informe en la nube...");
            // Subimos el archivo real al bucket de Supabase
            const fileUrl = await uploadFile('clinical-reports', selectedFile);

            const newAnalysis = {
                id: Date.now().toString(),
                fileName: selectedFile.name,
                analysis: analysisResult,
                createdAt: new Date(),
            };

            // Guardar en Supabase Database
            await saveClinicalReport(user.uid, newAnalysis);

            // Actualizar interfaz
            setClinicalAnalyses(prev => [newAnalysis, ...prev]);

            setSelectedFile(null);
            const fileInput = document.getElementById('file-upload') as HTMLInputElement;
            if(fileInput) fileInput.value = "";

            setSuccessMessage('El informe se ha guardado correctamente.');
            setTimeout(() => setSuccessMessage(null), 3000);

        } catch (err: any) {
            console.error(err);
            setError("No se pudo procesar el informe. Verifique su conexión y que los Buckets de Supabase estén creados.");
        } finally {
            setIsLoading(false);
        }
    };

    return (
        <div className="p-4 sm:p-6">
            <header className="mb-8">
                <h1 className="text-4xl font-bold text-brand-gray-800">Datos Clínicos</h1>
                <p className="text-xl text-brand-gray-600">Suba sus informes para un análisis sencillo.</p>
            </header>

            <div className="bg-white p-6 rounded-2xl shadow-md mb-8">
                <h2 className="text-2xl font-semibold text-brand-gray-700 mb-4">Subir Nuevo Informe</h2>
                <div className="flex flex-col items-center border-2 border-dashed border-brand-gray-300 p-8 rounded-xl text-center">
                    <UploadIcon />
                    <p className="text-lg text-brand-gray-600 my-4">Seleccione una imagen o PDF de su informe</p>
                    <input type="file" id="file-upload" accept="image/*,application/pdf" className="hidden" onChange={handleFileChange} />
                    <label htmlFor="file-upload" className="cursor-pointer bg-brand-lightblue text-brand-blue font-bold py-3 px-6 rounded-lg text-lg hover:bg-sky-200 transition-colors">
                        Seleccionar Archivo
                    </label>
                </div>
                {selectedFile && <p className="text-center text-lg mt-4 text-brand-gray-700">Listo para analizar: <strong>{selectedFile.name}</strong></p>}

                {isLoading ? <LoadingSpinner message={loadingMessage} /> : (
                    <button onClick={handleUpload} disabled={!selectedFile} className="w-full mt-6 bg-brand-blue text-white text-2xl font-bold py-5 px-6 rounded-2xl shadow-lg hover:bg-sky-700 transition-colors disabled:bg-brand-gray-400 disabled:cursor-not-allowed">
                        Analizar y Guardar
                    </button>
                )}
                 {error && <p className="text-center text-lg mt-4 text-brand-red p-4 bg-red-100 rounded-lg font-bold">{error}</p>}
                 {successMessage && (
                    <div className="mt-4 p-4 bg-green-100 text-green-800 rounded-xl border border-green-200 flex items-center justify-center animate-pulse">
                        <CheckCircleIcon />
                        <span className="ml-2 font-bold text-lg">{successMessage}</span>
                    </div>
                )}
            </div>

            <div className="space-y-6">
                <h2 className="text-2xl font-semibold text-brand-gray-700">Historial Médico</h2>
                {clinicalAnalyses.length === 0 ? (
                    <p className="text-lg text-center text-brand-gray-600 bg-white p-8 rounded-2xl shadow-md">Aún no hay informes registrados.</p>
                ) : (
                    clinicalAnalyses.map(item => (
                        <div key={item.id} className="bg-white p-6 rounded-2xl shadow-md">
                            <div className="border-b pb-4 mb-4 border-brand-gray-200">
                                <h3 className="text-2xl font-bold text-brand-gray-800">{item.fileName}</h3>
                                <p className="text-lg text-brand-gray-500">{item.createdAt.toLocaleDateString('es-ES', { year: 'numeric', month: 'long', day: 'numeric' })}</p>
                            </div>
                            <AnalysisDisplay analysis={item.analysis} type="clinical" />
                        </div>
                    ))
                )}
            </div>
        </div>
    );
};

export default ClinicalScreen;

