export const AuthProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<User | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    if (!isSupabaseConfigured) {
        // Modo Demo: No intentamos conectar con Supabase
        const savedDemoUser = localStorage.getItem('demo_user');
        if (savedDemoUser) {
            setUser(JSON.parse(savedDemoUser));
        }
        setLoading(false);
        return;
    }

    const checkUser = async () => {
        try {
            const { data: { session } } = await supabase.auth.getSession();
            if (session?.user) {
                setUser({ uid: session.user.id, email: session.user.email || null });
            }
        } catch (e) {
            console.warn("Supabase auth check failed, likely network issue or invalid URL:", e);
        } finally {
            setLoading(false);
        }
    };

    checkUser();

    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      if (session?.user) {
        setUser({ uid: session.user.id, email: session.user.email || null });
      } else {
        setUser(null);
      }
    });

    return () => subscription.unsubscribe();
  }, []);

  const signIn = async (email: string, password?: string) => {
      if (!isSupabaseConfigured || !password) {
          // Modo Demo
          const mockUser = { uid: 'demo-user-123', email };
          setUser(mockUser);
          localStorage.setItem('demo_user', JSON.stringify(mockUser));
          return;
      }
      const { error } = await supabase.auth.signInWithPassword({ email, password });
      if (error) throw error;
  };

  const signUp = async (email: string, password: string) => {
      if (!isSupabaseConfigured) {
          const mockUser = { uid: 'demo-user-123', email };
          setUser(mockUser);
          localStorage.setItem('demo_user', JSON.stringify(mockUser));
          return { uid: mockUser.uid };
      }
      const { data, error } = await supabase.auth.signUp({ email, password });
      if (error) throw error;
      return data.user ? { uid: data.user.id } : null;
  };

  const signOut = async () => {
      if (isSupabaseConfigured) {
          await supabase.auth.signOut();
      }
      setUser(null);
      localStorage.removeItem('demo_user');
  };

  return (
    <AuthContext.Provider value={{ user, loading, signIn, signUp, signOut }}>
      {!loading && children}
    </AuthContext.Provider>
  );
};

