export const initializeUser = async (uid: string, email: string): Promise<UserProfile> => {
    if (isDemo) {
        const profile = getLocal(`profile_${uid}`);
        if (profile) return profile;
        const defaultDemo = mapDbToProfile({ email, display_name: 'Usuario Demo' });
        setLocal(`profile_${uid}`, defaultDemo);
        return defaultDemo;
    }

    // Intentar obtener el perfil
    const { data, error } = await supabase.from('users').select('*').eq('id', uid).single();

    if (error || !data) {
        // Si no existe (ej. recién registrado y la DB no se actualizó), creamos uno básico
        console.warn("Perfil no encontrado en DB, creando uno por defecto...");
        const defaultProfile: UserProfile = {
            email, displayName: 'Nuevo Usuario', birthDate: '', gender: 'male', nationality: '',
            language: 'Español', emergencyContactName: '', emergencyContactPhone: '',
            hasLegalConsent: false, dataProcessingConsent: false, avatarId: 0,
            diaryPreferences: ['weight', 'systolicBP', 'diastolicBP', 'pulse', 'glucose'],
            healthData: { weight: null, falls: null, systolicBP: null, diastolicBP: null, pulse: null, oxygenSaturation: null, glucose: null, calfCircumference: null, abdominalCircumference: null },
            vigsScore: { score: 0, category: 'Robusto' },
            alerts: []
        };
        try {
            await registerUserInDb(uid, defaultProfile);
            return defaultProfile;
        } catch (e) {
            // Si falla la creación, devolvemos el objeto para que la app no rompa
            return defaultProfile;
        }
    }

    return mapDbToProfile(data);
