        user_id: uid, 
        title, 
        description,
        status: 'pending'
    });
};

import { supabase, isSupabaseConfigured } from './supabaseClient';
import type { UserProfile, HealthData, ClinicalAnalysis, NutritionalAnalysis, Appointment } from '../types';

const isDemo = !isSupabaseConfigured;

const getLocal = (key: string) => {
    const val = localStorage.getItem(key);
    return val ? JSON.parse(val) : null;
};

const setLocal = (key: string, val: any) => {
    localStorage.setItem(key, JSON.stringify(val));
};

// --- Mapeo de Nombres de Columnas (App -> DB) ---
const mapProfileToDb = (profile: Partial<UserProfile>) => {
    const dbData: any = {};
    if (profile.email !== undefined) dbData.email = profile.email;
    if (profile.displayName !== undefined) dbData.display_name = profile.displayName;
    if (profile.birthDate !== undefined) dbData.birth_date = profile.birthDate;
    if (profile.gender !== undefined) dbData.gender = profile.gender;
    if (profile.nationality !== undefined) dbData.nationality = profile.nationality;
    if (profile.language !== undefined) dbData.language = profile.language;
    if (profile.emergencyContactName !== undefined) dbData.emergency_contact_name = profile.emergencyContactName;
    if (profile.emergencyContactPhone !== undefined) dbData.emergency_contact_phone = profile.emergencyContactPhone;
    if (profile.diaryPreferences !== undefined) dbData.diary_preferences = profile.diaryPreferences;
    if (profile.hasLegalConsent !== undefined) dbData.has_legal_consent = profile.hasLegalConsent;
    if (profile.dataProcessingConsent !== undefined) dbData.data_processing_consent = profile.dataProcessingConsent;
    if (profile.avatarId !== undefined) dbData.avatar_id = profile.avatarId;
    if (profile.healthData !== undefined) dbData.health_data = profile.healthData;
    if (profile.vigsScore !== undefined) dbData.vigs_score = profile.vigsScore;
    if (profile.alerts !== undefined) dbData.alerts = profile.alerts;
    return dbData;
};

// --- Mapeo de Nombres de Columnas (DB -> App) ---
const mapDbToProfile = (data: any): UserProfile => {
    return {
        email: data.email || '',
        displayName: data.display_name || 'Usuario',
        birthDate: data.birth_date || '',
        gender: data.gender || 'male',
        nationality: data.nationality || '',
        language: data.language || 'Español',
        emergencyContactName: data.emergency_contact_name || '',
        emergencyContactPhone: data.emergency_contact_phone || '',
        diaryPreferences: data.diary_preferences || ['weight', 'systolicBP', 'diastolicBP', 'pulse', 'glucose'],
        hasLegalConsent: data.has_legal_consent || false,
        dataProcessingConsent: data.data_processing_consent || false,
        avatarId: data.avatar_id || 0,
        healthData: data.health_data || { weight: null, falls: null, systolicBP: null, diastolicBP: null, pulse: null, oxygenSaturation: null, glucose: null, calfCircumference: null, abdominalCircumference: null },
        vigsScore: data.vigs_score || { score: 0, category: 'Robusto' },
        alerts: data.alerts || []
    };
};

// --- Helper: Subir archivo a Supabase Storage ---
export const uploadFile = async (bucket: string, file: File): Promise<string> => {
    if (isDemo) return URL.createObjectURL(file);
    const fileExt = file.name.split('.').pop();
    const fileName = `${Math.random()}.${fileExt}`;
    const filePath = `${fileName}`;
    const { error: uploadError } = await supabase.storage.from(bucket).upload(filePath, file);
    if (uploadError) throw uploadError;
    const { data } = supabase.storage.from(bucket).getPublicUrl(filePath);
    return data.publicUrl;
};

export const initializeUser = async (uid: string, email: string): Promise<UserProfile> => {
    if (isDemo) {
        const profile = getLocal(`profile_${uid}`);
        if (profile) return profile;
        const defaultDemo = mapDbToProfile({ email, display_name: 'Usuario Demo' });
        setLocal(`profile_${uid}`, defaultDemo);
        return defaultDemo;
    }

    const { data, error } = await supabase.from('users').select('*').eq('id', uid).single();

    if (error || !data) {
        console.warn("Perfil no encontrado en DB, intentando crear uno inicial...");
        const defaultProfile: UserProfile = {
            email, displayName: 'Nuevo Usuario', birthDate: '', gender: 'male', nationality: '',
            language: 'Español', emergencyContactName: '', emergencyContactPhone: '',
            hasLegalConsent: false, dataProcessingConsent: false, avatarId: 0,
            diaryPreferences: ['weight', 'systolicBP', 'diastolicBP', 'pulse', 'glucose'],
            healthData: { weight: null, falls: null, systolicBP: null, diastolicBP: null, pulse: null, oxygenSaturation: null, glucose: null, calfCircumference: null, abdominalCircumference: null },
            vigsScore: { score: 0, category: 'Robusto' },
            alerts: []
        };

        // Intentar registrarlo. Si falla aquí, lanzamos el error para que el usuario sepa qué pasa (ej. falta tabla)
        await registerUserInDb(uid, defaultProfile);
        return defaultProfile;
    }

    return mapDbToProfile(data);
};

export const getUserProfile = async (uid: string): Promise<UserProfile | null> => {
    if (isDemo) return getLocal(`profile_${uid}`);
    const { data, error } = await supabase.from('users').select('*').eq('id', uid).single();
    if (error || !data) return null;
    return mapDbToProfile(data);
};

export const updateUserProfile = async (uid: string, profile: Partial<UserProfile>): Promise<void> => {
    if (isDemo) {
        const current = getLocal(`profile_${uid}`) || {};
        setLocal(`profile_${uid}`, { ...current, ...profile });
        return;
    }
    const dbData = mapProfileToDb(profile);
    const { error } = await supabase.from('users').update(dbData).eq('id', uid);
    if (error) {
        console.error("Error actualizando perfil:", error.message);
        throw error;
    }
};

export const registerUserInDb = async (uid: string, profile: UserProfile): Promise<void> => {
    if (isDemo) {
        setLocal(`profile_${uid}`, profile);
        return;
    }
    const dbData = { id: uid, ...mapProfileToDb(profile) };

    // Usamos UPSERT para evitar errores si el registro ya existe
    const { error } = await supabase.from('users').upsert(dbData, { onConflict: 'id' });

    if (error) {
        console.error("ERROR CRÍTICO AL GUARDAR EN TABLA 'users':", error.message, error.details);
        throw new Error(`Error en Base de Datos: ${error.message}. Verifique que la tabla 'users' exista y las políticas RLS permitan inserción.`);
    }
};

export const getClinicalReports = async (uid: string): Promise<ClinicalAnalysis[]> => {
