import React, { useState } from 'react';
import { useAuth } from '../contexts/AuthContext';
import { registerUserInDb } from '../services/firestore';
import type { UserProfile, HealthData } from '../types';
import { avatars } from '../components/Icons';

const LoginScreen: React.FC = () => {
  const { signIn, signUp } = useAuth();
  const [isRegistering, setIsRegistering] = useState(false); 
  const [step, setStep] = useState(0); 
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [personalData, setPersonalData] = useState({ displayName: '', birthDate: '', gender: 'male', height: '' });
  const [contactData, setContactData] = useState({ nationality: 'Española', language: 'Español', emergencyName: '', emergencyPhone: '' });
  const [diaryFields, setDiaryFields] = useState<(keyof HealthData)[]>(['weight', 'systolicBP', 'diastolicBP', 'pulse', 'oxygenSaturation', 'glucose', 'falls']);
  const [legalData, setLegalData] = useState({ hasLegalConsent: false, dataProcessingConsent: false });
  const [avatarId, setAvatarId] = useState(0);

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);
    setLoading(true);
    try {
        await signIn(email, password); 
    } catch (err: any) {
        setError(err.message || "Credenciales incorrectas o error de conexión.");
    } finally {
        setLoading(false);
    }
  };

  const handleNextStep = (e: React.FormEvent) => {
      e.preventDefault();
      setError(null);
      if (step === 0) {
          if (password.length < 6) { setError("La contraseña debe tener al menos 6 caracteres."); return; }
          if (!email.includes('@')) { setError("Email inválido."); return; }
      }
      if (step === 1 && (!personalData.displayName || !personalData.birthDate || !personalData.height)) {
          setError("Complete los campos obligatorios."); return;
      }
      if (step === 4 && (!legalData.hasLegalConsent || !legalData.dataProcessingConsent)) {
          setError("Acepte los términos legales."); return;
      }
      setStep(prev => prev + 1);
  };

  const handleFinalRegister = async () => {
      setLoading(true);
      setError(null);
      try {
          // 1. Crear usuario en Auth
          console.log("Iniciando registro en Auth...");
          const authRes = await signUp(email, password);
          if (!authRes) throw new Error("No se pudo crear el usuario en Authentication.");

          // 2. Crear Perfil en la DB
          console.log("Iniciando creación de perfil en DB para UID:", authRes.uid);
          const newProfile: UserProfile = {
              email: email,
              displayName: personalData.displayName,
              birthDate: personalData.birthDate,
              gender: personalData.gender as 'male' | 'female' | 'other',
              nationality: contactData.nationality,
              language: contactData.language,
              emergencyContactName: contactData.emergencyName,
              emergencyContactPhone: contactData.emergencyPhone,
              diaryPreferences: diaryFields, 
              hasLegalConsent: legalData.hasLegalConsent,
              dataProcessingConsent: legalData.dataProcessingConsent,
              avatarId: avatarId,
              healthData: {
                  weight: null, falls: null, systolicBP: null, diastolicBP: null, pulse: null,
                  oxygenSaturation: null, glucose: null, calfCircumference: null, abdominalCircumference: null,
                  height: parseFloat(personalData.height) || null
              },
              vigsScore: { score: 0, category: 'Robusto' },
              alerts: [{ id: Date.now(), type: 'success', title: 'Bienvenido', message: 'Su perfil ha sido creado correctamente.' }]
          };

          await registerUserInDb(authRes.uid, newProfile);
          console.log("Perfil guardado con éxito.");
      } catch (err: any) {
          console.error("Error completo en registro:", err);
          setError(err.message || "Error inesperado en el registro.");
      } finally {
          setLoading(false);
      }
  };

  const renderStepContent = () => {
      switch(step) {
          case 0: return (
              <div className="space-y-4">
                  <h2 className="text-2xl font-bold text-brand-blue mb-4">Paso 1: Su Cuenta</h2>
                  <input type="email" placeholder="Email" className="w-full p-4 border-2 rounded-xl" value={email} onChange={e => setEmail(e.target.value)} required />
                  <input type="password" placeholder="Contraseña (6+ caracteres)" className="w-full p-4 border-2 rounded-xl" value={password} onChange={e => setPassword(e.target.value)} required />
              </div>
          );
          case 1: return (
              <div className="space-y-4">
                  <h2 className="text-2xl font-bold text-brand-blue mb-4">Paso 2: Datos Personales</h2>
                  <input type="text" placeholder="Nombre completo" className="w-full p-4 border-2 rounded-xl" value={personalData.displayName} onChange={e => setPersonalData({...personalData, displayName: e.target.value})} />
                  <input type="date" className="w-full p-4 border-2 rounded-xl" value={personalData.birthDate} onChange={e => setPersonalData({...personalData, birthDate: e.target.value})} />
                  <input type="number" placeholder="Altura (cm)" className="w-full p-4 border-2 rounded-xl" value={personalData.height} onChange={e => setPersonalData({...personalData, height: e.target.value})} />
              </div>
          );
          case 2: return (
            <div className="space-y-4">
                <h2 className="text-2xl font-bold text-brand-blue mb-4">Paso 3: Contacto</h2>
                <input type="text" placeholder="Nacionalidad" className="w-full p-4 border-2 rounded-xl" value={contactData.nationality} onChange={e => setContactData({...contactData, nationality: e.target.value})} />
                <input type="text" placeholder="Nombre contacto emergencia" className="w-full p-4 border-2 rounded-xl" value={contactData.emergencyName} onChange={e => setContactData({...contactData, emergencyName: e.target.value})} />
                <input type="tel" placeholder="Teléfono emergencia" className="w-full p-4 border-2 rounded-xl" value={contactData.emergencyPhone} onChange={e => setContactData({...contactData, emergencyPhone: e.target.value})} />
            </div>
          );
          case 3: return (
              <div className="space-y-2 max-h-80 overflow-y-auto">
                  <h2 className="text-2xl font-bold text-brand-blue mb-4">Paso 4: Su Diario</h2>
                  {['weight', 'systolicBP', 'diastolicBP', 'pulse', 'glucose', 'falls'].map((f: any) => (
                      <label key={f} className="flex items-center p-3 border rounded-xl cursor-pointer">
                          <input type="checkbox" checked={diaryFields.includes(f)} onChange={() => setDiaryFields(prev => prev.includes(f) ? prev.filter(x => x !== f) : [...prev, f])} className="w-6 h-6 mr-3" />
                          <span className="capitalize">{f}</span>
                      </label>
                  ))}
              </div>
          );
          case 4: return (
              <div className="space-y-4">
                  <h2 className="text-2xl font-bold text-brand-blue mb-4">Paso 5: Legal</h2>
                  <label className="flex items-start gap-3 p-3 border rounded-xl"><input type="checkbox" checked={legalData.hasLegalConsent} onChange={e => setLegalData({...legalData, hasLegalConsent: e.target.checked})} /><span>Acepto el consentimiento informado.</span></label>
                  <label className="flex items-start gap-3 p-3 border rounded-xl"><input type="checkbox" checked={legalData.dataProcessingConsent} onChange={e => setLegalData({...legalData, dataProcessingConsent: e.target.checked})} /><span>Autorizo el tratamiento de mis datos de salud.</span></label>
              </div>
          );
          case 5: return (
              <div className="grid grid-cols-3 gap-4">
                  <h2 className="col-span-3 text-2xl font-bold text-brand-blue mb-4 text-center">Paso 6: Avatar</h2>
                  {avatars.map((A, i) => (
                      <button key={i} onClick={() => setAvatarId(i)} className={`p-4 rounded-full flex justify-center ${avatarId === i ? 'ring-4 ring-brand-blue bg-blue-50' : ''}`}><A className="w-16 h-16" /></button>
                  ))}
              </div>
          );
          default: return null;
      }
  };

  if (isRegistering) {
      return (
        <div className="min-h-screen bg-brand-gray-100 flex flex-col justify-center items-center p-4">
            <div className="bg-white p-8 rounded-3xl shadow-2xl w-full max-w-lg">
                <div className="mb-8 flex gap-2">
                    {[0,1,2,3,4,5].map(i => <div key={i} className={`h-2 flex-1 rounded-full ${i <= step ? 'bg-brand-blue' : 'bg-gray-200'}`}></div>)}
                </div>
                {renderStepContent()}
                {error && <p className="mt-4 text-brand-red font-bold text-center p-3 bg-red-50 rounded-lg text-sm">{error}</p>}
                <div className="mt-8 flex gap-4">
                    {step > 0 && <button onClick={() => setStep(s => s - 1)} className="flex-1 py-4 bg-gray-100 rounded-2xl font-bold">Atrás</button>}
                    <button onClick={step === 5 ? handleFinalRegister : handleNextStep} disabled={loading} className="flex-1 py-4 bg-brand-blue text-white rounded-2xl font-bold shadow-lg">
                        {loading ? 'Procesando...' : (step === 5 ? 'Finalizar' : 'Siguiente')}
                    </button>
                </div>
                <button onClick={() => setIsRegistering(false)} className="w-full mt-4 text-brand-gray-500 font-medium">¿Ya tiene cuenta? Entre aquí</button>
            </div>
        </div>
      );
  }

  return (
    <div className="min-h-screen bg-brand-gray-100 flex flex-col justify-center items-center p-4">
      <div className="bg-white p-10 rounded-3xl shadow-2xl w-full max-w-md text-center">
        <h1 className="text-4xl font-black text-brand-blue mb-2">Fisiosilver</h1>
        <p className="text-brand-gray-600 mb-10 text-lg">Asistente de Salud Senior</p>
        <form onSubmit={handleLogin} className="space-y-6">
          <input type="email" placeholder="Correo electrónico" required value={email} onChange={e => setEmail(e.target.value)} className="w-full p-4 border-2 rounded-2xl text-lg focus:border-brand-blue outline-none" />
          <input type="password" placeholder="Contraseña" required value={password} onChange={e => setPassword(e.target.value)} className="w-full p-4 border-2 rounded-2xl text-lg focus:border-brand-blue outline-none" />
          {error && <p className="text-brand-red font-bold bg-red-50 p-3 rounded-lg text-sm">{error}</p>}
          <button type="submit" disabled={loading} className="w-full bg-brand-blue text-white font-bold py-4 rounded-2xl text-xl shadow-lg hover:bg-sky-700 transition-all">
            {loading ? 'Entrando...' : 'Iniciar Sesión'}
          </button>
        </form>
        <div className="mt-10 pt-8 border-t">
            <button onClick={() => setIsRegistering(true)} className="w-full py-4 border-2 border-brand-blue text-brand-blue font-bold rounded-2xl text-lg">Crear Cuenta Nueva</button>
        </div>
      </div>
    </div>
  );
};

export default LoginScreen;

