        setLocal(`nutrition_${uid}`, [analysis, ...current]);
        return;
    }
    const { error } = await supabase.from('nutrition_logs').insert({ 
        user_id: uid, 
        image_preview: analysis.imagePreview, 
        analysis: analysis.analysis 
    });
    if (error) throw new Error(`Error guardando registro nutricional: ${error.message}`);
};

export const getDailyHistory = async (uid: string): Promise<(HealthData & { createdAt: Date })[]> => {
    if (isDemo) return (getLocal(`history_${uid}`) || []).map((d: any) => ({...d, createdAt: new Date(d.createdAt)}));
    const { data } = await supabase.from('daily_logs').select('*').eq('user_id', uid).order('created_at', { ascending: false });

    return (data || []).map(d => ({
        weight: d.weight,
        systolicBP: d.systolic_bp,
        diastolicBP: d.diastolic_bp,
        pulse: d.pulse,
        oxygenSaturation: d.oxygen_saturation,
        glucose: d.glucose,
        falls: d.falls,
        calfCircumference: d.calf_circumference,
        abdominalCircumference: d.abdominal_circumference,
        createdAt: new Date(d.created_at)
    }));
};

