const getVigsColor = (category: VigsCategory): string => {
  switch (category) {
    case 'Robusto': return 'bg-brand-green';
    case 'Leve': return 'bg-emerald-500';
    case 'Moderada': return 'bg-brand-yellow';
    case 'Severa': return 'bg-brand-red';
    default: return 'bg-brand-gray-400';
  }
};

const getAlertColors = (type: Alert['type']) => {
    switch (type) {
        case 'info': return 'bg-sky-100 border-sky-500 text-sky-800';
        case 'warning': return 'bg-amber-100 border-amber-500 text-amber-800';
        case 'success': return 'bg-green-100 border-green-500 text-green-800';
        case 'danger': return 'bg-red-100 border-red-500 text-red-800';
    }
}

// --- Chart Component ---
interface ChartDataPoint { date: Date; value: number; }
interface HistoryChartProps { 
    data: ChartDataPoint[]; 
    unit: string; 
    color: string;
    referenceRange?: { min: number; max: number; label?: string };
}

const HistoryChart: React.FC<HistoryChartProps> = ({ data, unit, color, referenceRange }) => {
    const [hoveredIndex, setHoveredIndex] = useState<number | null>(null);

    if (data.length < 2) return <div className="h-64 flex items-center justify-center bg-gray-50 rounded-lg border border-gray-200"><p className="text-gray-500">Necesita al menos 2 registros.</p></div>;

    const width = 100; const height = 50; const padding = 8;
    const values = data.map(d => d.value);
    let minVal = Math.min(...values);
    let maxVal = Math.max(...values);

    if (referenceRange) {
        minVal = Math.min(minVal, referenceRange.min);
        maxVal = Math.max(maxVal, referenceRange.max);
    }
    const rangeBuffer = (maxVal - minVal) * 0.1;
    minVal = Math.floor(minVal - rangeBuffer);
    maxVal = Math.ceil(maxVal + rangeBuffer);
    const range = maxVal - minVal || 1;

    const getX = (index: number) => padding + (index / (data.length - 1)) * (width - 2 * padding);
    const getY = (val: number) => height - padding - ((val - minVal) / range) * (height - 2 * padding);
    const pathD = data.map((d, i) => `${i === 0 ? 'M' : 'L'} ${getX(i)} ${getY(d.value)}`).join(' ');

    return (
        <div className="w-full">
            <div className="relative w-full aspect-[2/1] bg-white rounded-lg border border-gray-100 p-2 shadow-inner">
                <svg viewBox={`0 0 ${width} ${height}`} className="w-full h-full overflow-visible">
                    {referenceRange && (
                        <rect x={padding} y={getY(referenceRange.max)} width={width - 2 * padding} height={getY(referenceRange.min) - getY(referenceRange.max)} fill="rgba(74, 222, 128, 0.2)" />
                    )}
                    <path d={pathD} fill="none" stroke={color} strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round" />
                    {data.map((d, i) => (
                        <g key={i}>
                            <circle cx={getX(i)} cy={getY(d.value)} r={hoveredIndex === i ? "2.5" : "1.5"} fill="white" stroke={color} strokeWidth={hoveredIndex === i ? "1.5" : "0.8"} className="transition-all" />
                            <circle cx={getX(i)} cy={getY(d.value)} r="6" fill="transparent" className="cursor-pointer" onMouseEnter={() => setHoveredIndex(i)} onMouseLeave={() => setHoveredIndex(null)} />
                        </g>
                    ))}
                </svg>
            </div>
            <div className="flex justify-between mt-2 text-sm text-gray-600 font-medium px-2">
                <span>Min: {minVal} {unit}</span>
                {referenceRange && <span className="text-brand-green text-xs font-bold px-2 py-0.5 bg-green-100 rounded-full">Zona Recomendada: {referenceRange.min}-{referenceRange.max}</span>}
                <span>Max: {maxVal} {unit}</span>
            </div>
        </div>
    );
};

