const EditProfileModal: React.FC<{ onClose: (updatedProfile?: UserProfile) => void }> = ({ onClose }) => {
    const { user } = useAuth();
    const context = useContext(AppContext);
    const { setDiaryPreferences } = context!;
    const [profile, setProfile] = useState<UserProfile | null>(null);
    const [loading, setLoading] = useState(true);
    const [saving, setSaving] = useState(false);
    const [activeTab, setActiveTab] = useState<'personal' | 'diary' | 'legal'>('personal');

    useEffect(() => {
        const fetchProfile = async () => {
            if (!user) return;
            const data = await getUserProfile(user.uid);
            if (data) {
                if(!data.diaryPreferences) {
                    data.diaryPreferences = ['weight', 'systolicBP', 'diastolicBP', 'pulse', 'oxygenSaturation', 'glucose', 'falls', 'calfCircumference', 'abdominalCircumference'];
                }
                setProfile(data);
            }
            setLoading(false);
        };
        fetchProfile();
    }, [user]);

    const handleSave = async () => {
        if (!user || !profile) return;
        setSaving(true);
        try {
            const safeProfile = { ...profile };
            if (safeProfile.healthData && safeProfile.healthData.height) {
                if (isNaN(safeProfile.healthData.height)) {
                    safeProfile.healthData.height = null;
                }
            }
            await updateUserProfile(user.uid, safeProfile);
            setDiaryPreferences(safeProfile.diaryPreferences); 
            onClose(safeProfile); 
