export const saveDailyLog = async (uid: string, h: HealthData): Promise<void> => {
    if (isDemo) {
        const current = getLocal(`history_${uid}`) || [];
        setLocal(`history_${uid}`, [{...h, createdAt: new Date().toISOString()}, ...current]);
        return;
    }

    // 1. Guardar en el historial (daily_logs)
    const entry = {
        user_id: uid,
        weight: h.weight,
        systolic_bp: h.systolicBP,
        diastolic_bp: h.diastolicBP,
        pulse: h.pulse,
        oxygen_saturation: h.oxygenSaturation,
        glucose: h.glucose,
        falls: h.falls,
        calf_circumference: h.calfCircumference,
        abdominal_circumference: h.abdominalCircumference
    };

    const { error: logError } = await supabase.from('daily_logs').insert(entry);
    if (logError) throw new Error(`Error guardando historial: ${logError.message}`);

    // 2. Actualizar el "snapshot" en el perfil del usuario para que se vea en el Home
    const { error: userError } = await supabase.from('users').update({ health_data: h }).eq('id', uid);
    if (userError) console.error("Error actualizando snapshot de salud:", userError.message);
};

