const HomeScreen: React.FC = () => {
    const { user, signOut } = useAuth();
    const { healthData, setHealthData, setDiaryPreferences } = useContext(AppContext)!;
    const [profileData, setProfileData] = useState<{name: string, avatarId: number, height?: number | null} | null>(null);
    const [isProfileOpen, setIsProfileOpen] = useState(false);
    const [selectedMetric, setSelectedMetric] = useState<{key: keyof HealthData, label: string, unit: string} | null>(null);
    const [historyData, setHistoryData] = useState<ChartDataPoint[]>([]);
    const [chartReferenceRange, setChartReferenceRange] = useState<{min: number, max: number} | undefined>(undefined);
    const [isLoadingHistory, setIsLoadingHistory] = useState(false);

    useEffect(() => {
        const loadHeaderData = async () => {
            if (!user) return;
            const data = await getUserProfile(user.uid);
            if (data) {
                setProfileData({ 
                    name: data.displayName || 'Usuario', 
                    avatarId: data.avatarId || 0,
                    height: data.healthData?.height 
                });
                // Sincronizar contexto local
                setHealthData(data.healthData);
                setDiaryPreferences(data.diaryPreferences);
            }
        };
        loadHeaderData();
    }, [user]);

    const handleProfileUpdate = (updatedProfile?: UserProfile) => {
        if (updatedProfile) {
            setProfileData({
                name: updatedProfile.displayName,
                avatarId: updatedProfile.avatarId,
                height: updatedProfile.healthData.height
            });
            setHealthData(updatedProfile.healthData);
        }
        setIsProfileOpen(false);
    };

    const handleLogout = async () => {
        if (window.confirm("¿Desea cerrar la sesión de su asistente?")) {
            try {
                await signOut();
            } catch (err) {
                console.error("Error al cerrar sesión:", err);
            }
        }
    };

    const handleMetricClick = async (key: keyof HealthData, label: string, unit: string) => {
        if (!user) return;
        setSelectedMetric({ key, label, unit });
        setIsLoadingHistory(true);
        setHistoryData([]);
        setChartReferenceRange(undefined);

        try {
            const logs = await getDailyHistory(user.uid);
            // Definir rangos de referencia básicos para el gráfico
            let range = {min: 0, max: 100};
            if (key === 'systolicBP') range = {min: 90, max: 140};
            if (key === 'diastolicBP') range = {min: 60, max: 90};
            if (key === 'oxygenSaturation') range = {min: 94, max: 100};
            if (key === 'glucose') range = {min: 70, max: 110};

            setChartReferenceRange(range);

            const chartData = logs
                .map(l => ({ date: l.createdAt, value: l[key] as number | null }))
                .filter(d => d.value !== null && !isNaN(d.value))
                .sort((a, b) => a.date.getTime() - b.date.getTime()) as ChartDataPoint[];

            setHistoryData(chartData);
        } catch (error) {
            console.error("Error fetching history", error);
        } finally {
            setIsLoadingHistory(false);
        }
    };

    const AvatarComponent = profileData ? avatars[profileData.avatarId] || avatars[0] : avatars[0];

    return (
        <div className="p-4 sm:p-6 pb-24">
            <header className="flex justify-between items-start mb-8 pt-2">
                <div>
                    <h1 className="text-4xl font-black text-brand-gray-800 tracking-tight">Hola, {profileData?.name}</h1>
                    <p className="text-xl text-brand-gray-500 font-medium">Este es su resumen de salud hoy</p>
                </div>
                <div className="flex flex-col items-center gap-2">
                    <button onClick={() => setIsProfileOpen(true)} className="flex flex-col items-center justify-center bg-white p-2 rounded-2xl shadow-md border border-gray-50 hover:bg-sky-50 transition active:scale-95 group">
                        <AvatarComponent className="w-14 h-14 group-hover:scale-110 transition-transform" />
                        <span className="text-xs text-brand-blue font-black mt-1 uppercase tracking-tighter">Mi Perfil</span>
                    </button>
                    <button onClick={handleLogout} className="text-[10px] font-black text-white bg-red-500 hover:bg-red-600 px-3 py-1.5 rounded-full shadow-sm transition-colors active:scale-95 uppercase">Salir</button>
                </div>
            </header>

            <VigsScoreIndicator />
            <HealthDataGrid onMetricClick={handleMetricClick} />
            <AlertsList />

            {isProfileOpen && <EditProfileModal onClose={handleProfileUpdate} />}

            {selectedMetric && (
                <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm animate-fade-in">
                    <div className="bg-white p-6 rounded-3xl shadow-2xl w-full max-w-lg border border-gray-100">
                        <div className="flex justify-between items-center mb-6">
                            <div>
                                <h3 className="text-2xl font-black text-brand-gray-800">Evolución: {selectedMetric.label}</h3>
                                <p className="text-sm text-brand-gray-500 font-bold uppercase">{selectedMetric.unit}</p>
                            </div>
                            <button onClick={() => setSelectedMetric(null)} className="text-gray-400 hover:text-red-500 bg-gray-50 p-2 rounded-full transition-colors"><XMarkIcon /></button>
                        </div>
                        {isLoadingHistory ? (
                            <div className="h-64 flex flex-col items-center justify-center">
                                <div className="animate-spin rounded-full h-12 w-12 border-b-4 border-brand-blue mb-4"></div>
                                <p className="font-bold text-brand-gray-500">Buscando sus registros...</p>
                            </div>
                        ) : (
                            <div className="mt-2">
                                <HistoryChart data={historyData} unit={selectedMetric.unit} color="#005A9C" referenceRange={chartReferenceRange}/>
                            </div>
                        )}
                        <div className="mt-8 text-center">
                            <button onClick={() => setSelectedMetric(null)} className="w-full bg-brand-gray-100 text-brand-gray-700 font-black py-4 px-8 rounded-2xl hover:bg-brand-gray-200 transition-colors uppercase tracking-widest text-sm">Cerrar Gráfico</button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

export default HomeScreen;

