const EditProfileModal: React.FC<{ onClose: (updatedProfile?: UserProfile) => void }> = ({ onClose }) => {
    const { user } = useAuth();
    const context = useContext(AppContext);
    const { setDiaryPreferences } = context!;
    const [profile, setProfile] = useState<UserProfile | null>(null);
    const [loading, setLoading] = useState(true);
    const [saving, setSaving] = useState(false);
    const [activeTab, setActiveTab] = useState<'personal' | 'diary'>('personal');

    useEffect(() => {
        const fetchProfile = async () => {
            if (!user) return;
            const data = await getUserProfile(user.uid);
            if (data) setProfile(data);
            setLoading(false);
        };
        fetchProfile();
    }, [user]);

    const handleSave = async () => {
        if (!user || !profile) return;
        setSaving(true);
        try {
            await updateUserProfile(user.uid, profile);
            setDiaryPreferences(profile.diaryPreferences); 
