Para solucionar el error de "columna ya existente" y asegurar que la tabla tenga exactamente la estructura que necesitas para tu analítica, utiliza el siguiente script SQL. 

Este script es **definitivo** y limpia cualquier conflicto previo:

### 1. SQL Definitivo (Ejecutar en Supabase SQL Editor)

```sql
-- 1. Limpieza de seguridad (Cuidado: Borra datos previos de estas tablas)
DROP TABLE IF EXISTS public.clinical_reports CASCADE;
DROP TABLE IF EXISTS public.daily_logs CASCADE;
DROP TABLE IF EXISTS public.nutrition_logs CASCADE;
DROP TABLE IF EXISTS public.vigs_log CASCADE;
-- Mantenemos la tabla de users para no perder las cuentas, solo aseguramos la columna email
ALTER TABLE IF EXISTS public.users ADD COLUMN IF NOT EXISTS email TEXT;

-- 2. Creación de la tabla de analítica con tus especificaciones exactas
CREATE TABLE public.clinical_reports (
  id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
  user_id UUID REFERENCES public.users(id) ON DELETE CASCADE,
  file_name TEXT,
  resumen_ia TEXT,
  hemoglobina NUMERIC,
  albumina NUMERIC,
  vitamina_d_25_oh NUMERIC,
  glucosa NUMERIC,
  creatinina NUMERIC,
  pcr NUMERIC,
  sodio NUMERIC,
  tsh NUMERIC,
  vitamina_b12 NUMERIC,
  created_at TIMESTAMP WITH TIME ZONE DEFAULT now()
);

-- 3. Recreación de tablas auxiliares para consistencia
CREATE TABLE public.daily_logs (
  id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
  user_id UUID REFERENCES public.users(id) ON DELETE CASCADE,
  peso_kg NUMERIC,
  frec_cardiaca_lpm INTEGER,
  tas_mmhg INTEGER,
  tad_mmhg INTEGER,
  sat_o2_pct NUMERIC,
  glucosa_mgdl NUMERIC,
  caidas_detectadas INTEGER DEFAULT 0,
  created_at TIMESTAMP WITH TIME ZONE DEFAULT now()
);

CREATE TABLE public.nutrition_logs (
  id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
  user_id UUID REFERENCES public.users(id) ON DELETE CASCADE,
  foto_url TEXT,
  comida_descripcion TEXT,
  calorias_est NUMERIC,
  proteinas_g NUMERIC,
  carbohidratos_g NUMERIC,
  grasas_g NUMERIC,
  created_at TIMESTAMP WITH TIME ZONE DEFAULT now()
);

CREATE TABLE public.vigs_log (
  id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
  user_id UUID REFERENCES public.users(id) ON DELETE CASCADE,
  puntuacion_vigs INTEGER,
  categoria_vigs TEXT,
  indice_fragil_vig NUMERIC,
  created_at TIMESTAMP WITH TIME ZONE DEFAULT now()
);

-- 4. Buckets de Almacenamiento
INSERT INTO storage.buckets (id, name, public)
VALUES ('clinical-reports', 'clinical-reports', true), ('nutrition-photos', 'nutrition-photos', true)
ON CONFLICT (id) DO NOTHING;

-- 5. Seguridad RLS (Row Level Security)
ALTER TABLE users ENABLE ROW LEVEL SECURITY;
ALTER TABLE clinical_reports ENABLE ROW LEVEL SECURITY;
ALTER TABLE daily_logs ENABLE ROW LEVEL SECURITY;
ALTER TABLE nutrition_logs ENABLE ROW LEVEL SECURITY;
ALTER TABLE vigs_log ENABLE ROW LEVEL SECURITY;

-- Políticas (Eliminar anteriores si existen para evitar duplicados)
DROP POLICY IF EXISTS "Own" ON users;
DROP POLICY IF EXISTS "Own" ON clinical_reports;
DROP POLICY IF EXISTS "Own" ON daily_logs;
DROP POLICY IF EXISTS "Own" ON nutrition_logs;
DROP POLICY IF EXISTS "Own" ON vigs_log;

CREATE POLICY "Own" ON users FOR ALL USING (auth.uid() = id);
CREATE POLICY "Own" ON clinical_reports FOR ALL USING (auth.uid() = user_id);
CREATE POLICY "Own" ON daily_logs FOR ALL USING (auth.uid() = user_id);
CREATE POLICY "Own" ON nutrition_logs FOR ALL USING (auth.uid() = user_id);
CREATE POLICY "Own" ON vigs_log FOR ALL USING (auth.uid() = user_id);
```

