/**
 * Obtiene un mensaje de error legible de Supabase.
 */
const getErrorMessage = (error: any): string => {
    if (!error) return "Error desconocido";
    if (typeof error === 'string') return error;
    if (error.message) {
        if (error.message.includes('row-level security')) {
            return "Error de seguridad (RLS): No tienes permiso para realizar esta operación o tu sesión ha expirado. Si te acabas de registrar, revisa tu correo de confirmación.";
        }
        if (error.message.includes('bucket_id')) return "El contenedor de archivos (Bucket) no existe. Por favor, créalo en Supabase Storage.";
        return error.message;
    }
    return JSON.stringify(error);
};

