export const registerUserInDb = async (uid: string, profile: UserProfile): Promise<void> => {
    if (isDemo) return;

    // We use upsert to ensure that if the record was already created by an auth trigger, 
    // we just update it with the additional metadata.
    const dbData = { id: uid, ...mapProfileToDb(profile) };

    const { error } = await supabase.from('users').upsert(dbData, { onConflict: 'id' });
    if (error) {
        console.error("RLS Error during upsert:", error);
        throw new Error(getErrorMessage(error));
    }
};

