const HomeScreen: React.FC = () => {
    const { user, signOut } = useAuth();
    const { healthData, setHealthData, setDiaryPreferences, diaryPreferences, setVigsScore } = useContext(AppContext)!;
    const [profileData, setProfileData] = useState<{name: string, avatarId: number} | null>(null);
    const [isProfileOpen, setIsProfileOpen] = useState(false);
    const [selectedMetric, setSelectedMetric] = useState<{key: keyof HealthData, label: string, unit: string} | null>(null);
    const [historyData, setHistoryData] = useState<ChartDataPoint[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [isSavingProfile, setIsSavingProfile] = useState(false);

    const loadProfile = async () => {
        if (!user) return;
        setIsLoading(true);
        try {
            const data = await getUserProfile(user.uid);
            if (data) {
                setProfileData({ name: data.displayName, avatarId: data.avatarId });
                setHealthData(data.healthData);
                setDiaryPreferences(data.diaryPreferences);
                setVigsScore(data.vigsScore);
            }
        } catch (e) {
            console.error(e);
        } finally {
            setIsLoading(false);
        }
    };

    useEffect(() => { loadProfile(); }, [user]);

    const handleLogout = async () => {
        if (window.confirm("¿Seguro que desea salir de su asistente?")) {
            await signOut();
        }
    };

    const handleMetricClick = async (key: keyof HealthData, label: string, unit: string) => {
        if (!user) return;
        setSelectedMetric({ key, label, unit });
        try {
            const logs = await getDailyHistory(user.uid);
            const chartData = logs
                .map(l => ({ date: l.createdAt, value: l[key] as number | null }))
                .filter(d => d.value !== null && !isNaN(d.value))
                .sort((a, b) => a.date.getTime() - b.date.getTime()) as ChartDataPoint[];
            setHistoryData(chartData);
        } catch (e) { console.error(e); }
    };

    const handleSaveProfile = async () => {
        if (!user || !profileData) return;
        setIsSavingProfile(true);
        try {
            await updateUserProfile(user.uid, {
                displayName: profileData.name,
                avatarId: profileData.avatarId,
                diaryPreferences: diaryPreferences
            });
            setIsProfileOpen(false);
        } catch (error) {
            console.error(error);
            alert("Error al guardar el perfil.");
        } finally {
            setIsSavingProfile(false);
        }
    };

    const toggleDiaryPreference = (id: keyof HealthData) => {
        setDiaryPreferences(prev => 
            prev.includes(id) ? prev.filter(x => x !== id) : [...prev, id]
        );
    };

    const AvatarComponent = profileData ? avatars[profileData.avatarId] || avatars[0] : avatars[0];

    if (isLoading) return (
        <div className="flex h-screen items-center justify-center bg-brand-gray-100">
            <div className="flex flex-col items-center">
                <div className="animate-spin rounded-full h-16 w-16 border-b-4 border-brand-blue mb-6"></div>
                <p className="font-black text-brand-gray-500 uppercase tracking-widest text-xs">Cargando su Asistente Silver...</p>
            </div>
        </div>
    );

    return (
        <div className="p-4 sm:p-6 pb-24 max-w-3xl mx-auto">
            <header className="flex justify-between items-center mb-12 pt-6">
                <div>
                    <h1 className="text-5xl font-black text-brand-gray-800 tracking-tighter leading-[0.85]">BUENOS DÍAS,<br/><span className="text-brand-blue">{profileData?.name.toUpperCase() || 'USUARIO'}</span></h1>
                    <p className="text-xs font-black text-brand-gray-400 uppercase tracking-[0.4em] mt-4">Fisiosilver Monitoring</p>
                </div>
                <div className="flex flex-col items-center gap-4">
                    <button onClick={() => setIsProfileOpen(true)} className="bg-white p-1 rounded-full shadow-2xl border-4 border-white hover:scale-110 hover:rotate-6 transition-all active:scale-95 ring-2 ring-brand-blue/10">
                        <AvatarComponent className="w-20 h-20" />
                    </button>
                    <button onClick={handleLogout} className="text-[10px] font-black text-white bg-brand-gray-800 px-4 py-2 rounded-full uppercase tracking-widest hover:bg-brand-red transition-all shadow-md">Salir</button>
                </div>
            </header>

            <VigsScoreIndicator />
            <HealthDataGrid onMetricClick={handleMetricClick} />
            <AlertsList />

            {/* Modal de Perfil y Preferencias */}
            {isProfileOpen && profileData && (
                <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-brand-gray-900/90 backdrop-blur-md animate-fade-in">
                    <div className="bg-white p-6 sm:p-10 rounded-[2.5rem] shadow-2xl w-full max-w-2xl border border-white/20 max-h-[90vh] overflow-y-auto">
                        <div className="flex justify-between items-center mb-8">
                            <h3 className="text-3xl font-black text-brand-gray-800 tracking-tighter uppercase">Mi Perfil</h3>
                            <button onClick={() => setIsProfileOpen(false)} className="text-brand-gray-300 hover:text-brand-red bg-brand-gray-50 p-3 rounded-full transition-all"><XMarkIcon /></button>
                        </div>

                        <div className="space-y-8">
                            <div>
                                <label className="block text-xs font-black text-brand-gray-400 uppercase tracking-widest mb-3">Nombre Público</label>
                                <input 
                                    type="text" 
                                    value={profileData.name} 
                                    onChange={e => setProfileData({...profileData, name: e.target.value})}
                                    className="w-full p-4 border-2 rounded-2xl text-xl font-bold focus:border-brand-blue outline-none"
                                />
                            </div>

                            <div>
                                <label className="block text-xs font-black text-brand-gray-400 uppercase tracking-widest mb-3">Avatar</label>
                                <div className="grid grid-cols-3 sm:grid-cols-6 gap-3">
                                    {avatars.map((A, i) => (
                                        <button 
                                            key={i} 
                                            onClick={() => setAvatarId(i)}
                                            className={`p-2 rounded-2xl flex justify-center border-2 transition-all ${profileData.avatarId === i ? 'border-brand-blue bg-blue-50 scale-105 shadow-md' : 'border-transparent bg-gray-50 hover:bg-gray-100'}`}
                                        >
                                            <A className="w-10 h-10" />
                                        </button>
                                    ))}
                                </div>
                            </div>

                            <div>
                                <label className="block text-xs font-black text-brand-gray-400 uppercase tracking-widest mb-3">Métricas del Diario</label>
                                <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                                    {diaryOptions.map(opt => (
                                        <label key={opt.id} className={`flex items-center p-4 border-2 rounded-2xl cursor-pointer transition-all ${diaryPreferences.includes(opt.id as any) ? 'bg-blue-50 border-brand-blue' : 'bg-white border-gray-100'}`}>
                                            <input 
                                                type="checkbox" 
                                                checked={diaryPreferences.includes(opt.id as any)} 
                                                onChange={() => toggleDiaryPreference(opt.id as any)}
                                                className="w-6 h-6 mr-4 text-brand-blue rounded border-gray-300"
                                            />
                                            <span className="text-lg font-bold text-gray-700">{opt.label}</span>
                                        </label>
                                    ))}
                                </div>
                            </div>
                        </div>

                        <div className="mt-10 flex gap-4">
                            <button onClick={() => setIsProfileOpen(false)} className="flex-1 py-5 bg-gray-100 text-gray-600 rounded-3xl font-black uppercase tracking-widest text-xs hover:bg-gray-200 transition-all">Cancelar</button>
                            <button 
                                onClick={handleSaveProfile} 
                                disabled={isSavingProfile}
                                className="flex-1 py-5 bg-brand-blue text-white rounded-3xl font-black uppercase tracking-widest text-xs shadow-xl hover:bg-sky-700 transition-all active:scale-95 disabled:bg-gray-300"
                            >
                                {isSavingProfile ? 'Guardando...' : 'Guardar Cambios'}
                            </button>
                        </div>
                    </div>
                </div>
            )}

            {selectedMetric && (
                <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-brand-gray-900/90 backdrop-blur-md animate-fade-in">
                    <div className="bg-white p-8 rounded-[2.5rem] shadow-2xl w-full max-w-lg border border-white/20">
                        <div className="flex justify-between items-center mb-8">
                            <div>
                                <h3 className="text-3xl font-black text-brand-gray-800 tracking-tighter uppercase">{selectedMetric.label}</h3>
                                <p className="text-xs font-black text-brand-blue uppercase tracking-widest">Análisis Histórico</p>
                            </div>
                            <button onClick={() => setSelectedMetric(null)} className="text-brand-gray-300 hover:text-brand-red bg-brand-gray-50 p-3 rounded-full transition-all"><XMarkIcon /></button>
                        </div>
                        <div className="mt-2">
                            <HistoryChart 
                                data={historyData} 
                                unit={selectedMetric.unit} 
                                color="#005A9C" 
                                referenceRange={RECOMMENDED_RANGES[selectedMetric.key]}
                            />
                        </div>
                        <button onClick={() => setSelectedMetric(null)} className="w-full mt-10 bg-brand-gray-800 text-white font-black py-5 rounded-3xl hover:bg-black transition-all uppercase tracking-widest text-xs shadow-xl">Cerrar</button>
                    </div>
                </div>
            )}
        </div>
    );
};

