import { GoogleGenAI, Type } from "@google/genai";
import type { ClinicalAnalysisResult, NutritionalAnalysisResult, HealthData, VigsScore } from "../types";

// Always use the named parameter `apiKey` and the environment variable directly.
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const fileToGenerativePart = async (file: File) => {
  const base64EncodedDataPromise = new Promise<string>((resolve) => {
    const reader = new FileReader();
    reader.onloadend = () => resolve((reader.result as string).split(',')[1]);
    reader.readAsDataURL(file);
  });
  return {
    inlineData: { data: await base64EncodedDataPromise, mimeType: file.type },
  };
};

export const analyzeClinicalReport = async (file: File): Promise<ClinicalAnalysisResult> => {
  try {
    const imagePart = await fileToGenerativePart(file);
    const prompt = `
      Eres un asistente médico experto en análisis de laboratorio clínico y geriatría. 
      Tu tarea es procesar el informe adjunto (imagen o PDF) para extraer biomarcadores clave que serán almacenados en una base de datos médica.

      BIOMARCADORES A EXTRAER (EXACTOS):
      1. Hemoglobina (Hb)
      2. Albúmina (Alb)
      3. Vitamina D (25-hidroxivitamina D o 25-OH-D)
      4. Glucosa en Ayunas (o Glicemia)
      5. eGFR (Tasa de Filtración Glomerular Estimada)
      6. Sodio (Na+)
      7. Proteína C Reactiva (PCR o CRP)
      8. Vitamina B12 (Cobalamina)
      9. TSH (Hormona Tiroestimulante)
      10. Creatinina sérica

      REGLAS DE EXTRACCIÓN:
      - Extrae el valor numérico y su unidad (ej: "13.2 g/dL", "4.1 g/dL", "32 ng/mL").
      - Si un valor NO está presente o es ilegible, escribe exactamente "No encontrado".
      - Genera un resumen clínico breve (máximo 100 palabras) sobre el estado general sugerido por los resultados.
      - Incluye 2-3 recomendaciones de salud generales, preventivas y no prescriptivas.

      IMPORTANTE: Tu respuesta debe ser un objeto JSON válido que siga exactamente el esquema proporcionado.
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: { parts: [imagePart, { text: prompt }] },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            summary: { type: Type.STRING, description: "Un resumen breve y profesional del informe." },
            biomarkers: {
              type: Type.OBJECT,
              description: "Valores numéricos y unidades de los biomarcadores.",
              properties: {
                hemoglobin: { type: Type.STRING },
                albumin: { type: Type.STRING },
                vitaminD: { type: Type.STRING },
                glucoseFasting: { type: Type.STRING },
                egfr: { type: Type.STRING },
                sodium: { type: Type.STRING },
                crp: { type: Type.STRING },
                vitaminB12: { type: Type.STRING },
                tsh: { type: Type.STRING },
                creatinine: { type: Type.STRING }
              },
              required: ["hemoglobin", "albumin", "vitaminD", "glucoseFasting", "egfr", "sodium", "crp", "vitaminB12", "tsh", "creatinine"]
            },
            recommendations: {
              type: Type.ARRAY,
              description: "Lista de 2-3 recomendaciones preventivas.",
              items: { type: Type.STRING }
            }
          },
          required: ["summary", "biomarkers", "recommendations"]
        }
      }
    });

    return JSON.parse(response.text || '{}');

  } catch (error) {
    console.error("Error analyzing clinical report:", error);
    throw new Error("Lo siento, ha ocurrido un error al analizar el informe. Por favor, asegúrese de que el archivo sea legible.");
  }
};


