                <div className="flex flex-col items-center gap-4">
                    <button onClick={() => setIsProfileOpen(true)} className="bg-white p-1 rounded-full shadow-2xl border-4 border-white hover:scale-110 hover:rotate-6 transition-all active:scale-95 ring-2 ring-brand-blue/10">
