export const generateHealthRecommendations = async (healthData: HealthData, vigsScore: VigsScore): Promise<{ title: string; justification: string; }[]> => {
  try {
    const prompt = `
      Eres un asistente de salud geriátrica, empático y alentador.
      Basado en los siguientes datos de salud de un paciente mayor, genera 2-3 recomendaciones.
      Cada recomendación debe consistir en:
      1. Un título corto y accionable.
      2. Una justificación simple y motivadora.

      Datos del Paciente:
      - Puntuación de Fragilidad (VIGS): ${vigsScore.score} (Categoría: ${vigsScore.category})
      - Peso: ${healthData.weight || 'No registrado'} kg
      - Tensión Arterial: ${healthData.systolicBP && healthData.diastolicBP ? `${healthData.systolicBP}/${healthData.diastolicBP}` : 'No registrado'} mmHg

