                                            >
                                                <span className="font-bold text-brand-gray-700">{opt.label}</span>
                                                {isSelected && <CheckCircleIcon className="w-6 h-6 text-brand-blue" />}
                                            </button>
                                        );
                                    })}
                                </div>
                            </div>

                            <div className="pt-6 space-y-4">
                                {isEditing ? (
                                    <button 
                                        onClick={handleSaveProfile}
                                        disabled={saveLoading}
                                        className="w-full bg-brand-green text-white font-black py-5 rounded-3xl hover:bg-green-700 transition-all uppercase tracking-widest text-sm shadow-xl flex items-center justify-center gap-3 disabled:bg-brand-gray-300"
