                                    >
                                        Cerrar Sesión
                                    </button>
                                )}
                            </div>
                        </div>
                    </div>
                </div>
            )}

            {/* --- MODAL DE HISTORIAL --- */}
            {selectedMetric && (
                <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-brand-gray-900/90 backdrop-blur-md animate-fade-in">
                    <div className="bg-white p-8 rounded-[2.5rem] shadow-2xl w-full max-w-lg border border-white/20">
                        <div className="flex justify-between items-center mb-8">
