                                                />
                                            </div>
                                            <div className="space-y-3">
                                                <label className="text-xs font-black text-brand-blue uppercase tracking-widest ml-1">F. Nacimiento</label>
                                                <input 
                                                    type="date" 
                                                    value={editBirthDate} 
                                                    onChange={e => setEditBirthDate(e.target.value)} 
                                                    className="w-full p-5 bg-white border-2 border-brand-gray-300 rounded-2xl focus:border-brand-blue outline-none font-bold text-xl text-brand-gray-900 shadow-sm" 
                                                />
                                            </div>
                                        </div>
                                    </div>
                                )}
                            </div>

                            <hr className="border-brand-gray-100" />

                            {/* Preferencias del Diario */}
                            <div className="space-y-6">
                                <div className="flex justify-between items-end mb-2">
                                    <h4 className="text-sm font-black text-brand-gray-500 uppercase tracking-[0.2em]">Configurar mi Diario</h4>
                                    {isEditing && <p className="text-[10px] font-bold text-brand-blue uppercase bg-blue-50 px-3 py-1 rounded-full border border-blue-100 animate-pulse">Pulse para activar/desactivar</p>}
                                </div>
                                <div className="grid grid-cols-1 gap-3">
                                    {diaryOptions.map(opt => {
                                        const isSelected = isEditing ? editDiaryPrefs.includes(opt.id as any) : diaryPreferences.includes(opt.id as any);
                                        return (
                                            <button 
                                                key={opt.id}
                                                disabled={!isEditing}
                                                onClick={() => setEditDiaryPrefs(prev => prev.includes(opt.id as any) ? prev.filter(x => x !== opt.id) : [...prev, opt.id as any])}
                                                className={`flex items-center justify-between p-6 rounded-[2rem] border-2 transition-all group ${isSelected ? 'border-brand-blue bg-blue-50 shadow-sm' : 'border-brand-gray-200 bg-white opacity-60'} ${isEditing && 'hover:scale-[1.01] active:scale-95 cursor-pointer hover:border-brand-blue/50'}`}
                                            >
                                                <span className={`font-black text-lg ${isSelected ? 'text-brand-blue' : 'text-brand-gray-600'}`}>{opt.label}</span>
                                                {isSelected && <CheckCircleIcon className="w-8 h-8 text-brand-blue" />}
                                            </button>
                                        );
                                    })}
                                </div>
                            </div>

                            {/* Botones de Acción */}
                            <div className="pt-8 space-y-4">
                                {isEditing ? (
                                    <div className="flex flex-col sm:flex-row gap-4">
                                        <button 
                                            onClick={() => { setIsEditing(false); loadProfile(); }}
                                            className="flex-1 bg-brand-gray-200 text-brand-gray-800 font-black py-6 rounded-[2.5rem] hover:bg-brand-gray-300 transition-all uppercase tracking-widest text-xs"
                                        >
                                            Cancelar y Volver
                                        </button>
                                        <button 
                                            onClick={handleSaveProfile}
                                            disabled={saveLoading}
                                            className="flex-[2] bg-brand-green text-white font-black py-6 rounded-[2.5rem] hover:bg-green-700 transition-all uppercase tracking-widest text-sm shadow-xl flex items-center justify-center gap-3 disabled:bg-brand-gray-300"
                                        >
                                            {saveLoading ? <div className="animate-spin h-6 w-6 border-b-2 border-white rounded-full"></div> : "Guardar todos los cambios"}
                                        </button>
                                    </div>
                                ) : (
                                    <button 
                                        onClick={() => signOut()}
                                        className="w-full bg-brand-red text-white font-black py-6 rounded-[2.5rem] hover:bg-red-800 transition-all uppercase tracking-widest text-sm shadow-lg active:scale-95 border-none"
                                    >
                                        Cerrar Sesión Segura
                                    </button>
                                )}
                            </div>
                        </div>
                    </div>
                </div>
            )}

            {/* --- MODAL DE HISTORIAL --- */}
            {selectedMetric && (
                <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-brand-gray-900/80 backdrop-blur-md animate-fade-in">
                    <div className="bg-white p-8 rounded-[3.5rem] shadow-2xl w-full max-w-lg border-b-8 border-brand-blue">
                        <div className="flex justify-between items-center mb-10">
                            <div>
                                <h3 className="text-3xl font-black text-brand-gray-900 tracking-tighter uppercase">{selectedMetric.label}</h3>
                                <p className="text-[10px] font-black text-brand-blue uppercase tracking-[0.3em] mt-1">Análisis de evolución temporal</p>
                            </div>
                            <button onClick={() => setSelectedMetric(null)} className="text-brand-gray-400 hover:text-brand-red bg-brand-gray-50 p-3 rounded-full transition-all"><XMarkIcon /></button>
                        </div>
                        <HistoryChart data={historyData} unit={selectedMetric.unit} color="#005A9C" referenceRange={RECOMMENDED_RANGES[selectedMetric.key]} />
                        <button onClick={() => setSelectedMetric(null)} className="w-full mt-10 bg-brand-gray-900 text-white font-black py-6 rounded-[2.5rem] hover:bg-black transition-all uppercase tracking-widest text-xs shadow-lg">Cerrar Gráfico</button>
                    </div>
                </div>
            )}
        </div>
    );
};

