            )}

            {/* --- MODAL DE HISTORIAL --- */}
            {selectedMetric && (
                <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-brand-gray-900/80 backdrop-blur-md animate-fade-in">
                    <div className="bg-white p-8 rounded-[3.5rem] shadow-2xl w-full max-w-lg border-b-8 border-brand-blue">
                        <div className="flex justify-between items-center mb-10">
                            <div>
                                <h3 className="text-3xl font-black text-brand-gray-900 tracking-tighter uppercase">{selectedMetric.label}</h3>
