const parseAIValue = (val: string | undefined): number | null => {
    if (!val || val.toLowerCase().includes('no encontrado')) return null;
    const num = parseFloat(val.replace(/[^\d.-]/g, ''));
    return isNaN(num) ? null : num;
};

