import React, { useState } from 'react';
import { useAuth } from '../contexts/AuthContext';
import { registerUserInDb } from '../services/firestore';
import type { UserProfile, HealthData } from '../types';
import { avatars } from '../components/Icons';

const diaryOptions = [
    { id: 'weight', label: 'Peso Corporal' },
    { id: 'systolicBP', label: 'Tensión Sistólica' },
    { id: 'diastolicBP', label: 'Tensión Diastólica' },
    { id: 'pulse', label: 'Pulso (LPM)' },
    { id: 'oxygenSaturation', label: 'Saturación Oxígeno' },
    { id: 'glucose', label: 'Azúcar en Sangre' },
    { id: 'falls', label: 'Control de Caídas' },
    { id: 'calfCircumference', label: 'Pantorrilla' },
    { id: 'abdominalCircumference', label: 'Abdomen' },
];

const LoginScreen: React.FC = () => {
  const { signIn, signUp } = useAuth();
  const [isRegistering, setIsRegistering] = useState(false); 
  const [step, setStep] = useState(0); 
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [infoMessage, setInfoMessage] = useState<string | null>(null);

  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [personalData, setPersonalData] = useState({ displayName: '', gender: 'male', height: '' });
  // Default values for internal profile consistency
  const [diaryFields, setDiaryFields] = useState<(keyof HealthData)[]>(['weight', 'systolicBP', 'diastolicBP', 'pulse', 'glucose', 'falls']);
  const [legalData, setLegalData] = useState({ hasLegalConsent: false, dataProcessingConsent: false });
  const [avatarId, setAvatarId] = useState(0);

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);
    setInfoMessage(null);
    setLoading(true);
    try {
        await signIn(email, password); 
    } catch (err: any) {
        setError(err.message || "Credenciales incorrectas o error de conexión.");
    } finally {
        setLoading(false);
    }
  };

  const handleNextStep = (e?: React.FormEvent) => {
      if (e) e.preventDefault();
      setError(null);
      if (step === 0) {
          if (password.length < 6) { setError("La contraseña debe tener al menos 6 caracteres."); return; }
          if (!email.includes('@')) { setError("Email inválido."); return; }
      }
      if (step === 1 && (!personalData.displayName || !personalData.height)) {
          setError("Complete su nombre de usuario y altura."); return;
      }
      if (step === 3 && (!legalData.hasLegalConsent || !legalData.dataProcessingConsent)) {
          setError("Acepte los términos legales."); return;
      }
      setStep(prev => prev + 1);
  };

  const handleFinalRegister = async () => {
      setLoading(true);
      setError(null);
      setInfoMessage(null);
      try {
          const authRes = await signUp(email, password);
          if (!authRes) {
              setInfoMessage("Por favor, revisa tu correo electrónico para confirmar tu cuenta antes de continuar.");
              return;
          }

          const newProfile: UserProfile = {
              email: email,
              displayName: personalData.displayName,
              // Fix: Removed non-existent birthDate property from UserProfile to fix line 80 error
              gender: personalData.gender as 'male' | 'female' | 'other',
              nationality: 'Española',
              language: 'Español',
              emergencyContactName: '',
              emergencyContactPhone: '',
              diaryPreferences: diaryFields, 
              hasLegalConsent: legalData.hasLegalConsent,
              dataProcessingConsent: legalData.dataProcessingConsent,
              avatarId: avatarId,
              healthData: {
                  weight: null, falls: null, systolicBP: null, diastolicBP: null, pulse: null,
                  oxygenSaturation: null, glucose: null, calfCircumference: null, abdominalCircumference: null,
                  height: parseFloat(personalData.height) || null
              },
              vigsScore: { score: 0, category: 'No frágil' },
              alerts: [{ id: Date.now(), type: 'success', title: 'Bienvenido', message: 'Su perfil ha sido creado correctamente.' }]
          };

          try {
              await registerUserInDb(authRes.uid, newProfile);
              setInfoMessage("¡Registro completado! Ya puedes iniciar sesión.");
              setIsRegistering(false);
          } catch (rlsError: any) {
              console.warn("RLS restriction during signup (common if email confirmation is required):", rlsError);
              setInfoMessage("Cuenta creada. Por favor, confirma tu correo electrónico antes de entrar.");
          }
      } catch (err: any) {
          setError(err.message || "Error inesperado en el registro.");
      } finally {
          setLoading(false);
      }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter') {
        if (step === 4) {
            handleFinalRegister();
        } else {
            handleNextStep();
        }
    }
  };

  const renderStepContent = () => {
      switch(step) {
          case 0: return (
              <div className="space-y-4" onKeyDown={handleKeyDown}>
                  <h2 className="text-2xl font-bold text-brand-blue mb-4">Paso 1: Su Cuenta</h2>
                  <input type="email" placeholder="Email" className="w-full p-4 border-2 rounded-xl text-lg outline-none focus:border-brand-blue text-brand-gray-900 font-bold" value={email} onChange={e => setEmail(e.target.value)} required />
                  <input type="password" placeholder="Contraseña (6+ caracteres)" className="w-full p-4 border-2 rounded-xl text-lg outline-none focus:border-brand-blue text-brand-gray-900 font-bold" value={password} onChange={e => setPassword(e.target.value)} required />
              </div>
          );
          case 1: return (
              <div className="space-y-4" onKeyDown={handleKeyDown}>
                  <h2 className="text-2xl font-bold text-brand-blue mb-4">Paso 2: Datos Personales</h2>
                  <div className="space-y-1">
                      <label className="text-sm font-bold text-gray-600 ml-1 uppercase tracking-widest">Nombre de usuario</label>
                      <input type="text" placeholder="Ej: JuanP80" className="w-full p-4 border-2 rounded-xl text-lg outline-none focus:border-brand-blue text-brand-gray-900 font-bold" value={personalData.displayName} onChange={e => setPersonalData({...personalData, displayName: e.target.value})} />
                  </div>
                  <div className="space-y-1">
                      <label className="text-sm font-bold text-gray-600 ml-1 uppercase tracking-widest">Altura (cm)</label>
                      <input type="number" placeholder="Ej: 170" className="w-full p-4 border-2 rounded-xl text-lg outline-none focus:border-brand-blue text-brand-gray-900 font-bold" value={personalData.height} onChange={e => setPersonalData({...personalData, height: e.target.value})} />
                  </div>
              </div>
          );
          case 2: return (
              <div className="space-y-3 max-h-[50vh] overflow-y-auto pr-2" onKeyDown={handleKeyDown}>
                  <h2 className="text-2xl font-bold text-brand-blue mb-2">Paso 3: Su Diario</h2>
                  <p className="text-gray-700 font-medium mb-4">Marque lo que desea registrar cada día:</p>
                  {diaryOptions.map((opt) => (
                      <label key={opt.id} className={`flex items-center p-4 border-2 rounded-2xl cursor-pointer transition-all ${diaryFields.includes(opt.id as any) ? 'bg-blue-50 border-brand-blue' : 'bg-white border-gray-200'}`}>
                          <input type="checkbox" checked={diaryFields.includes(opt.id as any)} onChange={() => setDiaryFields(prev => prev.includes(opt.id as any) ? prev.filter(x => x !== opt.id) : [...prev, opt.id as any])} className="w-6 h-6 mr-4 text-brand-blue rounded border-gray-300" />
                          <span className={`text-lg font-black ${diaryFields.includes(opt.id as any) ? 'text-brand-blue' : 'text-brand-gray-700'}`}>{opt.label}</span>
                      </label>
                  ))}
              </div>
          );
          case 3: return (
              <div className="space-y-4" onKeyDown={handleKeyDown}>
                  <h2 className="text-2xl font-bold text-brand-blue mb-4">Paso 4: Legal y Privacidad</h2>
                  <div className="p-4 bg-gray-50 rounded-2xl text-sm text-brand-gray-800 border-2 border-brand-gray-200 mb-4 max-h-48 overflow-y-auto">
                      <p className="font-black mb-2 text-brand-blue uppercase tracking-widest">Resumen de Privacidad:</p>
                      <p className="font-medium">Fisiosilver protege sus datos de salud con encriptación avanzada. Solo se utilizarán para realizar análisis de fragilidad y recomendaciones personalizadas por el asistente. Sus datos nunca se venderán a terceros.</p>
                  </div>
                  <label className="flex items-start gap-4 p-5 border-2 rounded-2xl bg-white cursor-pointer active:bg-gray-50 border-brand-gray-200 transition-colors hover:border-brand-blue/30">
                      <input type="checkbox" checked={legalData.hasLegalConsent} onChange={e => setLegalData({...legalData, hasLegalConsent: e.target.checked})} className="mt-1 w-6 h-6 text-brand-blue" />
                      <span className="text-brand-gray-900 font-bold">Acepto el consentimiento informado para el uso de la aplicación.</span>
                  </label>
                  <label className="flex items-start gap-4 p-5 border-2 rounded-2xl bg-white cursor-pointer active:bg-gray-50 border-brand-gray-200 transition-colors hover:border-brand-blue/30">
                      <input type="checkbox" checked={legalData.dataProcessingConsent} onChange={e => setLegalData({...legalData, dataProcessingConsent: e.target.checked})} className="mt-1 w-6 h-6 text-brand-blue" />
                      <span className="text-brand-gray-900 font-bold">Autorizo el tratamiento de mis datos de salud con fines de seguimiento médico.</span>
                  </label>
              </div>
          );
          case 4: return (
              <div className="grid grid-cols-3 gap-4" onKeyDown={handleKeyDown}>
                  <h2 className="col-span-3 text-2xl font-bold text-brand-blue mb-4 text-center">Paso 5: Elija su Avatar</h2>
                  {avatars.map((A, i) => (
                      <button key={i} onClick={() => setAvatarId(i)} className={`p-4 rounded-3xl flex justify-center transition-all ${avatarId === i ? 'ring-4 ring-brand-blue bg-blue-50 border-brand-blue' : 'bg-gray-50 border-transparent'} border-2`}><A className="w-16 h-16" /></button>
                  ))}
              </div>
          );
          default: return null;
      }
  };

  if (isRegistering) {
      return (
        <div className="min-h-screen bg-brand-gray-100 flex flex-col justify-center items-center p-4">
            <div className="bg-white p-6 sm:p-10 rounded-[2.5rem] shadow-2xl w-full max-w-xl border-t-8 border-brand-blue">
                <div className="mb-8 flex gap-2">
                    {[0,1,2,3,4].map(i => <div key={i} className={`h-3 flex-1 rounded-full ${i <= step ? 'bg-brand-blue' : 'bg-brand-gray-200'}`}></div>)}
                </div>
                <div className="min-h-[350px]">
                    {renderStepContent()}
                </div>
                {error && <p className="mt-6 text-brand-red font-black text-center p-5 bg-red-50 rounded-2xl text-sm border-2 border-red-100 uppercase tracking-tight">{error}</p>}
                {infoMessage && <p className="mt-6 text-brand-blue font-black text-center p-5 bg-blue-50 rounded-2xl text-sm border-2 border-blue-100 uppercase tracking-tight">{infoMessage}</p>}
                <div className="mt-10 flex gap-4">
                    {step > 0 && <button onClick={() => setStep(s => s - 1)} className="flex-1 py-5 bg-brand-gray-100 text-brand-gray-700 rounded-2xl font-black text-lg active:scale-95 transition-all uppercase tracking-widest">Atrás</button>}
                    <button onClick={step === 4 ? handleFinalRegister : () => handleNextStep()} disabled={loading} className="flex-[2] py-5 bg-brand-blue text-white rounded-2xl font-black text-lg shadow-xl active:scale-95 transition-all uppercase tracking-widest">
                        {loading ? 'Procesando...' : (step === 4 ? 'Finalizar Registro' : 'Siguiente')}
                    </button>
                </div>
                <button onClick={() => { setIsRegistering(false); setError(null); setInfoMessage(null); }} className="w-full mt-8 text-brand-gray-500 font-black hover:text-brand-blue transition-colors uppercase text-xs tracking-widest">¿Ya tiene cuenta? Iniciar Sesión</button>
            </div>
        </div>
      );
  }

  return (
    <div className="min-h-screen bg-brand-gray-100 flex flex-col justify-center items-center p-4">
      <div className="bg-white p-10 rounded-[3rem] shadow-2xl w-full max-w-md text-center border-t-8 border-brand-blue">
        <h1 className="text-5xl font-black text-brand-blue mb-2 tracking-tighter uppercase">Fisiosilver</h1>
        <p className="text-brand-gray-500 mb-12 text-xs font-black uppercase tracking-[0.4em]">Asistente de Salud Senior</p>
        <form onSubmit={handleLogin} className="space-y-6">
          <input type="email" placeholder="Correo electrónico" required value={email} onChange={e => setEmail(e.target.value)} className="w-full p-5 bg-brand-gray-50 border-2 border-brand-gray-200 rounded-2xl text-xl focus:border-brand-blue outline-none font-black text-brand-gray-900 placeholder:text-brand-gray-300" />
          <input type="password" placeholder="Contraseña" required value={password} onChange={e => setPassword(e.target.value)} className="w-full p-5 bg-brand-gray-50 border-2 border-brand-gray-200 rounded-2xl text-xl focus:border-brand-blue outline-none font-black text-brand-gray-900 placeholder:text-brand-gray-300" />
          {error && <p className="text-brand-red font-black bg-red-50 p-4 rounded-xl text-sm border-2 border-red-100 uppercase tracking-tight">{error}</p>}
          {infoMessage && <p className="text-brand-blue font-black bg-blue-50 p-4 rounded-xl text-sm border-2 border-blue-100 uppercase tracking-tight">{infoMessage}</p>}
          <button type="submit" disabled={loading} className="w-full bg-brand-blue text-white font-black py-6 rounded-3xl text-xl shadow-2xl hover:bg-sky-700 transition-all active:scale-95 uppercase tracking-widest">
            {loading ? 'Entrando...' : 'Iniciar Sesión'}
          </button>
        </form>
        <div className="mt-12 pt-8 border-t border-brand-gray-100">
            <button onClick={() => { setIsRegistering(true); setError(null); setInfoMessage(null); setStep(0); }} className="w-full py-5 border-2 border-brand-blue text-brand-blue font-black rounded-3xl text-sm active:scale-95 transition-all hover:bg-blue-50 uppercase tracking-widest">Crear Cuenta Nueva</button>
        </div>
      </div>
    </div>
  );
};

