import React, { useState, useContext, useCallback } from 'react';
import { AppContext } from '../contexts/AppContext';
import { useAuth } from '../contexts/AuthContext';
import { saveDailyLog, updateUserProfile } from '../services/firestore';
import { CheckCircleIcon } from '../components/Icons';
import type { HealthData, Alert } from '../types';

type DailyDataForm = { [K in keyof HealthData]: string };

const initialFormData: DailyDataForm = {
    weight: '',
    falls: '',
    systolicBP: '',
    diastolicBP: '',
    pulse: '',
    oxygenSaturation: '',
    glucose: '',
    calfCircumference: '',
    abdominalCircumference: '',
    height: '',
};

const formFields: { label: string; id: keyof HealthData; unit: string; }[] = [
    { label: "Peso", id: "weight", unit: "kg" },
    { label: "Tensión Sistólica (Alta)", id: "systolicBP", unit: "mmHg" },
    { label: "Tensión Diastólica (Baja)", id: "diastolicBP", unit: "mmHg" },
    { label: "Pulso", id: "pulse", unit: "lpm" },
    { label: "Saturación de Oxígeno", id: "oxygenSaturation", unit: "%" },
    { label: "Glucemia", id: "glucose", unit: "mg/dl" },
    { label: "Perímetro Pantorrilla", id: "calfCircumference", unit: "cm" },
    { label: "Perímetro Abdominal", id: "abdominalCircumference", unit: "cm" },
    { label: "Nº de caídas esta semana", id: "falls", unit: "veces" },
];

const InputField: React.FC<{
    label: string;
    id: keyof HealthData;
    unit: string;
    value: string;
    placeholder?: string;
    onChange: (id: keyof HealthData, value: string) => void;
}> = ({ label, id, unit, value, placeholder, onChange }) => {

    const getInputMode = (): 'text' | 'decimal' | 'numeric' => {
        switch (id) {
            case 'weight':
            case 'calfCircumference':
            case 'abdominalCircumference':
                return 'decimal';
            case 'falls':
            case 'pulse':
            case 'oxygenSaturation':
            case 'glucose':
            case 'systolicBP':
            case 'diastolicBP':
                return 'numeric';
            default:
                return 'text';
        }
    };

    const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        let val = e.target.value;
        const inputMode = getInputMode();

        if (inputMode === 'decimal') {
            val = val.replace(/[^0-9.]/g, '').replace(/(\..*)\./g, '$1');
        } else if (inputMode === 'numeric') {
            val = val.replace(/[^0-9]/g, '');
        }

        onChange(id, val);
    };

    return (
        <div className="mb-8">
            <label htmlFor={id} className="block text-2xl text-brand-gray-800 font-black mb-3 uppercase tracking-tighter">{label}</label>
            <div className="relative">
                <input
                    type="text"
                    inputMode={getInputMode()}
                    id={id}
                    name={id}
                    value={value}
                    onChange={handleChange}
                    placeholder={placeholder}
                    className="w-full p-6 pr-28 text-2xl bg-white border-4 border-brand-gray-400 rounded-2xl focus:ring-8 focus:ring-brand-blue/20 focus:border-brand-blue outline-none transition-all font-black text-brand-gray-900 placeholder:text-brand-gray-300 shadow-sm"
                />
                <span className="absolute inset-y-0 right-0 flex items-center pr-8 text-lg font-black text-brand-blue pointer-events-none uppercase">
                    {unit}
                </span>
            </div>
        </div>
    );
};


const DiaryScreen: React.FC = () => {
    const context = useContext(AppContext);
    const { user } = useAuth();
    const { healthData, setHealthData, setAlerts, diaryPreferences } = context!;

    const [formData, setFormData] = useState<DailyDataForm>(initialFormData);
    const [isSavingData, setIsSavingData] = useState(false);
    const [successMessage, setSuccessMessage] = useState<string | null>(null);

    const visibleFields = formFields.filter(field => 
        (diaryPreferences || []).includes(field.id)
    );

    const handleFormChange = useCallback((field: keyof HealthData, value: string) => {
        setFormData(prev => ({ ...prev, [field]: value }));
    }, []);

    const handleSaveDailyData = async () => {
        if (!user) return;
        setIsSavingData(true);
        setSuccessMessage(null);

        const updatedData: Partial<HealthData> = {};
        let hasNewData = false;

        (Object.keys(formData) as Array<keyof HealthData>).forEach(key => {
            if (key === 'height') return;
            const value = formData[key];
            if (value.trim() !== '') {
                hasNewData = true;
                const numValue = parseFloat(value);
                if (!isNaN(numValue)) {
                    updatedData[key] = numValue;
                }
            }
        });

        if (!hasNewData) {
            alert("Por favor, introduzca al menos un dato para guardar.");
            setIsSavingData(false);
            return;
        }

        const newHealthData = { ...healthData, ...updatedData };

        try {
            await saveDailyLog(user.uid, newHealthData);
            setHealthData(newHealthData);

            const newAlerts: Alert[] = [
                { id: Date.now(), type: 'success', title: 'Datos Guardados', message: `Sus datos se han guardado con éxito.` },
                ...context!.alerts.filter(a => a.type !== 'success' && a.type !== 'danger'),
            ];

            setAlerts(newAlerts);
            await updateUserProfile(user.uid, { alerts: newAlerts });

            setSuccessMessage('Los datos se han guardado correctamente.');
            setTimeout(() => setSuccessMessage(null), 3000);
            setFormData(initialFormData);

        } catch (error: any) {
            console.error("Failed to save data:", error);
            const errorMsg = error instanceof Error ? error.message : (error?.message || "Error al conectar con la base de datos.");

            setAlerts(prev => [
                { id: Date.now(), type: 'danger', title: 'Error de Guardado', message: errorMsg },
                ...prev
            ]);
            alert(`Hubo un error: ${errorMsg}`);
        } finally {
            setIsSavingData(false);
        }
    };

    return (
        <div className="p-4 sm:p-8">
            <header className="mb-10">
                <h1 className="text-5xl font-black text-brand-gray-900 tracking-tighter uppercase">Diario de Salud</h1>
                <p className="text-xl text-brand-gray-600 font-bold mt-2">Registre sus constantes para estar tranquilo.</p>
            </header>

            <section className="bg-white p-8 rounded-[3rem] shadow-xl mb-12 border-4 border-brand-gray-50">
                <h2 className="text-3xl font-black text-brand-blue mb-8 uppercase tracking-tighter">Nueva Entrada de Hoy</h2>

                {visibleFields.length > 0 ? (
                    <div className="space-y-2">
                        {visibleFields.map(field => (
                            <InputField
                                key={field.id}
                                label={field.label}
                                id={field.id}
                                unit={field.unit}
                                value={formData[field.id]}
                                onChange={handleFormChange}
                                placeholder={healthData[field.id]?.toString() || ''}
                            />
                        ))}
                    </div>
                ) : (
                    <div className="bg-brand-gray-50 p-12 rounded-[2rem] text-center border-4 border-dashed border-brand-gray-200">
                         <p className="text-brand-gray-500 font-black uppercase text-sm tracking-widest">No hay métricas visibles. Configure su diario en su perfil.</p>
                    </div>
                )}

                <button
                    onClick={handleSaveDailyData}
                    disabled={isSavingData}
                    className="w-full mt-10 bg-brand-blue text-white text-2xl font-black py-8 px-6 rounded-[2.5rem] shadow-2xl hover:bg-sky-800 transition-all active:scale-[0.96] disabled:bg-brand-gray-300 disabled:cursor-not-allowed uppercase tracking-widest"
                >
                    {isSavingData ? 'Enviando a la nube...' : 'Guardar mis datos ahora'}
                </button>

                {successMessage && (
                    <div className="mt-8 p-6 bg-green-50 text-green-700 rounded-[2rem] border-4 border-green-200 flex items-center justify-center animate-bounce shadow-sm">
                        <CheckCircleIcon />
                        <span className="ml-4 font-black text-xl uppercase tracking-tighter">{successMessage}</span>
                    </div>
                )}
            </section>
        </div>
    );
};

export default DiaryScreen;

import { supabase, isSupabaseConfigured } from './supabaseClient';
import type { UserProfile, HealthData, ClinicalAnalysis, NutritionalAnalysis, VigsCategory } from '../types';

const isDemo = !isSupabaseConfigured;

const getErrorMessage = (error: any): string => {
    if (!error) return "Error desconocido";
    if (typeof error === 'string') return error;
    if (error.message) {
        if (error.message.includes('row-level security') || error.code === '42501') {
            return "Error de seguridad (RLS): No tienes permiso para esta operación.";
        }
        return error.message;
    }
    return JSON.stringify(error);
};

const getCurrentUserId = async (): Promise<string | null> => {
    const { data: { session } } = await supabase.auth.getSession();
    return session?.user?.id || null;
};

const getCategoryFromIndex = (index: number): VigsCategory => {
    if (index < 0.20) return 'No frágil';
    if (index <= 0.37) return 'Fragilidad leve';
    if (index <= 0.54) return 'Fragilidad moderada';
    return 'Fragilidad severa';
};

// --- Mapping App -> DB ---
// Solo incluimos campos que existen en la tabla public.users del SQL
const mapProfileToDb = (profile: Partial<UserProfile>) => {
    const dbData: any = {};
    if (profile.email !== undefined) dbData.email = profile.email;
    if (profile.displayName !== undefined) dbData.nombre_usuario = profile.displayName;
    if (profile.avatarId !== undefined) dbData.avatar_id = profile.avatarId;
    if (profile.diaryPreferences !== undefined) dbData.diary_preferences = profile.diaryPreferences;
    if (profile.alerts !== undefined) dbData.alerts_json = profile.alerts;

    if (profile.healthData?.height !== undefined) {
        dbData.talla_cm = profile.healthData.height || 170;
    }

    return dbData;
};

// --- Mapping DB -> App ---
const mapDbToProfile = (data: any, latestLog?: any, latestVigs?: any): UserProfile => {
    const index = latestVigs?.indice_vig_resultado ?? 0;
    return {
        email: data.email || '',
        displayName: data.nombre_usuario || 'Usuario',
        gender: 'male', // Por defecto ya que no está en DB
        nationality: 'Española', // Por defecto ya que no está en DB
        language: 'Español',
        emergencyContactName: '', 
        emergencyContactPhone: '', 
        diaryPreferences: data.diary_preferences || ['weight', 'systolicBP', 'diastolicBP', 'pulse', 'glucose'],
        hasLegalConsent: true,
        dataProcessingConsent: true,
        avatarId: data.avatar_id || 0,
        healthData: { 
            weight: latestLog?.peso_kg ?? null,
            systolicBP: latestLog?.tas_mmhg ?? null,
            diastolicBP: latestLog?.tad_mmhg ?? null,
            pulse: latestLog?.frec_cardiaca_lpm ?? null,
            oxygenSaturation: latestLog?.sat_o2_pct ?? null,
            glucose: latestLog?.glucosa_mgdl ?? null,
            falls: latestLog?.caidas_detectadas ?? null,
            calfCircumference: latestLog?.pantorrilla_cm ?? null,
            abdominalCircumference: latestLog?.abdomen_cm ?? null,
            height: data.talla_cm || 170
        },
        vigsScore: { 
            score: latestVigs?.puntos_totales ?? 0, 
            category: getCategoryFromIndex(index), 
            index: index
        },
        alerts: data.alerts_json || []
    };
};

export const initializeUser = async (uid: string, email: string): Promise<UserProfile> => {
    if (isDemo) return mapDbToProfile({ email, nombre_usuario: 'Usuario Demo' });
    const { data: user, error: userError } = await supabase.from('users').select('*').eq('id', uid).maybeSingle();

    if (!user) {
        const defaultProfile: UserProfile = {
            email, displayName: 'Nuevo Usuario', gender: 'male', nationality: 'Española',
            language: 'Español', emergencyContactName: '', emergencyContactPhone: '',
            hasLegalConsent: true, dataProcessingConsent: true, avatarId: 0,
            diaryPreferences: ['weight', 'systolicBP', 'diastolicBP', 'pulse', 'glucose'],
            healthData: { weight: null, falls: null, systolicBP: null, diastolicBP: null, pulse: null, oxygenSaturation: null, glucose: null, calfCircumference: null, abdominalCircumference: null, height: 170 },
            vigsScore: { score: 0, category: 'No frágil', index: 0 },
            alerts: []
        };
        try { await registerUserInDb(uid, defaultProfile); } catch (e) {}
        return defaultProfile;
    }

    const { data: latestLog } = await supabase.from('daily_logs').select('*').eq('user_id', uid).order('created_at', { ascending: false }).limit(1).maybeSingle();
    const { data: latestVigs } = await supabase.from('vigs_assessments').select('*').eq('user_id', uid).order('created_at', { ascending: false }).limit(1).maybeSingle();

    return mapDbToProfile(user, latestLog, latestVigs);
};

export const getUserProfile = async (uid: string): Promise<UserProfile | null> => {
    return initializeUser(uid, '');
};

export const updateUserProfile = async (uid: string, profile: Partial<UserProfile>): Promise<void> => {
    if (isDemo) return;
    const currentUid = await getCurrentUserId();
    if (!currentUid || currentUid !== uid) throw new Error("Sesión no válida.");

    const dbData = mapProfileToDb(profile);
    const { error } = await supabase.from('users').update(dbData).eq('id', uid);
    if (error) throw new Error(getErrorMessage(error));
};

export const saveVigsAssessment = async (uid: string, answers: Record<string, number>): Promise<void> => {
    if (isDemo) return;
    const currentUid = await getCurrentUserId();
    if (!currentUid || currentUid !== uid) throw new Error("Sesión no válida.");

    const totalPoints = Object.values(answers).reduce((sum, val) => sum + val, 0);
    const index = totalPoints / 25.0;

    const dbData = {
        user_id: uid,
        ayuda_dinero: answers.dinero > 0,
        ayuda_telefono: answers.telefono > 0,
        ayuda_medicacion: answers.medicacion > 0,
        barthel_grado: answers.barthel,
        perdida_peso_6m: answers.malnutricion > 0,
        deterioro_cognitivo_grado: answers.deterioro_cognitivo,
        usa_antidepresivos: answers.depresion > 0,
        usa_psicofarmacos: answers.ansiedad > 0,
        vulnerabilidad_social: answers.vulnerabilidad > 0,
        presenta_delirium: answers.confusional > 0,
        caidas_recuentes: answers.caidas > 0,
        presenta_ulceras: answers.ulceras > 0,
        polifarmacia: answers.polifarmacia > 0,
        presenta_disfagia: answers.disfagia > 0,
        dolor_control_dificil: answers.dolor > 0,
        disnea_basal: answers.disnea > 0,
        enf_oncologica: answers.cancer,
        enf_respiratoria: answers.respiratoria,
        enf_cardiaca: answers.cardiaca,
        enf_neurodegenerativa: answers.neurologica,
        enf_digestiva: answers.digestiva,
        enf_renal_cronica: answers.renal,
        puntos_totales: totalPoints,
        indice_vig_resultado: index
    };

    const { error } = await supabase.from('vigs_assessments').insert(dbData);
    if (error) throw new Error(getErrorMessage(error));
};

