export const uploadFile = async (bucket: string, file: File): Promise<string> => {
    const fileName = `${Math.random()}-${file.name.replace(/[^a-zA-Z0-9.-]/g, '_')}`;
    const { error: uploadError } = await supabase.storage.from(bucket).upload(fileName, file);
    if (uploadError) throw new Error(getErrorMessage(uploadError));
    const { data } = supabase.storage.from(bucket).getPublicUrl(fileName);
    return data.publicUrl;
};

export const saveAppointment = async (uid: string, title: string, description: string): Promise<void> => {
    const { data: userRecord, error: userFetchError } = await supabase.from('users').select('alerts_json').eq('id', uid).maybeSingle();
    if (userFetchError) throw new Error(getErrorMessage(userFetchError));
    const currentAlerts = userRecord?.alerts_json || [];
    const newAlerts = [{ id: Date.now(), type: 'info', title, message: description }, ...currentAlerts];
    const { error: updateError } = await supabase.from('users').update({ alerts_json: newAlerts }).eq('id', uid);
    if (updateError) throw new Error(getErrorMessage(updateError));
};

import React, { useState } from 'react';
import { useAuth } from '../contexts/AuthContext';
import { registerUserInDb } from '../services/firestore';
import type { UserProfile, HealthData } from '../types';
import { avatars } from '../components/Icons';

const diaryOptions = [
    { id: 'weight', label: 'Peso Corporal' },
    { id: 'systolicBP', label: 'Tensión Sistólica' },
    { id: 'diastolicBP', label: 'Tensión Diastólica' },
    { id: 'pulse', label: 'Pulso (LPM)' },
    { id: 'oxygenSaturation', label: 'Saturación Oxígeno' },
    { id: 'glucose', label: 'Azúcar en Sangre' },
    { id: 'falls', label: 'Control de Caídas' },
    { id: 'calfCircumference', label: 'Pantorrilla' },
    { id: 'abdominalCircumference', label: 'Abdomen' },
];

const LoginScreen: React.FC = () => {
  const { signIn, signUp } = useAuth();
  const [isRegistering, setIsRegistering] = useState(false); 
  const [step, setStep] = useState(0); 
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [infoMessage, setInfoMessage] = useState<string | null>(null);

  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [personalData, setPersonalData] = useState({ displayName: '', gender: 'male', height: '' });
  const [diaryFields, setDiaryFields] = useState<(keyof HealthData)[]>(['weight', 'systolicBP', 'diastolicBP', 'pulse', 'glucose']);
  const [legalData, setLegalData] = useState({ hasLegalConsent: false, dataProcessingConsent: false });
  const [avatarId, setAvatarId] = useState(0);

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);
    setInfoMessage(null);
    setLoading(true);
    try {
        await signIn(email, password); 
    } catch (err: any) {
        setError(err.message || "Credenciales incorrectas o error de conexión.");
    } finally {
        setLoading(false);
    }
  };

  const handleNextStep = (e?: React.FormEvent) => {
      if (e) e.preventDefault();
      setError(null);
      if (step === 0) {
          if (password.length < 6) { setError("La contraseña debe tener al menos 6 caracteres."); return; }
          if (!email.includes('@')) { setError("Email inválido."); return; }
      }
      if (step === 1 && (!personalData.displayName || !personalData.height)) {
          setError("Complete su nombre de usuario y altura."); return;
      }
      if (step === 3 && (!legalData.hasLegalConsent || !legalData.dataProcessingConsent)) {
          setError("Acepte los términos legales."); return;
      }
      setStep(prev => prev + 1);
  };

  const handleFinalRegister = async () => {
      setLoading(true);
      setError(null);
      setInfoMessage(null);
      try {
          const authRes = await signUp(email, password);
          if (!authRes) {
              setInfoMessage("Por favor, revisa tu correo electrónico para confirmar tu cuenta antes de continuar.");
              return;
          }

          const heightVal = parseFloat(personalData.height) || 170;

          // Creamos el perfil siguiendo estrictamente el esquema de la tabla users
          const newProfile: UserProfile = {
              email: email,
              displayName: personalData.displayName,
              gender: personalData.gender as 'male' | 'female' | 'other',
              nationality: 'Española',
              language: 'Español',
              emergencyContactName: '',
              emergencyContactPhone: '',
              diaryPreferences: diaryFields, 
              hasLegalConsent: legalData.hasLegalConsent,
              dataProcessingConsent: legalData.dataProcessingConsent,
              avatarId: avatarId,
              healthData: {
                  weight: null, falls: null, systolicBP: null, diastolicBP: null, pulse: null,
                  oxygenSaturation: null, glucose: null, calfCircumference: null, abdominalCircumference: null,
                  height: heightVal
              },
              vigsScore: { score: 0, category: 'No frágil' },
              alerts: [{ id: Date.now(), type: 'success', title: 'Bienvenido', message: 'Su perfil ha sido creado correctamente.' }]
          };

          try {
              // Esta llamada inserta en public.users vinculando con el ID de auth.users
              await registerUserInDb(authRes.uid, newProfile);
              setInfoMessage("¡Registro completado! Ya puedes iniciar sesión.");
              setIsRegistering(false);
          } catch (dbError: any) {
              console.error("Database Registration Failed:", dbError);
              setError(`Error en base de datos: ${dbError.message}. Revisa tus políticas RLS en Supabase.`);
          }
      } catch (err: any) {
          setError(err.message || "Error inesperado en el registro.");
      } finally {
          setLoading(false);
      }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter') {
        if (step === 4) handleFinalRegister();
        else handleNextStep();
    }
  };

  // ESTILO DE ALTO CONTRASTE: !bg-white fuerza el fondo blanco, text-brand-gray-900 fuerza el texto oscuro.
  const inputClass = "w-full p-5 bg-white !bg-white border-4 border-brand-gray-500 rounded-2xl text-xl outline-none focus:border-brand-blue focus:ring-4 focus:ring-brand-blue/20 text-brand-gray-900 font-black placeholder:text-brand-gray-400 shadow-sm transition-all";

  const renderStepContent = () => {
      switch(step) {
          case 0: return (
              <div className="space-y-6" onKeyDown={handleKeyDown}>
                  <h2 className="text-3xl font-black text-brand-blue mb-4 tracking-tighter uppercase">Paso 1: Su Cuenta</h2>
                  <div className="space-y-2">
                    <label className="text-sm font-black text-brand-gray-700 uppercase tracking-widest ml-1">Correo Electrónico</label>
                    <input type="email" placeholder="ejemplo@correo.com" className={inputClass} value={email} onChange={e => setEmail(e.target.value)} required />
                  </div>
                  <div className="space-y-2">
                    <label className="text-sm font-black text-brand-gray-700 uppercase tracking-widest ml-1">Contraseña</label>
                    <input type="password" placeholder="Mínimo 6 caracteres" className={inputClass} value={password} onChange={e => setPassword(e.target.value)} required />
                  </div>
              </div>
          );
          case 1: return (
              <div className="space-y-6" onKeyDown={handleKeyDown}>
                  <h2 className="text-3xl font-black text-brand-blue mb-4 tracking-tighter uppercase">Paso 2: Datos Personales</h2>
                  <div className="space-y-2">
                      <label className="text-sm font-black text-brand-gray-700 uppercase tracking-widest ml-1">Nombre de usuario</label>
                      <input type="text" placeholder="Ej: JuanP80" className={inputClass} value={personalData.displayName} onChange={e => setPersonalData({...personalData, displayName: e.target.value})} />
                  </div>
                  <div className="space-y-2">
                      <label className="text-sm font-black text-brand-gray-700 uppercase tracking-widest ml-1">Altura (cm)</label>
                      <input type="number" placeholder="Ej: 170" className={inputClass} value={personalData.height} onChange={e => setPersonalData({...personalData, height: e.target.value})} />
                  </div>
              </div>
          );
          case 2: return (
              <div className="space-y-3 max-h-[50vh] overflow-y-auto pr-2" onKeyDown={handleKeyDown}>
                  <h2 className="text-3xl font-black text-brand-blue mb-2 tracking-tighter uppercase">Paso 3: Su Diario</h2>
                  <p className="text-brand-gray-600 font-bold mb-4 uppercase text-xs tracking-widest">¿Qué desea anotar cada día?</p>
                  {diaryOptions.map((opt) => (
                      <label key={opt.id} className={`flex items-center p-5 border-4 rounded-[2rem] cursor-pointer transition-all ${diaryFields.includes(opt.id as any) ? 'bg-blue-50 border-brand-blue' : 'bg-white border-brand-gray-200'}`}>
                          <input type="checkbox" checked={diaryFields.includes(opt.id as any)} onChange={() => setDiaryFields(prev => prev.includes(opt.id as any) ? prev.filter(x => x !== opt.id) : [...prev, opt.id as any])} className="w-8 h-8 mr-4 text-brand-blue rounded border-brand-gray-400" />
                          <span className={`text-xl font-black ${diaryFields.includes(opt.id as any) ? 'text-brand-blue' : 'text-brand-gray-800'}`}>{opt.label}</span>
                      </label>
                  ))}
              </div>
          );
          case 3: return (
              <div className="space-y-6" onKeyDown={handleKeyDown}>
                  <h2 className="text-3xl font-black text-brand-blue mb-4 tracking-tighter uppercase">Paso 4: Privacidad</h2>
                  <div className="p-6 bg-brand-gray-50 rounded-[2rem] text-sm text-brand-gray-800 border-4 border-brand-gray-200 mb-4 max-h-48 overflow-y-auto font-bold leading-relaxed">
                      Sus datos están protegidos y solo se usan para mejorar su salud. Nunca se compartirán con empresas de publicidad.
                  </div>
                  <label className="flex items-center gap-4 p-6 border-4 rounded-[2rem] bg-white cursor-pointer border-brand-gray-200 hover:border-brand-blue transition-all">
                      <input type="checkbox" checked={legalData.hasLegalConsent} onChange={e => setLegalData({...legalData, hasLegalConsent: e.target.checked})} className="w-8 h-8 text-brand-blue border-brand-gray-400" />
                      <span className="text-brand-gray-900 font-black text-lg">Acepto el uso de la aplicación.</span>
                  </label>
                  <label className="flex items-center gap-4 p-6 border-4 rounded-[2rem] bg-white cursor-pointer border-brand-gray-200 hover:border-brand-blue transition-all">
                      <input type="checkbox" checked={legalData.dataProcessingConsent} onChange={e => setLegalData({...legalData, dataProcessingConsent: e.target.checked})} className="w-8 h-8 text-brand-blue border-brand-gray-400" />
                      <span className="text-brand-gray-900 font-black text-lg">Autorizo el tratamiento de mis datos de salud.</span>
                  </label>
              </div>
          );
          case 4: return (
              <div className="grid grid-cols-3 gap-6" onKeyDown={handleKeyDown}>
                  <h2 className="col-span-3 text-3xl font-black text-brand-blue mb-4 text-center tracking-tighter uppercase">Paso 5: Su Imagen</h2>
                  {avatars.map((A, i) => (
                      <button key={i} onClick={() => setAvatarId(i)} className={`p-6 rounded-[2rem] flex justify-center transition-all ${avatarId === i ? 'ring-8 ring-brand-blue/20 bg-blue-50 border-brand-blue shadow-xl scale-110' : 'bg-white border-brand-gray-200'} border-4`}><A className="w-16 h-16" /></button>
                  ))}
              </div>
          );
          default: return null;
      }
  };

  if (isRegistering) {
      return (
        <div className="min-h-screen bg-brand-gray-100 flex flex-col justify-center items-center p-4">
            <div className="bg-white p-8 sm:p-12 rounded-[3rem] shadow-2xl w-full max-w-xl border-t-[12px] border-brand-blue">
                <div className="mb-10 flex gap-3">
                    {[0,1,2,3,4].map(i => <div key={i} className={`h-4 flex-1 rounded-full ${i <= step ? 'bg-brand-blue' : 'bg-brand-gray-200'}`}></div>)}
                </div>
                <div className="min-h-[400px]">
                    {renderStepContent()}
                </div>
                {error && <p className="mt-8 text-brand-red font-black text-center p-5 bg-red-50 rounded-2xl border-4 border-red-200 uppercase tracking-tight shadow-sm leading-tight">{error}</p>}
                {infoMessage && <p className="mt-8 text-brand-blue font-black text-center p-5 bg-blue-50 rounded-2xl border-4 border-blue-200 uppercase tracking-tight shadow-sm">{infoMessage}</p>}
                <div className="mt-12 flex gap-4">
                    {step > 0 && <button onClick={() => setStep(s => s - 1)} className="flex-1 py-6 bg-brand-gray-200 text-brand-gray-700 rounded-[2rem] font-black text-xl active:scale-95 transition-all uppercase tracking-widest">Atrás</button>}
                    <button onClick={step === 4 ? handleFinalRegister : () => handleNextStep()} disabled={loading} className="flex-[2] py-6 bg-brand-blue text-white rounded-[2rem] font-black text-xl shadow-2xl active:scale-95 transition-all uppercase tracking-widest">
                        {loading ? 'Procesando...' : (step === 4 ? 'Registrarme ahora' : 'Siguiente paso')}
                    </button>
                </div>
                <button onClick={() => { setIsRegistering(false); setError(null); setInfoMessage(null); }} className="w-full mt-10 text-brand-gray-500 font-black hover:text-brand-blue transition-colors uppercase text-sm tracking-[0.2em]">Ya tengo cuenta. Entrar aquí.</button>
            </div>
        </div>
      );
  }

  return (
    <div className="min-h-screen bg-brand-gray-100 flex flex-col justify-center items-center p-4">
      <div className="bg-white p-12 rounded-[4rem] shadow-2xl w-full max-w-md text-center border-t-[12px] border-brand-blue">
        <h1 className="text-6xl font-black text-brand-blue mb-4 tracking-tighter uppercase">Fisiosilver</h1>
        <p className="text-brand-gray-500 mb-14 text-sm font-black uppercase tracking-[0.4em]">Asistente de Salud Senior</p>
        <form onSubmit={handleLogin} className="space-y-8">
          <div className="space-y-2 text-left">
            <label className="text-xs font-black text-brand-gray-700 uppercase tracking-widest ml-1">Correo Electrónico</label>
            <input type="email" placeholder="ejemplo@correo.com" required value={email} onChange={e => setEmail(e.target.value)} className={inputClass} />
          </div>
          <div className="space-y-2 text-left">
            <label className="text-xs font-black text-brand-gray-700 uppercase tracking-widest ml-1">Contraseña</label>
            <input type="password" placeholder="Su clave secreta" required value={password} onChange={e => setPassword(e.target.value)} className={inputClass} />
          </div>
          {error && <p className="text-brand-red font-black bg-red-50 p-6 rounded-[2rem] border-4 border-red-200 uppercase tracking-tight shadow-sm">{error}</p>}
          {infoMessage && <p className="text-brand-blue font-black bg-blue-50 p-6 rounded-[2rem] border-4 border-blue-200 uppercase tracking-tight shadow-sm">{infoMessage}</p>}
          <button type="submit" disabled={loading} className="w-full bg-brand-blue text-white font-black py-8 rounded-[2.5rem] text-2xl shadow-2xl hover:bg-sky-700 transition-all active:scale-95 uppercase tracking-widest mt-4">
            {loading ? 'Entrando...' : 'Entrar ahora'}
          </button>
        </form>
        <div className="mt-14 pt-10 border-t-4 border-brand-gray-100">
            <button onClick={() => { setIsRegistering(true); setError(null); setInfoMessage(null); setStep(0); }} className="w-full py-6 border-4 border-brand-blue text-brand-blue font-black rounded-[2rem] text-lg active:scale-95 transition-all hover:bg-blue-50 uppercase tracking-widest">Crear una cuenta nueva</button>
        </div>
      </div>
    </div>
  );
};

