import React, { useState, useContext, useCallback } from 'react';
import { AppContext } from '../contexts/AppContext';
import { useAuth } from '../contexts/AuthContext';
import { saveDailyLog, updateUserProfile } from '../services/firestore';
import { CheckCircleIcon } from '../components/Icons';
import type { HealthData, Alert } from '../types';

type DailyDataForm = { [K in keyof HealthData]: string };

const initialFormData: DailyDataForm = {
    weight: '',
    falls: '',
    systolicBP: '',
    diastolicBP: '',
    pulse: '',
    oxygenSaturation: '',
    glucose: '',
    calfCircumference: '',
    abdominalCircumference: '',
    height: '',
};

const formFields: { label: string; id: keyof HealthData; unit: string; }[] = [
    { label: "Peso", id: "weight", unit: "kg" },
    { label: "Tensión Sistólica (Alta)", id: "systolicBP", unit: "mmHg" },
    { label: "Tensión Diastólica (Baja)", id: "diastolicBP", unit: "mmHg" },
    { label: "Pulso", id: "pulse", unit: "lpm" },
    { label: "Saturación de Oxígeno", id: "oxygenSaturation", unit: "%" },
    { label: "Glucemia", id: "glucose", unit: "mg/dl" },
    { label: "Perímetro Pantorrilla", id: "calfCircumference", unit: "cm" },
    { label: "Perímetro Abdominal", id: "abdominalCircumference", unit: "cm" },
    { label: "Nº de caídas esta semana", id: "falls", unit: "veces" },
];

const InputField: React.FC<{
    label: string;
    id: keyof HealthData;
    unit: string;
    value: string;
    placeholder?: string;
    onChange: (id: keyof HealthData, value: string) => void;
}> = ({ label, id, unit, value, placeholder, onChange }) => {

    const getInputMode = (): 'text' | 'decimal' | 'numeric' => {
        switch (id) {
            case 'weight':
            case 'calfCircumference':
            case 'abdominalCircumference':
                return 'decimal';
            case 'falls':
            case 'pulse':
            case 'oxygenSaturation':
            case 'glucose':
            case 'systolicBP':
            case 'diastolicBP':
                return 'numeric';
            default:
                return 'text';
        }
    };

    const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        let val = e.target.value;
        const inputMode = getInputMode();

        if (inputMode === 'decimal') {
            val = val.replace(/[^0-9.]/g, '').replace(/(\..*)\./g, '$1');
        } else if (inputMode === 'numeric') {
            val = val.replace(/[^0-9]/g, '');
        }

        onChange(id, val);
    };

    return (
        <div className="mb-8">
            <label htmlFor={id} className="block text-2xl text-brand-gray-800 font-black mb-3 uppercase tracking-tighter">{label}</label>
            <div className="relative">
                <input
                    type="text"
                    inputMode={getInputMode()}
                    id={id}
                    name={id}
                    value={value}
                    onChange={handleChange}
                    placeholder={placeholder}
                    className="w-full p-6 pr-28 text-2xl bg-white !bg-white border-4 border-brand-gray-500 rounded-2xl focus:ring-8 focus:ring-brand-blue/20 focus:border-brand-blue outline-none transition-all font-black text-brand-gray-900 placeholder:text-brand-gray-300 shadow-sm"
                />
                <span className="absolute inset-y-0 right-0 flex items-center pr-8 text-lg font-black text-brand-blue pointer-events-none uppercase">
                    {unit}
                </span>
            </div>
        </div>
    );
};


const DiaryScreen: React.FC = () => {
    const context = useContext(AppContext);
    const { user } = useAuth();
    const { healthData, setHealthData, setAlerts, diaryPreferences } = context!;

    const [formData, setFormData] = useState<DailyDataForm>(initialFormData);
    const [isSavingData, setIsSavingData] = useState(false);
    const [successMessage, setSuccessMessage] = useState<string | null>(null);

    const visibleFields = formFields.filter(field => 
        (diaryPreferences || []).includes(field.id)
    );

    const handleFormChange = useCallback((field: keyof HealthData, value: string) => {
        setFormData(prev => ({ ...prev, [field]: value }));
    }, []);

    const handleSaveDailyData = async () => {
        if (!user) return;
        setIsSavingData(true);
        setSuccessMessage(null);

        const updatedData: Partial<HealthData> = {};
        let hasNewData = false;

        (Object.keys(formData) as Array<keyof HealthData>).forEach(key => {
            if (key === 'height') return;
            const value = formData[key];
            if (value.trim() !== '') {
                hasNewData = true;
                const numValue = parseFloat(value);
                if (!isNaN(numValue)) {
                    updatedData[key] = numValue;
                }
            }
        });

        if (!hasNewData) {
            alert("Por favor, introduzca al menos un dato para guardar.");
            setIsSavingData(false);
            return;
        }

        const newHealthData = { ...healthData, ...updatedData };

        try {
            await saveDailyLog(user.uid, newHealthData);
            setHealthData(newHealthData);

            const newAlerts: Alert[] = [
                { id: Date.now(), type: 'success', title: 'Datos Guardados', message: `Sus datos se han guardado con éxito.` },
                ...context!.alerts.filter(a => a.type !== 'success' && a.type !== 'danger'),
            ];

            setAlerts(newAlerts);
            await updateUserProfile(user.uid, { alerts: newAlerts });

            setSuccessMessage('Los datos se han guardado correctamente.');
            setTimeout(() => setSuccessMessage(null), 3000);
            setFormData(initialFormData);

        } catch (error: any) {
            console.error("Failed to save data:", error);
            const errorMsg = error instanceof Error ? error.message : (error?.message || "Error al conectar con la base de datos.");

            setAlerts(prev => [
                { id: Date.now(), type: 'danger', title: 'Error de Guardado', message: errorMsg },
                ...prev
            ]);
            alert(`Hubo un error: ${errorMsg}`);
        } finally {
            setIsSavingData(false);
        }
    };

    return (
        <div className="p-4 sm:p-8">
            <header className="mb-10">
                <h1 className="text-5xl font-black text-brand-gray-900 tracking-tighter uppercase">Diario de Salud</h1>
                <p className="text-xl text-brand-gray-600 font-bold mt-2">Registre sus constantes para estar tranquilo.</p>
            </header>

            <section className="bg-white p-8 rounded-[3rem] shadow-xl mb-12 border-4 border-brand-gray-50">
                <h2 className="text-3xl font-black text-brand-blue mb-8 uppercase tracking-tighter">Nueva Entrada de Hoy</h2>

                {visibleFields.length > 0 ? (
                    <div className="space-y-2">
                        {visibleFields.map(field => (
                            <InputField
                                key={field.id}
                                label={field.label}
                                id={field.id}
                                unit={field.unit}
                                value={formData[field.id]}
                                onChange={handleFormChange}
                                placeholder={healthData[field.id]?.toString() || ''}
                            />
                        ))}
                    </div>
                ) : (
                    <div className="bg-brand-gray-50 p-12 rounded-[2rem] text-center border-4 border-dashed border-brand-gray-200">
                         <p className="text-brand-gray-500 font-black uppercase text-sm tracking-widest">No hay métricas visibles. Configure su diario en su perfil.</p>
                    </div>
                )}

                <button
                    onClick={handleSaveDailyData}
                    disabled={isSavingData}
                    className="w-full mt-10 bg-brand-blue text-white text-2xl font-black py-8 px-6 rounded-[2.5rem] shadow-2xl hover:bg-sky-800 transition-all active:scale-[0.96] disabled:bg-brand-gray-300 disabled:cursor-not-allowed uppercase tracking-widest"
                >
                    {isSavingData ? 'Enviando a la nube...' : 'Guardar mis datos ahora'}
                </button>

                {successMessage && (
                    <div className="mt-8 p-6 bg-green-50 text-green-700 rounded-[2rem] border-4 border-green-200 flex items-center justify-center animate-bounce shadow-sm">
                        <CheckCircleIcon />
                        <span className="ml-4 font-black text-xl uppercase tracking-tighter">{successMessage}</span>
                    </div>
                )}
            </section>
        </div>
    );
};

