];

const RECOMMENDED_RANGES: Record<string, { min: number; max: number }> = {
    systolicBP: { min: 110, max: 140 },
    diastolicBP: { min: 60, max: 90 },
    pulse: { min: 60, max: 100 },
    oxygenSaturation: { min: 95, max: 100 },
    glucose: { min: 70, max: 110 },
    calfCircumference: { min: 31, max: 45 },
    abdominalCircumference: { min: 70, max: 102 },
};

const getVigsColorClass = (category: VigsCategory): string => {
  switch (category) {
    case 'No frágil': return 'text-brand-green bg-brand-soft-green';
    case 'Fragilidad leve': return 'text-emerald-600 bg-emerald-50';
    case 'Fragilidad moderada': return 'text-brand-yellow bg-brand-soft-yellow';
    case 'Fragilidad severa': return 'text-brand-red bg-brand-soft-red';
    default: return 'text-brand-gray-500 bg-brand-gray-100';
  }
};

interface ChartDataPoint { date: Date; value: number; }

const HistoryChart: React.FC<{ data: ChartDataPoint[]; color: string; referenceRange?: { min: number; max: number } }> = ({ data, color, referenceRange }) => {
    if (data.length < 2) return <div className="h-48 flex items-center justify-center bg-brand-gray-50 rounded-3xl"><p className="text-brand-gray-400 text-sm font-semibold uppercase tracking-wider">Historial insuficiente</p></div>;

    const width = 100; const height = 50; const padding = 6;
    const values = data.map(d => d.value);
    let minVal = Math.min(...values);
    let maxVal = Math.max(...values);

    if (referenceRange) {
        minVal = Math.min(minVal, referenceRange.min);
        maxVal = Math.max(maxVal, referenceRange.max);
    }
    const rangeBuffer = (maxVal - minVal) * 0.2;
    minVal = minVal - rangeBuffer;
    maxVal = maxVal + rangeBuffer;
    const range = maxVal - minVal || 1;

    const getX = (index: number) => padding + (index / (data.length - 1)) * (width - 2 * padding);
    const getY = (val: number) => height - padding - ((val - minVal) / range) * (height - 2 * padding);
    const pathD = data.map((d, i) => `${i === 0 ? 'M' : 'L'} ${getX(i)} ${getY(d.value)}`).join(' ');

    return (
        <div className="w-full">
            <div className="relative w-full aspect-[2/1] bg-white rounded-[2rem] p-4 overflow-visible">
                <svg viewBox={`0 0 ${width} ${height}`} className="w-full h-full overflow-visible">
                    {referenceRange && (
                        <rect x={padding} y={getY(referenceRange.max)} width={width - 2 * padding} height={Math.abs(getY(referenceRange.min) - getY(referenceRange.max))} fill="rgba(0, 90, 156, 0.03)" rx="2" />
                    )}
                    <path d={pathD} fill="none" stroke={color} strokeWidth="3" strokeLinecap="round" strokeLinejoin="round" />
                    {data.map((d, i) => (
                        <circle key={i} cx={getX(i)} cy={getY(d.value)} r="1.5" fill="white" stroke={color} strokeWidth="2" />
                    ))}
                </svg>
            </div>
        </div>
    );
};

const HomeScreen: React.FC = () => {
    const { user, signOut } = useAuth();
    const { healthData, setHealthData, setDiaryPreferences, diaryPreferences, setVigsScore, vigsScore } = useContext(AppContext)!;
    const [profile, setProfile] = useState<UserProfile | null>(null);
    const [isProfileOpen, setIsProfileOpen] = useState(false);
    const [isEditing, setIsEditing] = useState(false);
    const [selectedMetric, setSelectedMetric] = useState<{key: keyof HealthData, label: string, unit: string} | null>(null);
    const [historyData, setHistoryData] = useState<ChartDataPoint[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [saveLoading, setSaveLoading] = useState(false);

    const [editName, setEditName] = useState("");
    const [editHeight, setEditHeight] = useState("");
    const [editDiaryPrefs, setEditDiaryPrefs] = useState<(keyof HealthData)[]>([]);

    const loadProfile = async () => {
        if (!user) return;
        setIsLoading(true);
        try {
            const data = await getUserProfile(user.uid);
            if (data) {
                setProfile(data);
                setEditName(data.displayName);
                setEditHeight(data.healthData.height?.toString() || "");
                setEditDiaryPrefs(data.diaryPreferences);
                setHealthData(data.healthData);
                setDiaryPreferences(data.diaryPreferences);
                setVigsScore(data.vigsScore);
            }
        } catch (e) { console.error(e); }
        finally { setIsLoading(false); }
    };

    useEffect(() => { loadProfile(); }, [user]);

    const handleMetricClick = async (key: keyof HealthData, label: string, unit: string) => {
        if (!user) return;
        setSelectedMetric({ key, label, unit });
        try {
            const logs = await getDailyHistory(user.uid);
            const chartData = logs
                .map(l => ({ date: l.createdAt, value: l[key] as number | null }))
                .filter(d => d.value !== null)
                .sort((a, b) => a.date.getTime() - b.date.getTime()) as ChartDataPoint[];
            setHistoryData(chartData);
        } catch (e) { console.error(e); }
    };

    const handleSaveProfile = async () => {
        if (!user) return;
        setSaveLoading(true);
        try {
            const updates: Partial<UserProfile> = {
                displayName: editName,
                diaryPreferences: editDiaryPrefs,
                healthData: { ...healthData, height: editHeight ? parseFloat(editHeight) : null }
            };
            await updateUserProfile(user.uid, updates);
            await loadProfile(); 
            setIsEditing(false);
        } catch (e) { alert("Error al actualizar."); }
        finally { setSaveLoading(false); }
    };

    const AvatarComponent = profile ? avatars[profile.avatarId] || avatars[0] : avatars[0];
    const displayVigs = vigsScore.index !== undefined ? vigsScore.index.toFixed(2) : (vigsScore.score / 25.0).toFixed(2);

    if (isLoading) return <div className="flex h-screen items-center justify-center bg-brand-bg"><div className="animate-spin rounded-full h-10 w-10 border-b-2 border-brand-blue"></div></div>;

    return (
        <div className="p-6 max-w-4xl mx-auto animate-fade-in pb-32">
            {/* Soft Header */}
            <header className="flex justify-between items-center mb-10 pt-4">
                <div>
                    <p className="text-brand-gray-500 font-bold uppercase tracking-[0.2em] text-[10px] mb-1">Bienvenido de nuevo</p>
                    <h1 className="text-4xl font-black text-brand-gray-900 tracking-tighter">Hola, <span className="text-brand-blue">{profile?.displayName?.split(' ')[0] || 'Usuario'}</span></h1>
                </div>
                <button onClick={() => { setIsProfileOpen(true); setIsEditing(false); }} className="bg-white p-1 rounded-full shadow-soft hover:shadow-soft-lg transition-all active:scale-95 border-2 border-white">
                    <AvatarComponent className="w-16 h-16" />
                </button>
            </header>

            {/* Bento Grid Layout */}
            <div className="bento-grid">

                {/* VIGS Large Card */}
                <div className="bento-item-large bg-white p-8 rounded-v-large shadow-soft border border-brand-gray-50 flex items-center justify-between">
                    <div>
                        <h2 className="text-sm font-black text-brand-gray-400 uppercase tracking-widest mb-4">Estado de Fragilidad</h2>
                        <div className={`inline-block px-4 py-2 rounded-2xl font-black text-sm uppercase tracking-tighter mb-4 ${getVigsColorClass(vigsScore.category)}`}>
                            {vigsScore.category}
                        </div>
                        <p className="text-brand-gray-500 text-sm font-medium max-w-[200px]">Su índice IF-VIG actual indica un estado estable.</p>
                    </div>
                    <div className="flex flex-col items-center">
                        <div className="relative w-28 h-28 flex items-center justify-center">
                            <svg className="absolute inset-0 w-full h-full transform -rotate-90">
                                <circle cx="56" cy="56" r="48" fill="none" stroke="#F3F4F6" strokeWidth="8" />
                                <circle cx="56" cy="56" r="48" fill="none" stroke="#005A9C" strokeWidth="8" strokeDasharray="301.59" strokeDashoffset={301.59 * (1 - parseFloat(displayVigs))} strokeLinecap="round" />
                            </svg>
                            <span className="text-3xl font-black text-brand-gray-900 leading-none">{displayVigs}</span>
                        </div>
                    </div>
                </div>

                {/* Metrics Grid */}
                {diaryOptions.filter(opt => diaryPreferences.includes(opt.id as any)).map((opt, i) => {
                    const value = healthData[opt.id as keyof HealthData];
                    const unit = opt.label.includes('(') ? opt.label.split('(')[1].replace(')', '') : '';
                    const label = opt.label.split('(')[0].trim();

                    return (
                        <button 
