                            onClick={() => handleMetricClick(opt.id as any, label, unit)}
                            className="bg-white p-6 rounded-v-large shadow-soft border border-brand-gray-50 text-left hover:shadow-soft-lg transition-all active:scale-95 group animate-slide-up"
