  const [infoMessage, setInfoMessage] = useState<string | null>(null);

  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [personalData, setPersonalData] = useState({ displayName: '', gender: 'male', height: '' });
  const [diaryFields, setDiaryFields] = useState<(keyof HealthData)[]>(['weight', 'systolicBP', 'diastolicBP', 'pulse', 'glucose']);
  const [legalData, setLegalData] = useState({ hasLegalConsent: false, dataProcessingConsent: false });
  const [avatarId, setAvatarId] = useState(0);

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);
    setLoading(true);
    try {
        await signIn(email, password); 
    } catch (err: any) {
        setError("Correo o contraseña no válidos.");
    } finally {
        setLoading(false);
    }
  };

  const inputClass = "w-full p-4 bg-brand-gray-50 border border-brand-gray-200 rounded-2xl text-lg font-semibold focus:border-brand-blue focus:ring-4 focus:ring-brand-blue/5 outline-none transition-all placeholder:text-brand-gray-400";

  const renderStepContent = () => {
      switch(step) {
          case 0: return (
              <div className="space-y-6 animate-fade-in">
                  <h2 className="text-2xl font-black text-brand-gray-900 tracking-tighter uppercase">Datos de acceso</h2>
                  <input type="email" placeholder="Correo electrónico" className={inputClass} value={email} onChange={e => setEmail(e.target.value)} />
                  <input type="password" placeholder="Contraseña segura" className={inputClass} value={password} onChange={e => setPassword(e.target.value)} />
              </div>
          );
          case 1: return (
              <div className="space-y-6 animate-fade-in">
                  <h2 className="text-2xl font-black text-brand-gray-900 tracking-tighter uppercase">Sobre usted</h2>
                  <input type="text" placeholder="Su nombre" className={inputClass} value={personalData.displayName} onChange={e => setPersonalData({...personalData, displayName: e.target.value})} />
                  <input type="number" placeholder="Altura en cm" className={inputClass} value={personalData.height} onChange={e => setPersonalData({...personalData, height: e.target.value})} />
              </div>
          );
          case 2: return (
              <div className="space-y-3 max-h-[45vh] overflow-y-auto pr-2 animate-fade-in">
                  <h2 className="text-2xl font-black text-brand-gray-900 tracking-tighter uppercase">Mi Diario</h2>
                  {diaryOptions.map(opt => (
                      <button key={opt.id} onClick={() => setDiaryFields(prev => prev.includes(opt.id as any) ? prev.filter(x => x !== opt.id) : [...prev, opt.id as any])} className={`w-full text-left p-4 rounded-2xl border transition-all ${diaryFields.includes(opt.id as any) ? 'border-brand-blue bg-blue-50/50' : 'border-brand-gray-100 bg-white'}`}>
                          <span className={`font-bold ${diaryFields.includes(opt.id as any) ? 'text-brand-blue' : 'text-brand-gray-500'}`}>{opt.label}</span>
                      </button>
                  ))}
              </div>
          );
          case 3: return (
              <div className="space-y-6 animate-fade-in">
                  <h2 className="text-2xl font-black text-brand-gray-900 tracking-tighter uppercase">Privacidad</h2>
                  <div className="space-y-4">
                    <label className="flex items-start gap-4 p-4 rounded-2xl bg-brand-gray-50 border border-brand-gray-100 cursor-pointer">
                        <input type="checkbox" checked={legalData.hasLegalConsent} onChange={e => setLegalData({...legalData, hasLegalConsent: e.target.checked})} className="mt-1 w-5 h-5 accent-brand-blue" />
                        <span className="text-sm font-semibold text-brand-gray-600">Acepto los términos de uso de la aplicación.</span>
                    </label>
                    <label className="flex items-start gap-4 p-4 rounded-2xl bg-brand-gray-50 border border-brand-gray-100 cursor-pointer">
                        <input type="checkbox" checked={legalData.dataProcessingConsent} onChange={e => setLegalData({...legalData, dataProcessingConsent: e.target.checked})} className="mt-1 w-5 h-5 accent-brand-blue" />
                        <span className="text-sm font-semibold text-brand-gray-600">Autorizo el tratamiento de mis datos de salud de forma segura.</span>
                    </label>
                  </div>
              </div>
          );
          case 4: return (
              <div className="grid grid-cols-3 gap-4 animate-fade-in">
                  <h2 className="col-span-3 text-2xl font-black text-brand-gray-900 tracking-tighter uppercase">Elija su avatar</h2>
                  {avatars.map((A, i) => (
                      <button key={i} onClick={() => setAvatarId(i)} className={`p-4 rounded-2xl flex justify-center border-2 transition-all ${avatarId === i ? 'border-brand-blue bg-blue-50' : 'border-transparent bg-brand-gray-50'}`}><A className="w-12 h-12" /></button>
                  ))}
              </div>
          );
          default: return null;
      }
  };

  const handleNext = () => {
      if (step === 0 && (!email || password.length < 6)) { setError("Introduzca datos válidos."); return; }
      if (step === 1 && !personalData.displayName) { setError("Introduzca su nombre."); return; }
      if (step === 3 && (!legalData.hasLegalConsent || !legalData.dataProcessingConsent)) { setError("Debe aceptar los términos."); return; }
      setError(null);
      setStep(s => s + 1);
  };

  const handleRegister = async () => {
    setLoading(true);
    try {
        const res = await signUp(email, password);
        if (!res) { setInfoMessage("Revise su correo para confirmar su cuenta."); return; }
        await registerUserInDb(res.uid, {
            email, displayName: personalData.displayName, gender: 'male', nationality: 'Española', language: 'Español', emergencyContactName: '', emergencyContactPhone: '', hasLegalConsent: true, dataProcessingConsent: true, avatarId, diaryPreferences: diaryFields, healthData: { weight: null, falls: null, systolicBP: null, diastolicBP: null, pulse: null, oxygenSaturation: null, glucose: null, calfCircumference: null, abdominalCircumference: null, height: parseFloat(personalData.height) || 170 }, vigsScore: { score: 0, category: 'No frágil' }, alerts: []
        });
        setIsRegistering(false);
    } catch (e: any) { setError(e.message); }
    finally { setLoading(false); }
  };

  return (
    <div className="min-h-screen bg-brand-bg flex items-center justify-center p-6">
      <div className="bg-white p-10 sm:p-12 rounded-v-xl shadow-soft-lg w-full max-w-md border border-brand-gray-50">
        <div className="text-center mb-10">
            <h1 className="text-5xl font-black text-brand-blue tracking-tighter uppercase">Fisiosilver</h1>
            <p className="text-brand-gray-400 font-black text-[10px] uppercase tracking-[0.4em] mt-2">Salud Senior Inteligente</p>
        </div>

        {isRegistering ? (
            <div>
                <div className="flex gap-1 mb-8">
                    {[0,1,2,3,4].map(i => <div key={i} className={`h-1.5 flex-1 rounded-full transition-all duration-500 ${i <= step ? 'bg-brand-blue' : 'bg-brand-gray-100'}`}></div>)}
                </div>
                {renderStepContent()}
                {error && <p className="mt-6 text-brand-red text-center font-bold text-sm bg-brand-soft-red p-3 rounded-xl">{error}</p>}
                <div className="mt-10 flex gap-3">
                    {step > 0 && <button onClick={() => setStep(s => s - 1)} className="flex-1 py-4 bg-brand-gray-50 text-brand-gray-500 rounded-2xl font-black text-xs uppercase tracking-widest">Atrás</button>}
                    <button onClick={step === 4 ? handleRegister : handleNext} disabled={loading} className="flex-[2] py-4 bg-brand-blue text-white rounded-2xl font-black text-xs uppercase tracking-widest shadow-soft">{loading ? '...' : (step === 4 ? 'Finalizar' : 'Continuar')}</button>
                </div>
                <button onClick={() => setIsRegistering(false)} className="w-full mt-8 text-brand-gray-400 font-bold text-xs uppercase tracking-widest text-center">Ya tengo cuenta</button>
            </div>
        ) : (
            <form onSubmit={handleLogin} className="space-y-6">
                <input type="email" placeholder="Correo electrónico" className={inputClass} value={email} onChange={e => setEmail(e.target.value)} required />
                <input type="password" placeholder="Contraseña" className={inputClass} value={password} onChange={e => setPassword(e.target.value)} required />
                {error && <p className="text-brand-red text-center font-bold text-sm bg-brand-soft-red p-3 rounded-xl">{error}</p>}
                <button type="submit" disabled={loading} className="w-full py-5 bg-brand-blue text-white rounded-v-large font-black text-sm uppercase tracking-widest shadow-soft active:scale-95 transition-all">{loading ? 'Entrando...' : 'Entrar ahora'}</button>
                <div className="pt-6 border-t border-brand-gray-50 mt-8">
                    <button type="button" onClick={() => { setIsRegistering(true); setStep(0); }} className="w-full py-4 border-2 border-brand-blue text-brand-blue rounded-v-large font-black text-xs uppercase tracking-widest">Crear cuenta gratis</button>
                </div>
            </form>
        )}
      </div>
    </div>
  );
};

export default LoginScreen;

import React, { useState, useContext, useCallback } from 'react';
import { AppContext } from '../contexts/AppContext';
import { useAuth } from '../contexts/AuthContext';
import { saveDailyLog, updateUserProfile } from '../services/firestore';
import { CheckCircleIcon } from '../components/Icons';
import type { HealthData, Alert } from '../types';

type DailyDataForm = { [K in keyof HealthData]: string };

const initialFormData: DailyDataForm = {
    weight: '',
    falls: '',
    systolicBP: '',
    diastolicBP: '',
    pulse: '',
    oxygenSaturation: '',
    glucose: '',
    calfCircumference: '',
    abdominalCircumference: '',
    height: '',
};

const formFields: { label: string; id: keyof HealthData; unit: string; }[] = [
    { label: "Peso", id: "weight", unit: "kg" },
    { label: "Tensión Alta", id: "systolicBP", unit: "mmHg" },
    { label: "Tensión Baja", id: "diastolicBP", unit: "mmHg" },
    { label: "Pulso Cardiaco", id: "pulse", unit: "lpm" },
    { label: "Oxígeno en Sangre", id: "oxygenSaturation", unit: "%" },
    { label: "Azúcar (Glucosa)", id: "glucose", unit: "mg/dl" },
    { label: "Perímetro Pantorrilla", id: "calfCircumference", unit: "cm" },
    { label: "Perímetro Abdomen", id: "abdominalCircumference", unit: "cm" },
    { label: "Caídas detectadas", id: "falls", unit: "veces" },
];

const DiaryScreen: React.FC = () => {
    const context = useContext(AppContext);
    const { user } = useAuth();
    const { healthData, setHealthData, setAlerts, diaryPreferences } = context!;

    const [formData, setFormData] = useState<DailyDataForm>(initialFormData);
    const [isSaving, setIsSaving] = useState(false);
    const [success, setSuccess] = useState(false);

    const visibleFields = formFields.filter(f => (diaryPreferences || []).includes(f.id));

    const handleSave = async () => {
        if (!user) return;
        setIsSaving(true);
        const updated: Partial<HealthData> = {};
        Object.keys(formData).forEach(k => {
            const val = formData[k as keyof HealthData];
            if (val.trim()) updated[k as keyof HealthData] = parseFloat(val);
        });

        if (Object.keys(updated).length === 0) { setIsSaving(false); return; }

        try {
            await saveDailyLog(user.uid, { ...healthData, ...updated });
            setHealthData({ ...healthData, ...updated });
            setSuccess(true);
            setTimeout(() => setSuccess(false), 3000);
            setFormData(initialFormData);
        } catch (e) { alert("Error al guardar."); }
        finally { setIsSaving(false); }
    };

    return (
        <div className="p-6 max-w-2xl mx-auto animate-fade-in pb-32">
            <header className="mb-10 pt-4">
                <h1 className="text-4xl font-black text-brand-gray-900 tracking-tighter uppercase mb-2">Mi Diario</h1>
                <p className="text-brand-gray-500 font-medium">Anote sus mediciones hoy para llevar un control seguro.</p>
            </header>

            <div className="bg-white p-8 rounded-v-large shadow-soft border border-brand-gray-50">
                <div className="space-y-8">
                    {visibleFields.map(f => (
                        <div key={f.id} className="relative">
                            <label className="block text-[10px] font-black text-brand-gray-400 uppercase tracking-widest mb-2 ml-1">{f.label}</label>
                            <div className="flex items-center gap-4">
                                <input 
                                    type="number" 
                                    value={formData[f.id]} 
                                    onChange={e => setFormData({...formData, [f.id]: e.target.value})} 
                                    className="flex-1 p-5 bg-brand-gray-50 border border-brand-gray-100 rounded-2xl text-xl font-black text-brand-blue outline-none focus:border-brand-blue focus:ring-4 focus:ring-brand-blue/5 transition-all" 
                                    placeholder={healthData[f.id]?.toString() || '0'}
                                />
                                <span className="text-xs font-black text-brand-gray-400 uppercase tracking-tighter w-16">{f.unit}</span>
                            </div>
                        </div>
                    ))}
                </div>

                <button 
                    onClick={handleSave} 
                    disabled={isSaving} 
                    className="w-full mt-12 bg-brand-blue text-white py-6 rounded-v-large font-black text-sm uppercase tracking-widest shadow-soft hover:shadow-soft-lg active:scale-[0.98] transition-all disabled:bg-brand-gray-200"
                >
                    {isSaving ? 'Guardando...' : 'Confirmar Mediciones'}
                </button>

                {success && (
                    <div className="mt-8 p-5 bg-brand-soft-green text-brand-green rounded-2xl flex items-center justify-center gap-3 animate-fade-in">
                        <CheckCircleIcon className="w-5 h-5" />
                        <span className="font-black text-xs uppercase tracking-widest">Datos guardados con éxito</span>
                    </div>
                )}
            </div>
        </div>
    );
};

export default DiaryScreen;

