                    <Biomarker label="Vitamina D" value={analysis.biomarkers.vitaminD} />
                    <Biomarker label="Glucosa" value={analysis.biomarkers.glucoseFasting} />
                    <Biomarker label="TSH" value={analysis.biomarkers.tsh} />
