interface ChartDataPoint { date: Date; value: number; }

const DetailedHistoryChart: React.FC<{ 
    data: ChartDataPoint[]; 
    color: string; 
    metricKey: string;
    unit: string;
    referenceRange?: { min: number; max: number };
}> = ({ data, color, metricKey, unit, referenceRange }) => {
    if (data.length === 0) return <div className="h-64 flex flex-col items-center justify-center bg-brand-gray-50 rounded-3xl"><p className="text-brand-gray-400 text-sm font-black uppercase tracking-wider">Sin historial registrado</p></div>;

    const width = 400; const height = 200; const paddingX = 40; const paddingY = 30;
    const values = data.map(d => d.value);

    let minVal = Math.min(...values);
    let maxVal = Math.max(...values);

    if (referenceRange) {
        minVal = Math.min(minVal, referenceRange.min);
        maxVal = Math.max(maxVal, referenceRange.max);
    }

    const rangeBuffer = (maxVal - minVal) * 0.3 || 10;
    minVal = Math.max(0, minVal - rangeBuffer);
    maxVal = maxVal + rangeBuffer;
    const range = maxVal - minVal || 1;

    const getX = (index: number) => paddingX + (index / Math.max(1, data.length - 1)) * (width - 2 * paddingX);
    const getY = (val: number) => height - paddingY - ((val - minVal) / range) * (height - 2 * paddingY);

    const pathD = data.map((d, i) => `${i === 0 ? 'M' : 'L'} ${getX(i)} ${getY(d.value)}`).join(' ');

    return (
        <div className="w-full bg-white p-4 rounded-v-large border border-brand-gray-100 shadow-soft">
            <div className="flex justify-between items-center mb-6">
                <span className="text-[10px] font-black text-brand-gray-400 uppercase tracking-widest">Evolución</span>
                {referenceRange && (
                    <div className="flex items-center gap-2">
                        <div className="w-3 h-3 bg-brand-blue/10 rounded-sm"></div>
                        <span className="text-[10px] font-black text-brand-blue/60 uppercase">Rango Saludable: {referenceRange.min}-{referenceRange.max}{unit}</span>
                    </div>
                )}
            </div>
            <svg viewBox={`0 0 ${width} ${height}`} className="w-full h-auto overflow-visible">
                {/* Horizontal Grid lines */}
                {[0, 0.5, 1].map(p => (
                    <line key={p} x1={paddingX} y1={paddingY + p * (height - 2 * paddingY)} x2={width - paddingX} y2={paddingY + p * (height - 2 * paddingY)} stroke="#F3F4F6" strokeWidth="1" strokeDasharray="4 4" />
                ))}

                {/* Reference Range Background */}
                {referenceRange && (
                    <rect 
                        x={paddingX} 
                        y={getY(referenceRange.max)} 
                        width={width - 2 * paddingX} 
                        height={Math.max(1, Math.abs(getY(referenceRange.min) - getY(referenceRange.max)))} 
                        fill="rgba(0, 90, 156, 0.05)" 
                        rx="4" 
                    />
                )}

                {/* The Line */}
                <path d={pathD} fill="none" stroke={color} strokeWidth="4" strokeLinecap="round" strokeLinejoin="round" className="drop-shadow-sm" />

                {/* Data Points */}
                {data.map((d, i) => (
                    <g key={i} className="group cursor-pointer">
                        <circle cx={getX(i)} cy={getY(d.value)} r="5" fill="white" stroke={color} strokeWidth="3" />
                        <text x={getX(i)} y={getY(d.value) - 12} textAnchor="middle" className="text-[10px] font-black fill-brand-gray-900 opacity-0 group-hover:opacity-100 transition-opacity">{d.value}</text>
                    </g>
                ))}

                {/* X Axis Labels (Dates) */}
                {data.length > 0 && (
                    <>
                        <text x={getX(0)} y={height - 8} textAnchor="start" className="text-[8px] font-black fill-brand-gray-400 uppercase tracking-tighter">
                            {data[0].date.toLocaleDateString('es-ES', { day: 'numeric', month: 'short' })}
                        </text>
                        {data.length > 1 && (
                            <text x={getX(data.length - 1)} y={height - 8} textAnchor="end" className="text-[8px] font-black fill-brand-gray-400 uppercase tracking-tighter">
                                {data[data.length - 1].date.toLocaleDateString('es-ES', { day: 'numeric', month: 'short' })}
                            </text>
                        )}
                    </>
                )}
            </svg>
        </div>
    );
};

const HomeScreen: React.FC = () => {
    const { user, signOut } = useAuth();
    const { healthData, setHealthData, setDiaryPreferences, diaryPreferences, setVigsScore, vigsScore } = useContext(AppContext)!;
    const [profile, setProfile] = useState<UserProfile | null>(null);
    const [isProfileOpen, setIsProfileOpen] = useState(false);
    const [isEditing, setIsEditing] = useState(false);
    const [selectedMetric, setSelectedMetric] = useState<{key: keyof HealthData, label: string, unit: string} | null>(null);
    const [historyData, setHistoryData] = useState<ChartDataPoint[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [saveLoading, setSaveLoading] = useState(false);

    const [editName, setEditName] = useState("");
    const [editHeight, setEditHeight] = useState("");
    const [editDiaryPrefs, setEditDiaryPrefs] = useState<(keyof HealthData)[]>([]);

    const heightInMeters = (profile?.healthData.height || 170) / 100;
    const imcRange = { min: Math.round(18.5 * heightInMeters ** 2), max: Math.round(24.9 * heightInMeters ** 2) };

    const RECOMMENDED_RANGES: Record<string, { min: number; max: number }> = useMemo(() => ({
        systolicBP: { min: 110, max: 140 },
        diastolicBP: { min: 60, max: 90 },
        pulse: { min: 60, max: 100 },
        oxygenSaturation: { min: 95, max: 100 },
        glucose: { min: 70, max: 110 },
        calfCircumference: { min: 31, max: 45 },
        abdominalCircumference: { min: 70, max: 102 },
        weight: imcRange,
        falls: { min: 0, max: 0 }
    }), [imcRange]);

    // Derivación de nuevos índices
    const calculatedIndices = useMemo(() => {
        const vigs = vigsScore.index || (vigsScore.score / 25);
        const sys = healthData.systolicBP || 120;
        const dia = healthData.diastolicBP || 80;
        const falls = healthData.falls || 0;

        // Índice de Protección (Basado en VIGS y Alertas) - Cuanto más bajo VIGS, más alto protección
        const prot = Math.max(0, Math.min(100, (1 - vigs) * 100));
        // Riesgo Cardiovascular (Basado en TA)
        const cvRisk = Math.min(100, ((sys - 120) / 60 + (dia - 80) / 40) * 50);
        // Riesgo de Caídas (Basado en historial de caídas)
        const fallRisk = Math.min(100, falls * 25);
        // Riesgo de Hospitalización (Correlacionado con VIGS)
        const hospRisk = Math.min(100, vigs * 100);

        return {
            protection: prot.toFixed(0),
            cardio: cvRisk > 10 ? cvRisk.toFixed(0) : "Normal",
            falls: fallRisk > 0 ? (fallRisk > 50 ? "Alto" : "Moderado") : "Bajo",
            hospital: hospRisk > 50 ? "Moderado" : "Bajo"
        };
    }, [vigsScore, healthData]);

    const loadProfile = async () => {
        if (!user) return;
        setIsLoading(true);
        try {
            const data = await getUserProfile(user.uid);
            if (data) {
                setProfile(data);
                setEditName(data.displayName);
                setEditHeight(data.healthData.height?.toString() || "");
                setEditDiaryPrefs(data.diaryPreferences);
                setHealthData(data.healthData);
                setDiaryPreferences(data.diaryPreferences);
                setVigsScore(data.vigsScore);
            }
        } catch (e) { console.error(e); }
        finally { setIsLoading(false); }
    };

    useEffect(() => { loadProfile(); }, [user]);

    const handleMetricClick = async (key: keyof HealthData, label: string, unit: string) => {
        if (!user) return;
        setSelectedMetric({ key, label, unit });
        try {
            const logs = await getDailyHistory(user.uid);
            const chartData = logs
                .map(l => ({ date: l.createdAt, value: l[key] as number | null }))
                .filter(d => d.value !== null)
                .sort((a, b) => a.date.getTime() - b.date.getTime()) as ChartDataPoint[];
            setHistoryData(chartData);
        } catch (e) { console.error(e); }
    };

    const handleSaveProfile = async () => {
        if (!user) return;
        setSaveLoading(true);
        try {
            const updates: Partial<UserProfile> = {
                displayName: editName,
                diaryPreferences: editDiaryPrefs,
                healthData: { ...healthData, height: editHeight ? parseFloat(editHeight) : null }
            };
            await updateUserProfile(user.uid, updates);
            await loadProfile(); 
            setIsEditing(false);
        } catch (e) { alert("Error al actualizar."); }
        finally { setSaveLoading(false); }
    };

    const AvatarComponent = profile ? avatars[profile.avatarId] || avatars[0] : avatars[0];
    const displayVigs = parseFloat(vigsScore.index !== undefined ? vigsScore.index.toFixed(2) : (vigsScore.score / 25.0).toFixed(2));

    if (isLoading) return <div className="flex h-screen items-center justify-center bg-brand-bg"><div className="animate-spin rounded-full h-10 w-10 border-b-2 border-brand-blue"></div></div>;

    return (
        <div className="p-6 max-w-4xl mx-auto animate-fade-in pb-32">
            {/* Header con colores de alto contraste */}
            <header className="flex justify-between items-center mb-10 pt-4">
                <div>
                    <p className="text-brand-gray-500 font-black uppercase tracking-[0.2em] text-[10px] mb-1">Tu salud hoy</p>
                    <h1 className="text-4xl font-black text-brand-gray-900 tracking-tighter">Hola, <span className="text-brand-blue">{profile?.displayName?.split(' ')[0] || 'Usuario'}</span></h1>
                </div>
                <button onClick={() => { setIsProfileOpen(true); setIsEditing(false); }} className="bg-white p-1 rounded-full shadow-soft hover:shadow-soft-lg transition-all active:scale-95 border-2 border-brand-blue/20">
                    <AvatarComponent className="w-16 h-16" />
                </button>
            </header>

            {/* Bento Grid: Indices de Salud */}
            <div className="grid grid-cols-2 sm:grid-cols-4 gap-4 mb-8">
                {/* Fragilidad (Principal) */}
                <div className="col-span-2 bg-white p-6 rounded-v-large shadow-soft border border-brand-gray-50 flex flex-col justify-between min-h-[160px]">
                    <div className="flex justify-between items-start">
                        <div>
                            <h2 className="text-[10px] font-black text-brand-gray-400 uppercase tracking-widest mb-1">Fragilidad (VIGS)</h2>
                            <div className={`inline-block px-3 py-1 rounded-xl font-black text-[10px] uppercase tracking-tighter ${getVigsColorClass(vigsScore.category)}`}>
                                {vigsScore.category}
                            </div>
                        </div>
                        <div className="relative w-16 h-16 flex items-center justify-center">
                            <svg className="absolute inset-0 w-full h-full transform -rotate-90">
                                <circle cx="32" cy="32" r="28" fill="none" stroke="#F3F4F6" strokeWidth="6" />
                                <circle 
                                    cx="32" cy="32" r="28" fill="none" 
                                    stroke={displayVigs > 0.37 ? "#FFC107" : "#005A9C"} 
                                    strokeWidth="6" 
                                    strokeDasharray="175.93" 
                                    strokeDashoffset={175.93 * (1 - displayVigs)} 
                                    strokeLinecap="round" 
                                />
                            </svg>
                            <span className="text-xl font-black text-brand-gray-900 leading-none">{displayVigs.toFixed(2)}</span>
                        </div>
                    </div>
                    <p className="text-brand-gray-600 text-[11px] font-bold leading-tight mt-4">Nivel de dependencia y riesgo actual.</p>
                </div>

                {/* Otros 4 Indices */}
                <div className="bg-white p-5 rounded-v-large shadow-soft border border-brand-gray-50">
                    <h3 className="text-[9px] font-black text-brand-gray-400 uppercase tracking-widest mb-2">Protección</h3>
                    <div className="text-2xl font-black text-brand-green">{calculatedIndices.protection}%</div>
                    <div className="w-full h-1 bg-brand-gray-100 rounded-full mt-3 overflow-hidden">
                        <div className="h-full bg-brand-green" style={{ width: `${calculatedIndices.protection}%` }}></div>
                    </div>
                </div>
                <div className="bg-white p-5 rounded-v-large shadow-soft border border-brand-gray-50">
                    <h3 className="text-[9px] font-black text-brand-gray-400 uppercase tracking-widest mb-2">Cardio</h3>
                    <div className="text-xl font-black text-brand-blue">{calculatedIndices.cardio}</div>
                    <p className="text-[9px] font-bold text-brand-gray-500 mt-2">Basado en tensión</p>
                </div>
                <div className="bg-white p-5 rounded-v-large shadow-soft border border-brand-gray-50">
                    <h3 className="text-[9px] font-black text-brand-gray-400 uppercase tracking-widest mb-2">Riesgo Caídas</h3>
                    <div className={`text-xl font-black ${calculatedIndices.falls === 'Alto' ? 'text-brand-red' : 'text-brand-blue'}`}>{calculatedIndices.falls}</div>
                </div>
                <div className="bg-white p-5 rounded-v-large shadow-soft border border-brand-gray-50">
                    <h3 className="text-[9px] font-black text-brand-gray-400 uppercase tracking-widest mb-2">Hospit.</h3>
                    <div className="text-xl font-black text-brand-blue">{calculatedIndices.hospital}</div>
                </div>
            </div>

            {/* Metrics Bento Grid */}
            <h2 className="text-[10px] font-black text-brand-gray-400 uppercase tracking-[0.3em] mb-4 ml-2">Constantes Vitales</h2>
            <div className="bento-grid">
                {diaryOptions.filter(opt => diaryPreferences.includes(opt.id as any)).map((opt, i) => {
                    const value = healthData[opt.id as keyof HealthData];
                    const unit = opt.label.includes('(') ? opt.label.split('(')[1].replace(')', '') : '';
                    const label = opt.label.split('(')[0].trim();

                    return (
                        <button 
                            key={opt.id} 
                            onClick={() => handleMetricClick(opt.id as any, label, unit)}
                            className="bg-white p-6 rounded-v-large shadow-soft border border-brand-gray-50 text-left hover:shadow-soft-lg transition-all active:scale-95 group animate-slide-up"
                            style={{ animationDelay: `${i * 0.05}s` }}
                        >
                            <div className="w-10 h-10 bg-brand-lightblue rounded-2xl flex items-center justify-center text-brand-blue mb-4 group-hover:bg-brand-blue group-hover:text-white transition-colors">
                                <CheckCircleIcon className="w-5 h-5" />
                            </div>
                            <h3 className="text-[10px] font-black text-brand-gray-400 uppercase tracking-widest mb-1">{label}</h3>
                            <div className="flex items-baseline gap-1">
                                <span className="text-2xl font-black text-brand-gray-900">{value ?? '--'}</span>
                                <span className="text-[10px] font-bold text-brand-gray-400 uppercase">{unit}</span>
                            </div>
                        </button>
                    );
                })}
            </div>

            {/* Perfil (Drawer) - Corregido Visibilidad Texto */}
            {isProfileOpen && (
                <div className="fixed inset-0 z-50 flex items-end sm:items-center justify-center p-0 sm:p-6 bg-brand-gray-900/60 backdrop-blur-sm animate-fade-in">
                    <div className="bg-white w-full max-w-xl h-[90vh] sm:h-auto sm:max-h-[85vh] overflow-y-auto rounded-t-v-xl sm:rounded-v-xl shadow-soft-lg border-t border-brand-gray-100">
                        <div className="px-8 py-6 sticky top-0 bg-white/95 backdrop-blur flex justify-between items-center border-b border-brand-gray-50 z-20">
                            <h3 className="text-xl font-black text-brand-gray-900 uppercase tracking-tighter">Mi Perfil</h3>
                            <button onClick={() => setIsProfileOpen(false)} className="bg-brand-gray-100 p-2 rounded-full text-brand-gray-500 hover:text-brand-red transition-all"><XMarkIcon className="w-6 h-6"/></button>
                        </div>

                        <div className="p-8 pb-12">
                            <div className="flex flex-col items-center mb-10">
                                <div className="bg-brand-lightblue p-2 rounded-full ring-8 ring-brand-lightblue/30 mb-6">
                                    <AvatarComponent className="w-24 h-24" />
                                </div>
                                {!isEditing ? (
                                    <div className="text-center">
                                        <h4 className="text-2xl font-black text-brand-gray-900">{profile?.displayName}</h4>
                                        <p className="text-sm font-bold text-brand-gray-500 mb-6">{profile?.email}</p>
                                        <button onClick={() => setIsEditing(true)} className="px-8 py-4 bg-brand-lightblue text-brand-blue rounded-2xl text-xs font-black uppercase tracking-widest hover:bg-brand-blue hover:text-white transition-all shadow-sm flex items-center gap-2 mx-auto"><PencilSquareIcon className="w-4 h-4" /> Editar Perfil</button>
                                    </div>
                                ) : (
                                    <div className="w-full space-y-4">
                                        <input type="text" value={editName} onChange={e => setEditName(e.target.value)} className="w-full p-4 bg-white border-2 border-brand-gray-200 rounded-2xl font-black text-lg text-brand-gray-900 focus:border-brand-blue outline-none" placeholder="Nombre" />
                                        <input type="number" value={editHeight} onChange={e => setEditHeight(e.target.value)} className="w-full p-4 bg-white border-2 border-brand-gray-200 rounded-2xl font-black text-lg text-brand-gray-900 focus:border-brand-blue outline-none" placeholder="Altura (cm)" />
                                    </div>
                                )}
                            </div>

                            <div className="space-y-4">
                                <h5 className="text-[10px] font-black text-brand-gray-400 uppercase tracking-widest mb-2">Preferencias del Diario</h5>
                                {diaryOptions.map(opt => {
                                    const isSel = isEditing ? editDiaryPrefs.includes(opt.id as any) : diaryPreferences.includes(opt.id as any);
                                    return (
                                        <button 
                                            key={opt.id}
                                            disabled={!isEditing}
                                            onClick={() => setEditDiaryPrefs(prev => prev.includes(opt.id as any) ? prev.filter(x => x !== opt.id) : [...prev, opt.id as any])}
                                            className={`w-full flex items-center justify-between p-5 rounded-2xl border transition-all ${isSel ? 'border-brand-blue bg-blue-50/50' : 'border-brand-gray-100 bg-white opacity-60'}`}
                                        >
                                            <span className={`font-black uppercase text-xs tracking-widest ${isSel ? 'text-brand-blue' : 'text-brand-gray-600'}`}>{opt.label}</span>
                                            {isSel && <CheckCircleIcon className="w-6 h-6 text-brand-blue" />}
                                        </button>
                                    );
                                })}
                            </div>

                            <div className="mt-12 pt-8 border-t border-brand-gray-50 flex gap-4">
                                {isEditing ? (
                                    <>
                                        <button onClick={() => setIsEditing(false)} className="flex-1 py-5 bg-brand-gray-100 text-brand-gray-600 rounded-2xl font-black text-xs uppercase tracking-widest">Cancelar</button>
                                        <button onClick={handleSaveProfile} disabled={saveLoading} className="flex-[2] py-5 bg-brand-blue text-white rounded-2xl font-black text-xs uppercase tracking-widest shadow-soft">Guardar</button>
                                    </>
                                ) : (
                                    <button onClick={() => signOut()} className="w-full py-5 text-brand-red font-black text-xs uppercase tracking-widest border border-brand-soft-red bg-brand-soft-red rounded-2xl">Cerrar Sesión</button>
                                )}
                            </div>
                        </div>
                    </div>
                </div>
            )}

            {/* Metric Detail Modal (Gráfica Detallada) */}
            {selectedMetric && (
                <div className="fixed inset-0 z-50 flex items-center justify-center p-6 bg-brand-gray-900/80 backdrop-blur-md animate-fade-in">
                    <div className="bg-white w-full max-w-xl rounded-v-xl shadow-soft-lg overflow-hidden border border-brand-gray-100">
                        <div className="p-8">
                            <div className="flex justify-between items-start mb-8">
                                <div>
                                    <h3 className="text-3xl font-black text-brand-gray-900 tracking-tighter uppercase leading-none">{selectedMetric.label}</h3>
                                    <p className="text-[10px] font-black text-brand-blue uppercase tracking-widest mt-2">Seguimiento Médico Detallado</p>
                                </div>
                                <button onClick={() => setSelectedMetric(null)} className="text-brand-gray-500 bg-brand-gray-100 p-3 rounded-full hover:text-brand-red transition-all"><XMarkIcon className="w-6 h-6"/></button>
                            </div>

                            <DetailedHistoryChart 
                                data={historyData} 
                                color="#005A9C" 
                                metricKey={selectedMetric.key}
                                unit={selectedMetric.unit}
                                referenceRange={RECOMMENDED_RANGES[selectedMetric.key]} 
                            />

                            <div className="mt-8 grid grid-cols-2 gap-4">
                                <div className="bg-brand-gray-50 p-4 rounded-2xl border border-brand-gray-100">
                                    <span className="text-[9px] font-black text-brand-gray-400 uppercase tracking-widest block mb-1">Valor Actual</span>
                                    <span className="text-2xl font-black text-brand-gray-900">{healthData[selectedMetric.key] || '--'}<small className="text-xs ml-1 text-brand-gray-400">{selectedMetric.unit}</small></span>
                                </div>
                                <div className="bg-brand-gray-50 p-4 rounded-2xl border border-brand-gray-100">
                                    <span className="text-[9px] font-black text-brand-gray-400 uppercase tracking-widest block mb-1">Rango Óptimo</span>
                                    <span className="text-xl font-black text-brand-blue">
                                        {RECOMMENDED_RANGES[selectedMetric.key]?.min}-{RECOMMENDED_RANGES[selectedMetric.key]?.max}
                                        <small className="text-[10px] ml-1 text-brand-blue/60">{selectedMetric.unit}</small>
                                    </span>
                                </div>
                            </div>

                            {selectedMetric.key === 'weight' && (
                                <div className="mt-4 p-4 bg-blue-50/50 rounded-2xl border border-brand-blue/10">
                                    <p className="text-[10px] font-black text-brand-blue uppercase tracking-widest mb-1">Nota Nutricional (IMC)</p>
                                    <p className="text-xs font-bold text-brand-gray-600 leading-tight">Su rango saludable está calculado para una altura de {profile?.healthData.height}cm siguiendo el Índice de Masa Corporal (18.5 - 24.9).</p>
                                </div>
                            )}

                            <button onClick={() => setSelectedMetric(null)} className="w-full mt-10 bg-brand-gray-900 text-white font-black py-5 rounded-2xl text-xs uppercase tracking-widest shadow-soft active:scale-95 transition-all">Regresar al panel</button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

export default HomeScreen;

import React, { useState } from 'react';
import { useAuth } from '../contexts/AuthContext';
import { registerUserInDb } from '../services/firestore';
import type { UserProfile, HealthData } from '../types';
import { avatars } from '../components/Icons';

const diaryOptions = [
    { id: 'weight', label: 'Peso Corporal' },
    { id: 'systolicBP', label: 'Tensión Sistólica' },
    { id: 'diastolicBP', label: 'Tensión Diastólica' },
    { id: 'pulse', label: 'Pulso (LPM)' },
    { id: 'oxygenSaturation', label: 'Saturación Oxígeno' },
    { id: 'glucose', label: 'Azúcar en Sangre' },
    { id: 'falls', label: 'Control de Caídas' },
    { id: 'calfCircumference', label: 'Pantorrilla' },
    { id: 'abdominalCircumference', label: 'Abdomen' },
];

const LoginScreen: React.FC = () => {
  const { signIn, signUp } = useAuth();
  const [isRegistering, setIsRegistering] = useState(false); 
  const [step, setStep] = useState(0); 
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [infoMessage, setInfoMessage] = useState<string | null>(null);

  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [personalData, setPersonalData] = useState({ displayName: '', gender: 'male', height: '' });
  const [diaryFields, setDiaryFields] = useState<(keyof HealthData)[]>(['weight', 'systolicBP', 'diastolicBP', 'pulse', 'glucose']);
  const [legalData, setLegalData] = useState({ hasLegalConsent: false, dataProcessingConsent: false });
  const [avatarId, setAvatarId] = useState(0);

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);
    setLoading(true);
    try {
        await signIn(email, password); 
    } catch (err: any) {
        setError("Correo o contraseña no válidos.");
    } finally {
        setLoading(false);
    }
  };

  const inputClass = "w-full p-5 bg-white border-2 border-brand-gray-200 rounded-2xl text-lg font-black text-brand-gray-900 focus:border-brand-blue focus:ring-4 focus:ring-brand-blue/5 outline-none transition-all placeholder:text-brand-gray-400 shadow-sm";

  const renderStepContent = () => {
      switch(step) {
          case 0: return (
              <div className="space-y-6 animate-fade-in">
                  <h2 className="text-2xl font-black text-brand-gray-900 tracking-tighter uppercase">Datos de acceso</h2>
                  <input type="email" placeholder="Correo electrónico" className={inputClass} value={email} onChange={e => setEmail(e.target.value)} />
                  <input type="password" placeholder="Contraseña segura" className={inputClass} value={password} onChange={e => setPassword(e.target.value)} />
              </div>
          );
          case 1: return (
              <div className="space-y-6 animate-fade-in">
                  <h2 className="text-2xl font-black text-brand-gray-900 tracking-tighter uppercase">Sobre usted</h2>
                  <input type="text" placeholder="Su nombre" className={inputClass} value={personalData.displayName} onChange={e => setPersonalData({...personalData, displayName: e.target.value})} />
                  <input type="number" placeholder="Altura en cm" className={inputClass} value={personalData.height} onChange={e => setPersonalData({...personalData, height: e.target.value})} />
              </div>
          );
          case 2: return (
              <div className="space-y-3 max-h-[45vh] overflow-y-auto pr-2 animate-fade-in">
                  <h2 className="text-2xl font-black text-brand-gray-900 tracking-tighter uppercase">Mi Diario</h2>
                  {diaryOptions.map(opt => (
                      <button key={opt.id} onClick={() => setDiaryFields(prev => prev.includes(opt.id as any) ? prev.filter(x => x !== opt.id) : [...prev, opt.id as any])} className={`w-full text-left p-5 rounded-2xl border-2 transition-all ${diaryFields.includes(opt.id as any) ? 'border-brand-blue bg-blue-50/50' : 'border-brand-gray-100 bg-white'}`}>
                          <span className={`font-black uppercase text-xs tracking-widest ${diaryFields.includes(opt.id as any) ? 'text-brand-blue' : 'text-brand-gray-500'}`}>{opt.label}</span>
                      </button>
                  ))}
              </div>
          );
          case 3: return (
              <div className="space-y-6 animate-fade-in">
                  <h2 className="text-2xl font-black text-brand-gray-900 tracking-tighter uppercase">Privacidad</h2>
                  <div className="space-y-4">
                    <label className="flex items-start gap-4 p-5 rounded-2xl bg-brand-gray-50 border-2 border-brand-gray-100 cursor-pointer">
                        <input type="checkbox" checked={legalData.hasLegalConsent} onChange={e => setLegalData({...legalData, hasLegalConsent: e.target.checked})} className="mt-1 w-6 h-6 accent-brand-blue" />
                        <span className="text-sm font-black text-brand-gray-900 uppercase tracking-tighter">Acepto los términos de uso.</span>
                    </label>
                    <label className="flex items-start gap-4 p-5 rounded-2xl bg-brand-gray-50 border-2 border-brand-gray-100 cursor-pointer">
                        <input type="checkbox" checked={legalData.dataProcessingConsent} onChange={e => setLegalData({...legalData, dataProcessingConsent: e.target.checked})} className="mt-1 w-6 h-6 accent-brand-blue" />
                        <span className="text-sm font-black text-brand-gray-900 uppercase tracking-tighter">Autorizo el tratamiento de mis datos médicos.</span>
                    </label>
                  </div>
              </div>
          );
          case 4: return (
              <div className="grid grid-cols-3 gap-4 animate-fade-in">
                  <h2 className="col-span-3 text-2xl font-black text-brand-gray-900 tracking-tighter uppercase">Elija su avatar</h2>
                  {avatars.map((A, i) => (
                      <button key={i} onClick={() => setAvatarId(i)} className={`p-4 rounded-2xl flex justify-center border-4 transition-all ${avatarId === i ? 'border-brand-blue bg-blue-50 shadow-inner' : 'border-transparent bg-brand-gray-50'}`}><A className="w-12 h-12" /></button>
                  ))}
              </div>
          );
          default: return null;
      }
  };

  const handleNext = () => {
      if (step === 0 && (!email || password.length < 6)) { setError("Introduzca datos válidos."); return; }
      if (step === 1 && !personalData.displayName) { setError("Introduzca su nombre."); return; }
      if (step === 3 && (!legalData.hasLegalConsent || !legalData.dataProcessingConsent)) { setError("Debe aceptar los términos."); return; }
      setError(null);
      setStep(s => s + 1);
  };

  const handleRegister = async () => {
    setLoading(true);
    try {
        const res = await signUp(email, password);
        if (!res) { setInfoMessage("Revise su correo para confirmar su cuenta."); return; }
        await registerUserInDb(res.uid, {
            email, displayName: personalData.displayName, gender: 'male', nationality: 'Española', language: 'Español', emergencyContactName: '', emergencyContactPhone: '', hasLegalConsent: true, dataProcessingConsent: true, avatarId, diaryPreferences: diaryFields, healthData: { weight: null, falls: null, systolicBP: null, diastolicBP: null, pulse: null, oxygenSaturation: null, glucose: null, calfCircumference: null, abdominalCircumference: null, height: parseFloat(personalData.height) || 170 }, vigsScore: { score: 0, category: 'No frágil' }, alerts: []
        });
        setIsRegistering(false);
    } catch (e: any) { setError(e.message); }
    finally { setLoading(false); }
  };

  return (
    <div className="min-h-screen bg-brand-bg flex items-center justify-center p-6">
      <div className="bg-white p-10 sm:p-12 rounded-v-xl shadow-soft-lg w-full max-w-md border border-brand-gray-100">
        <div className="text-center mb-10">
            <h1 className="text-5xl font-black text-brand-blue tracking-tighter uppercase">Fisiosilver</h1>
            <p className="text-brand-gray-400 font-black text-[10px] uppercase tracking-[0.4em] mt-2">Salud Senior Inteligente</p>
        </div>

        {isRegistering ? (
            <div>
                <div className="flex gap-1 mb-8">
                    {[0,1,2,3,4].map(i => <div key={i} className={`h-1.5 flex-1 rounded-full transition-all duration-500 ${i <= step ? 'bg-brand-blue' : 'bg-brand-gray-100'}`}></div>)}
                </div>
                {renderStepContent()}
                {error && <p className="mt-6 text-brand-red text-center font-black text-xs bg-brand-soft-red p-4 rounded-2xl uppercase tracking-widest">{error}</p>}
                <div className="mt-10 flex gap-4">
                    {step > 0 && <button onClick={() => setStep(s => s - 1)} className="flex-1 py-5 bg-brand-gray-100 text-brand-gray-600 rounded-2xl font-black text-xs uppercase tracking-widest shadow-sm">Atrás</button>}
                    <button onClick={step === 4 ? handleRegister : handleNext} disabled={loading} className="flex-[2] py-5 bg-brand-blue text-white rounded-2xl font-black text-xs uppercase tracking-widest shadow-soft hover:shadow-soft-lg">{loading ? '...' : (step === 4 ? 'Finalizar' : 'Continuar')}</button>
                </div>
                <button onClick={() => setIsRegistering(false)} className="w-full mt-8 text-brand-gray-400 font-black text-[10px] uppercase tracking-[0.3em] text-center hover:text-brand-blue transition-colors">Ya tengo cuenta • Entrar</button>
            </div>
        ) : (
            <form onSubmit={handleLogin} className="space-y-6">
                <input type="email" placeholder="Correo electrónico" className={inputClass} value={email} onChange={e => setEmail(e.target.value)} required />
                <input type="password" placeholder="Contraseña" className={inputClass} value={password} onChange={e => setPassword(e.target.value)} required />
                {error && <p className="text-brand-red text-center font-black text-xs bg-brand-soft-red p-4 rounded-2xl uppercase tracking-widest">{error}</p>}
                <button type="submit" disabled={loading} className="w-full py-6 bg-brand-blue text-white rounded-v-large font-black text-sm uppercase tracking-widest shadow-soft active:scale-95 transition-all">{loading ? 'Entrando...' : 'Entrar ahora'}</button>
                <div className="pt-8 border-t border-brand-gray-50 mt-10">
                    <button type="button" onClick={() => { setIsRegistering(true); setStep(0); }} className="w-full py-5 border-2 border-brand-blue text-brand-blue rounded-v-large font-black text-[10px] uppercase tracking-[0.3em] hover:bg-brand-blue hover:text-white transition-all">Crear cuenta gratis</button>
                </div>
            </form>
        )}
      </div>
    </div>
  );
};

