    return (
        <div className="p-6 max-w-4xl mx-auto animate-fade-in pb-32">
            <header className="flex justify-between items-center mb-10 pt-4">
                <div>
                    <p className="text-brand-gray-500 font-black uppercase tracking-[0.2em] text-[10px] mb-1">Tu salud hoy</p>
                    <h1 className="text-4xl font-black text-brand-gray-900 tracking-tighter">Hola, <span className="text-brand-blue">{profile?.displayName?.split(' ')[0] || 'Usuario'}</span></h1>
                </div>
                <button onClick={() => { setIsProfileOpen(true); setIsEditing(false); }} className="bg-white p-1 rounded-full shadow-soft hover:shadow-soft-lg transition-all active:scale-95 border-2 border-brand-blue/20">
                    <AvatarComponent className="w-16 h-16" />
                </button>
            </header>

            <h2 className="text-[11px] font-black text-brand-gray-400 uppercase tracking-[0.3em] mb-4 ml-2">Índices de Salud Global</h2>
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6 mb-12">
                <IndexCard 
                    title="Fragilidad (VIGS)"
                    value={displayVigs.toFixed(2)}
                    percent={displayVigs * 100}
                    description="Nivel de dependencia y riesgo actual."
                    color={displayVigs > 0.37 ? "#D32F2F" : "#005A9C"}
                    category={vigsScore.category}
                    categoryClass={getVigsColorClass(vigsScore.category)}
                />
                <IndexCard 
                    title="Protección"
                    value={`${calculatedIndices.protection.toFixed(0)}%`}
                    percent={calculatedIndices.protection}
                    description="Grado de cobertura ante fragilidad."
                    color="#2E7D32"
                />
                <IndexCard 
                    title="Cardiovascular"
                    value={calculatedIndices.cardio > 20 ? calculatedIndices.cardio.toFixed(0) : "Normal"}
                    percent={calculatedIndices.cardio}
                    description="Riesgo cardíaco basado en TA."
                    color={calculatedIndices.cardio > 50 ? "#D32F2F" : "#005A9C"}
                />
                <IndexCard 
                    title="Riesgo de Caídas"
                    value={calculatedIndices.falls > 0 ? "Moderado" : "Bajo"}
                    percent={calculatedIndices.falls}
                    description="Posibilidad de incidentes motrices."
                    color={calculatedIndices.falls > 50 ? "#D32F2F" : "#005A9C"}
                />
                <IndexCard 
                    title="Hospitalización"
                    value={calculatedIndices.hospital > 40 ? "Moderado" : "Bajo"}
                    percent={calculatedIndices.hospital}
                    description="Riesgo de reingreso médico."
                    color={calculatedIndices.hospital > 60 ? "#D32F2F" : "#005A9C"}
                />
