    case 'Fragilidad moderada': return 'text-brand-yellow bg-brand-soft-yellow';
    case 'Fragilidad severa': return 'text-brand-red bg-brand-soft-red';
    default: return 'text-brand-gray-500 bg-brand-gray-100';
  }
};

const getProgressBarColor = (percent: number, inverted: boolean = false): string => {
    if (inverted) {
        if (percent > 70) return 'bg-brand-green';
        if (percent > 40) return 'bg-brand-yellow';
        return 'bg-brand-red';
    }
    if (percent < 30) return 'bg-brand-green';
    if (percent < 60) return 'bg-brand-yellow';
    return 'bg-brand-red';
};

interface ChartDataPoint { date: Date; value: number; }

const IndexCard: React.FC<{ 
    title: string; 
    value: string | number; 
    percent: number; 
    description: string;
    invertedColor?: boolean;
    category?: string;
    categoryClass?: string;
}> = ({ title, value, percent, description, invertedColor = false, category, categoryClass }) => (
    <div className="bg-white p-8 rounded-[2.5rem] shadow-soft border border-brand-gray-100 flex flex-col justify-between min-h-[220px] animate-slide-up group hover:shadow-soft-lg transition-all duration-300">
        <div>
            <div className="flex justify-between items-start mb-4">
                <h2 className="text-[12px] font-black text-brand-gray-400 uppercase tracking-[0.2em]">{title}</h2>
                {category && (
                    <div className={`px-4 py-1.5 rounded-full font-black text-[10px] uppercase tracking-wider ${categoryClass}`}>
                        {category}
                    </div>
                )}
            </div>
            <div className="flex items-baseline gap-2 mb-6">
                <span className="text-6xl font-black text-brand-gray-900 tracking-tighter">{value}</span>
            </div>
        </div>
        <div className="space-y-4">
            <div className="w-full h-4 bg-brand-gray-100 rounded-full overflow-hidden shadow-inner">
                <div 
                    className={`h-full transition-all duration-1000 ease-out ${getProgressBarColor(percent, invertedColor)}`} 
                    style={{ width: `${Math.max(5, percent)}%` }}
                ></div>
            </div>
            <p className="text-brand-gray-700 text-sm font-bold leading-snug">{description}</p>
        </div>
    </div>
);

const DetailedHistoryChart: React.FC<{ 
    data: ChartDataPoint[]; 
    color: string; 
    metricKey: string;
    unit: string;
    referenceRange?: { min: number; max: number };
}> = ({ data, color, metricKey, unit, referenceRange }) => {
    if (data.length === 0) return <div className="h-64 flex flex-col items-center justify-center bg-brand-gray-50 rounded-3xl"><p className="text-brand-gray-400 text-sm font-black uppercase tracking-wider">Sin historial registrado</p></div>;

    const width = 400; const height = 200; const paddingX = 40; const paddingY = 40;
    const values = data.map(d => d.value);

    let minVal = Math.min(...values);
    let maxVal = Math.max(...values);

    if (referenceRange) {
        minVal = Math.min(minVal, referenceRange.min);
        maxVal = Math.max(maxVal, referenceRange.max);
    }

    const rangeBuffer = (maxVal - minVal) * 0.3 || 10;
    minVal = Math.max(0, minVal - rangeBuffer);
    maxVal = maxVal + rangeBuffer;
    const range = maxVal - minVal || 1;

    const getX = (index: number) => paddingX + (index / Math.max(1, data.length - 1)) * (width - 2 * paddingX);
    const getY = (val: number) => height - paddingY - ((val - minVal) / range) * (height - 2 * paddingY);

    const pathD = data.map((d, i) => `${i === 0 ? 'M' : 'L'} ${getX(i)} ${getY(d.value)}`).join(' ');

    return (
        <div className="w-full bg-white p-6 rounded-[2rem] border border-brand-gray-100 shadow-soft">
            <svg viewBox={`0 0 ${width} ${height}`} className="w-full h-auto overflow-visible">
                {referenceRange && (
                    <rect 
                        x={paddingX} 
                        y={getY(referenceRange.max)} 
                        width={width - 2 * paddingX} 
                        height={Math.max(2, Math.abs(getY(referenceRange.min) - getY(referenceRange.max)))} 
                        fill="rgba(46, 125, 50, 0.15)" 
                        rx="8" 
                    />
                )}

                {[0, 0.5, 1].map(p => (
                    <line key={p} x1={paddingX} y1={paddingY + p * (height - 2 * paddingY)} x2={width - paddingX} y2={paddingY + p * (height - 2 * paddingY)} stroke="#F3F4F6" strokeWidth="1.5" strokeDasharray="6 6" />
                ))}

                <path d={pathD} fill="none" stroke={color} strokeWidth="6" strokeLinecap="round" strokeLinejoin="round" className="drop-shadow-md" />

                {data.map((d, i) => (
                    <g key={i} className="group cursor-pointer">
                        <circle cx={getX(i)} cy={getY(d.value)} r="8" fill="white" stroke={color} strokeWidth="5" />
                        <text x={getX(i)} y={getY(d.value) - 20} textAnchor="middle" className="text-[12px] font-black fill-brand-gray-900 opacity-0 group-hover:opacity-100 transition-opacity bg-white px-1">{d.value}</text>
                    </g>
                ))}

                {data.length > 0 && (
                    <>
                        <text x={getX(0)} y={height - 5} textAnchor="start" className="text-[11px] font-black fill-brand-gray-400 uppercase tracking-tighter">
                            {data[0].date.toLocaleDateString('es-ES', { day: 'numeric', month: 'short' })}
                        </text>
                        {data.length > 1 && (
                            <text x={getX(data.length - 1)} y={height - 5} textAnchor="end" className="text-[11px] font-black fill-brand-gray-400 uppercase tracking-tighter">
                                {data[data.length - 1].date.toLocaleDateString('es-ES', { day: 'numeric', month: 'short' })}
                            </text>
                        )}
                    </>
                )}
            </svg>
        </div>
    );
};

