const getVigsColorClass = (category: VigsCategory): string => {
  switch (category) {
    case 'No frágil': return 'text-brand-green bg-brand-soft-green';
    case 'Fragilidad leve': return 'text-emerald-600 bg-emerald-50';
    case 'Fragilidad moderada': return 'text-brand-yellow bg-brand-soft-yellow';
    case 'Fragilidad severa': return 'text-brand-red bg-brand-soft-red';
    default: return 'text-brand-gray-500 bg-brand-gray-100';
  }
};

const getProgressBarColor = (percent: number, inverted: boolean = false): string => {
    if (inverted) {
        if (percent > 70) return 'bg-brand-green';
        if (percent > 40) return 'bg-brand-yellow';
        return 'bg-brand-red';
    }
    if (percent < 30) return 'bg-brand-green';
    if (percent < 60) return 'bg-brand-yellow';
    return 'bg-brand-red';
};

interface ChartDataPoint { date: Date; value: number; }

const MiniSparkline: React.FC<{ data: number[], color: string }> = ({ data, color }) => {
    if (data.length < 2) return <div className="h-6" />;
    const width = 100;
    const height = 30;
    const min = Math.min(...data);
    const max = Math.max(...data);
    const range = max - min || 1;
    const points = data.map((d, i) => ({
        x: (i / (data.length - 1)) * width,
        y: height - ((d - min) / range) * height
    }));
    const d = points.map((p, i) => `${i === 0 ? 'M' : 'L'} ${p.x} ${p.y}`).join(' ');
    return (
        <svg width="100%" height="30" viewBox={`0 0 ${width} ${height}`} className="mt-2 opacity-50">
            <path d={d} fill="none" stroke={color} strokeWidth="3" strokeLinecap="round" strokeLinejoin="round" />
        </svg>
    );
};

