const DetailedHistoryChart: React.FC<{ 
    data: ChartDataPoint[]; 
    color: string; 
    metricKey: string;
    unit: string;
    referenceRange?: { min: number; max: number };
}> = ({ data, color, metricKey, unit, referenceRange }) => {
    if (data.length === 0) return <div className="h-64 flex flex-col items-center justify-center bg-brand-gray-50 rounded-3xl"><p className="text-brand-gray-400 text-sm font-black uppercase tracking-wider">Sin historial registrado</p></div>;

    const width = 400; const height = 200; const paddingX = 40; const paddingY = 40;
    const values = data.map(d => d.value);

    let minVal = Math.min(...values);
    let maxVal = Math.max(...values);

    if (referenceRange) {
        minVal = Math.min(minVal, referenceRange.min);
        maxVal = Math.max(maxVal, referenceRange.max);
    }

    const rangeBuffer = (maxVal - minVal) * 0.3 || 10;
    minVal = Math.max(0, minVal - rangeBuffer);
    maxVal = maxVal + rangeBuffer;
    const range = maxVal - minVal || 1;

    const getX = (index: number) => paddingX + (index / Math.max(1, data.length - 1)) * (width - 2 * paddingX);
    const getY = (val: number) => height - paddingY - ((val - minVal) / range) * (height - 2 * paddingY);

    const pathD = data.map((d, i) => `${i === 0 ? 'M' : 'L'} ${getX(i)} ${getY(d.value)}`).join(' ');

    return (
        <div className="w-full bg-white p-8 rounded-[2.5rem] border border-brand-gray-100 shadow-soft">
            <svg viewBox={`0 0 ${width} ${height}`} className="w-full h-auto overflow-visible">
                {referenceRange && (
                    <rect 
                        x={paddingX} 
                        y={getY(referenceRange.max)} 
                        width={width - 2 * paddingX} 
                        height={Math.max(2, Math.abs(getY(referenceRange.min) - getY(referenceRange.max)))} 
                        fill="rgba(46, 125, 50, 0.2)" 
                        rx="10" 
                    />
                )}

                {[0, 0.5, 1].map(p => (
                    <line key={p} x1={paddingX} y1={paddingY + p * (height - 2 * paddingY)} x2={width - paddingX} y2={paddingY + p * (height - 2 * paddingY)} stroke="#F3F4F6" strokeWidth="1.5" strokeDasharray="6 6" />
                ))}

                <path d={pathD} fill="none" stroke={color} strokeWidth="6" strokeLinecap="round" strokeLinejoin="round" className="drop-shadow-md" />

                {data.map((d, i) => (
                    <g key={i} className="group cursor-pointer">
                        <circle cx={getX(i)} cy={getY(d.value)} r="8" fill="white" stroke={color} strokeWidth="5" />
                        <text x={getX(i)} y={getY(d.value) - 20} textAnchor="middle" className="text-[12px] font-black fill-brand-gray-900 opacity-0 group-hover:opacity-100 transition-opacity bg-white px-1">{d.value}</text>
                    </g>
                ))}

                {data.length > 0 && (
                    <>
                        <text x={getX(0)} y={height - 5} textAnchor="start" className="text-[11px] font-black fill-brand-gray-400 uppercase tracking-tighter">
                            {data[0].date.toLocaleDateString('es-ES', { day: 'numeric', month: 'short' })}
                        </text>
                        {data.length > 1 && (
                            <text x={getX(data.length - 1)} y={height - 5} textAnchor="end" className="text-[11px] font-black fill-brand-gray-400 uppercase tracking-tighter">
                                {data[data.length - 1].date.toLocaleDateString('es-ES', { day: 'numeric', month: 'short' })}
                            </text>
                        )}
                    </>
                )}
            </svg>
        </div>
    );
};

const HomeScreen: React.FC = () => {
    const { user, signOut } = useAuth();
    const { healthData, setHealthData, setDiaryPreferences, diaryPreferences, setVigsScore, vigsScore } = useContext(AppContext)!;
    const [profile, setProfile] = useState<UserProfile | null>(null);
    const [isProfileOpen, setIsProfileOpen] = useState(false);
    const [isEditing, setIsEditing] = useState(false);
    const [selectedMetric, setSelectedMetric] = useState<{key: keyof HealthData, label: string, unit: string} | null>(null);
    const [historyData, setHistoryData] = useState<ChartDataPoint[]>([]);
    const [fullHistory, setFullHistory] = useState<Record<string, number[]>>({});
    const [isLoading, setIsLoading] = useState(true);
    const [saveLoading, setSaveLoading] = useState(false);

    const [editName, setEditName] = useState("");
    const [editHeight, setEditHeight] = useState("");
    const [editDiaryPrefs, setEditDiaryPrefs] = useState<(keyof HealthData)[]>([]);

    const heightInMeters = (profile?.healthData.height || 170) / 100;
    const imcRange = { min: Math.round(18.5 * heightInMeters ** 2), max: Math.round(24.9 * heightInMeters ** 2) };

    const RECOMMENDED_RANGES: Record<string, { min: number; max: number }> = useMemo(() => ({
        systolicBP: { min: 110, max: 140 },
        diastolicBP: { min: 60, max: 90 },
        pulse: { min: 60, max: 100 },
        oxygenSaturation: { min: 95, max: 100 },
        glucose: { min: 70, max: 110 },
        calfCircumference: { min: 31, max: 45 },
        abdominalCircumference: { min: 70, max: 102 },
        weight: imcRange,
        falls: { min: 0, max: 0 }
    }), [imcRange]);

    const calculatedIndices = useMemo(() => {
        const vigs = vigsScore.index || (vigsScore.score / 25);
        const sys = healthData.systolicBP || 120;
        const dia = healthData.diastolicBP || 80;
        const falls = healthData.falls || 0;

        const prot = Math.max(0, Math.min(100, (1 - vigs) * 100));
        const cvRisk = Math.min(100, ((sys - 120) / 60 + (dia - 80) / 40) * 50);
        const fallRisk = Math.min(100, falls * 25);
        const hospRisk = Math.min(100, vigs * 100);

        return {
            protection: prot,
            cardio: cvRisk,
            falls: fallRisk,
            hospital: hospRisk
        };
    }, [vigsScore, healthData]);

    const loadProfile = async () => {
        if (!user) return;
        setIsLoading(true);
        try {
            const data = await getUserProfile(user.uid);
            if (data) {
                setProfile(data);
                setEditName(data.displayName);
                setEditHeight(data.healthData.height?.toString() || "");
                setEditDiaryPrefs(data.diaryPreferences);
                setHealthData(data.healthData);
                setDiaryPreferences(data.diaryPreferences);
                setVigsScore(data.vigsScore);
            }

            const logs = await getDailyHistory(user.uid);
            const historyMap: Record<string, number[]> = {};
            diaryOptions.forEach(opt => {
                historyMap[opt.id] = logs
                    .map(l => l[opt.id as keyof HealthData] as number | null)
                    .filter(v => v !== null)
                    .reverse() as number[];
            });
            setFullHistory(historyMap);

        } catch (e) { console.error(e); }
        finally { setIsLoading(false); }
    };

    useEffect(() => { loadProfile(); }, [user]);

    const handleMetricClick = async (key: keyof HealthData, label: string, unit: string) => {
        if (!user) return;
        setSelectedMetric({ key, label, unit });
        try {
            const logs = await getDailyHistory(user.uid);
            const chartData = logs
                .map(l => ({ date: l.createdAt, value: l[key] as number | null }))
                .filter(d => d.value !== null)
                .sort((a, b) => a.date.getTime() - b.date.getTime()) as ChartDataPoint[];
            setHistoryData(chartData);
        } catch (e) { console.error(e); }
    };

    const handleSaveProfile = async () => {
        if (!user) return;
        setSaveLoading(true);
        try {
            const updates: Partial<UserProfile> = {
                displayName: editName,
                diaryPreferences: editDiaryPrefs,
                healthData: { ...healthData, height: editHeight ? parseFloat(editHeight) : null }
            };
            await updateUserProfile(user.uid, updates);
            await loadProfile(); 
            setIsEditing(false);
        } catch (e) { alert("Error al actualizar."); }
        finally { setSaveLoading(false); }
    };

    const AvatarComponent = profile ? avatars[profile.avatarId] || avatars[0] : avatars[0];
    const displayVigs = parseFloat(vigsScore.index !== undefined ? vigsScore.index.toFixed(2) : (vigsScore.score / 25.0).toFixed(2));

    if (isLoading) return <div className="flex h-screen items-center justify-center bg-brand-bg"><div className="animate-spin rounded-full h-10 w-10 border-b-2 border-brand-blue"></div></div>;

    return (
        <div className="p-8 max-w-6xl mx-auto animate-fade-in pb-32">
            <header className="flex justify-between items-center mb-16 pt-8">
                <div>
                    <p className="text-brand-gray-500 font-black uppercase tracking-[0.5em] text-[12px] mb-3">Monitor de Bienestar Fisiosilver</p>
                    <h1 className="text-6xl font-black text-brand-gray-900 tracking-tighter">Buenos días, <span className="text-brand-blue">{profile?.displayName?.split(' ')[0] || 'Usuario'}</span></h1>
                </div>
                <button onClick={() => { setIsProfileOpen(true); setIsEditing(false); }} className="bg-white p-2 rounded-full shadow-soft hover:shadow-soft-lg transition-all active:scale-95 border-[6px] border-brand-blue/5">
                    <AvatarComponent className="w-24 h-24" />
                </button>
            </header>

            <h2 className="text-[14px] font-black text-brand-gray-400 uppercase tracking-[0.4em] mb-8 ml-4">Índices de Salud General</h2>
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-10 mb-24">
                <IndexCard 
                    title="Fragilidad (VIGS)"
                    value={displayVigs.toFixed(2)}
                    percent={displayVigs * 100}
                    description="Evaluación de su grado de independencia física y motriz."
                    category={vigsScore.category}
                    categoryClass={getVigsColorClass(vigsScore.category)}
                />
                <IndexCard 
                    title="Nivel de Protección"
                    value={`${calculatedIndices.protection.toFixed(0)}%`}
                    percent={calculatedIndices.protection}
                    invertedColor={true}
                    description="Grado de cobertura ante fragilidad severa."
                />
                <IndexCard 
                    title="Riesgo Cardiovascular"
                    value={calculatedIndices.cardio > 20 ? calculatedIndices.cardio.toFixed(0) : "OK"}
                    percent={calculatedIndices.cardio}
                    description="Riesgo estimado basado en sus mediciones de tensión."
                />
            </div>

            <h2 className="text-[14px] font-black text-brand-gray-400 uppercase tracking-[0.4em] mb-8 ml-4">Mis Constantes Médicas</h2>
            <div className="grid grid-cols-2 sm:grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-8">
                {diaryOptions.filter(opt => diaryPreferences.includes(opt.id as any)).map((opt, i) => {
                    const value = healthData[opt.id as keyof HealthData];
                    const unit = opt.label.includes('(') ? opt.label.split('(')[1].replace(')', '') : '';
                    const label = opt.label.split('(')[0].trim();
                    const history = fullHistory[opt.id] || [];

                    return (
                        <button 
                            key={opt.id} 
                            onClick={() => handleMetricClick(opt.id as any, label, unit)}
                            className="bg-white p-8 rounded-[2.5rem] shadow-soft border border-brand-gray-50 text-left hover:shadow-soft-lg transition-all active:scale-95 group animate-slide-up flex flex-col justify-between h-full"
                            style={{ animationDelay: `${i * 0.05}s` }}
                        >
                            <div>
                                <div className="w-14 h-14 bg-brand-lightblue rounded-[1.25rem] flex items-center justify-center text-brand-blue mb-8 group-hover:bg-brand-blue group-hover:text-white transition-colors">
                                    <CheckCircleIcon className="w-7 h-7" />
                                </div>
                                <h3 className="text-[11px] font-black text-brand-gray-400 uppercase tracking-widest mb-3 leading-tight">{label}</h3>
                                <div className="flex items-baseline gap-1">
                                    <span className="text-4xl font-black text-brand-gray-900 leading-none">{value ?? '--'}</span>
                                    <span className="text-[11px] font-bold text-brand-gray-400 uppercase">{unit}</span>
                                </div>
                            </div>
                            <MiniSparkline data={history} color="#005A9C" />
                        </button>
                    );
                })}
            </div>

            {isProfileOpen && (
                <div className="fixed inset-0 z-50 flex items-end sm:items-center justify-center p-0 sm:p-6 bg-brand-gray-900/60 backdrop-blur-sm animate-fade-in">
                    <div className="bg-white w-full max-w-xl h-[90vh] sm:h-auto sm:max-h-[85vh] overflow-y-auto rounded-t-[3rem] sm:rounded-[3rem] shadow-soft-lg border-t border-brand-gray-100">
                        <div className="px-10 py-10 sticky top-0 bg-white/95 backdrop-blur flex justify-between items-center border-b border-brand-gray-50 z-20">
                            <h3 className="text-3xl font-black text-brand-gray-900 uppercase tracking-tighter">Mi Perfil</h3>
                            <button onClick={() => setIsProfileOpen(false)} className="bg-brand-gray-100 p-4 rounded-full text-brand-gray-600 hover:text-brand-red transition-all"><XMarkIcon className="w-8 h-8"/></button>
                        </div>

                        <div className="p-12 pb-20">
                            <div className="flex flex-col items-center mb-12">
                                <div className="bg-brand-lightblue p-3 rounded-full ring-8 ring-brand-lightblue/30 mb-10">
                                    <AvatarComponent className="w-40 h-40" />
                                </div>
                                {!isEditing ? (
                                    <div className="text-center">
                                        <h4 className="text-4xl font-black text-brand-gray-900 mb-3">{profile?.displayName}</h4>
                                        <p className="text-xl font-bold text-brand-gray-500 mb-10">{profile?.email}</p>
                                        <button onClick={() => setIsEditing(true)} className="px-12 py-6 bg-brand-lightblue text-brand-blue rounded-3xl text-sm font-black uppercase tracking-widest hover:bg-brand-blue hover:text-white transition-all shadow-sm flex items-center gap-4 mx-auto"><PencilSquareIcon className="w-6 h-6" /> Editar Mis Datos</button>
                                    </div>
                                ) : (
                                    <div className="w-full space-y-8">
                                        <input type="text" value={editName} onChange={e => setEditName(e.target.value)} className="w-full p-8 bg-white border-2 border-brand-gray-200 rounded-[2rem] font-black text-2xl text-brand-gray-900 focus:border-brand-blue outline-none shadow-sm" placeholder="Su nombre completo" />
                                        <input type="number" value={editHeight} onChange={e => setEditHeight(e.target.value)} className="w-full p-8 bg-white border-2 border-brand-gray-200 rounded-[2rem] font-black text-2xl text-brand-gray-900 focus:border-brand-blue outline-none shadow-sm" placeholder="Altura en centímetros" />
                                    </div>
                                )}
                            </div>

                            <div className="space-y-4">
                                <h5 className="text-[14px] font-black text-brand-gray-400 uppercase tracking-widest mb-6 ml-3">¿Qué deseo anotar en mi diario?</h5>
                                {diaryOptions.map(opt => {
                                    const isSel = isEditing ? editDiaryPrefs.includes(opt.id as any) : diaryPreferences.includes(opt.id as any);
                                    return (
                                        <button 
                                            key={opt.id}
                                            disabled={!isEditing}
                                            onClick={() => setEditDiaryPrefs(prev => prev.includes(opt.id as any) ? prev.filter(x => x !== opt.id) : [...prev, opt.id as any])}
                                            className={`w-full flex items-center justify-between p-8 rounded-[2rem] border-2 transition-all ${isSel ? 'border-brand-blue bg-blue-50/50' : 'border-brand-gray-100 bg-white opacity-60'}`}
                                        >
                                            <span className={`font-black uppercase text-[14px] tracking-widest ${isSel ? 'text-brand-blue' : 'text-brand-gray-900'}`}>{opt.label}</span>
                                            {isSel && <CheckCircleIcon className="w-8 h-8 text-brand-blue" />}
                                        </button>
                                    );
                                })}
                            </div>

                            <div className="mt-20 pt-12 border-t border-brand-gray-50 flex gap-8">
                                {isEditing ? (
                                    <>
                                        <button onClick={() => setIsEditing(false)} className="flex-1 py-8 bg-brand-gray-100 text-brand-gray-900 rounded-[2rem] font-black text-sm uppercase tracking-widest">Cancelar</button>
                                        <button onClick={handleSaveProfile} disabled={saveLoading} className="flex-[2] py-8 bg-brand-blue text-white rounded-[2rem] font-black text-sm uppercase tracking-widest shadow-soft">Guardar Todo</button>
                                    </>
                                ) : (
                                    <button onClick={() => signOut()} className="w-full py-8 text-brand-red font-black text-sm uppercase tracking-widest border-2 border-brand-soft-red bg-brand-soft-red rounded-[2rem]">Salir de la Cuenta</button>
                                )}
                            </div>
                        </div>
                    </div>
                </div>
            )}

            {selectedMetric && (
                <div className="fixed inset-0 z-50 flex items-center justify-center p-6 bg-brand-gray-900/85 backdrop-blur-md animate-fade-in">
                    <div className="bg-white w-full max-w-5xl rounded-[3.5rem] shadow-soft-lg overflow-hidden border border-brand-gray-100 flex flex-col max-h-[94vh]">
                        <div className="p-12 border-b border-brand-gray-50 shrink-0">
                            <div className="flex justify-between items-start">
                                <div>
                                    <h3 className="text-5xl font-black text-brand-gray-900 tracking-tighter uppercase leading-none">{selectedMetric.label}</h3>
                                    <p className="text-lg font-black text-brand-blue uppercase tracking-widest mt-6">Evolución Médica Personalizada</p>
                                </div>
                                <button onClick={() => setSelectedMetric(null)} className="text-brand-gray-500 bg-brand-gray-100 p-5 rounded-full hover:text-brand-red transition-all shadow-sm"><XMarkIcon className="w-10 h-10"/></button>
                            </div>
                        </div>

                        <div className="p-12 overflow-y-auto space-y-20">
                            <DetailedHistoryChart 
                                data={historyData} 
                                color="#005A9C" 
                                metricKey={selectedMetric.key}
                                unit={selectedMetric.unit}
                                referenceRange={RECOMMENDED_RANGES[selectedMetric.key]} 
                            />

                            <div>
                                <h4 className="text-[16px] font-black text-brand-gray-400 uppercase tracking-[0.5em] mb-10 ml-4">Historial de Mediciones</h4>
                                <div className="space-y-6">
                                    {historyData.slice().reverse().map((record, index) => (
                                        <div key={index} className="bg-brand-gray-50 p-10 rounded-[2.5rem] border-2 border-transparent hover:border-brand-blue/30 hover:bg-white flex justify-between items-center transition-all duration-300 shadow-sm group">
                                            <div>
                                                <p className="text-[12px] font-black text-brand-gray-400 uppercase tracking-[0.3em] group-hover:text-brand-blue transition-colors">{record.date.toLocaleDateString('es-ES', { day: 'numeric', month: 'long', year: 'numeric' })}</p>
                                                <p className="text-lg font-bold text-brand-gray-500 mt-2 uppercase">{record.date.toLocaleTimeString('es-ES', { hour: '2-digit', minute: '2-digit' })}</p>
                                            </div>
                                            <div className="text-right">
                                                <span className="text-5xl font-black text-brand-gray-900 tracking-tighter">{record.value}</span>
                                                <span className="text-sm font-black text-brand-gray-400 uppercase ml-3 tracking-widest">{selectedMetric.unit}</span>
                                            </div>
                                        </div>
                                    ))}
                                    {historyData.length === 0 && (
                                        <div className="text-center py-24 bg-brand-gray-50 rounded-[3rem] border-2 border-dashed border-brand-gray-200">
                                            <p className="text-brand-gray-400 font-black uppercase tracking-widest text-lg">No hay registros previos para mostrar.</p>
                                        </div>
                                    )}
                                </div>
                            </div>
                        </div>

                        <div className="p-12 bg-brand-gray-50 border-t border-brand-gray-100 shrink-0">
                            <button onClick={() => setSelectedMetric(null)} className="w-full bg-brand-gray-900 text-white font-black py-8 rounded-[2.5rem] text-sm uppercase tracking-widest shadow-soft active:scale-95 transition-all">Regresar al Inicio</button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

