import { GoogleGenAI, Type } from "@google/genai";
import type { ClinicalAnalysisResult, NutritionalAnalysisResult, HealthData, VigsScore } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const fileToGenerativePart = async (file: File) => {
  const base64EncodedDataPromise = new Promise<string>((resolve) => {
    const reader = new FileReader();
    reader.onloadend = () => resolve((reader.result as string).split(',')[1]);
    reader.readAsDataURL(file);
  });
  return {
    inlineData: { data: await base64EncodedDataPromise, mimeType: file.type },
  };
};

export const analyzeClinicalReport = async (file: File): Promise<ClinicalAnalysisResult> => {
  try {
    const filePart = await fileToGenerativePart(file);
    const prompt = `
      Eres un asistente médico experto en análisis de laboratorio clínico y geriatría. 
      Extrae los biomarcadores con precisión.
      Si el valor NO aparece, escribe "No encontrado".
      IMPORTANTE: Devuelve un objeto JSON puro.
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: { parts: [filePart, { text: prompt }] },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            summary: { type: Type.STRING },
            biomarkers: {
              type: Type.OBJECT,
              properties: {
                hemoglobin: { type: Type.STRING },
                albumin: { type: Type.STRING },
                vitaminD: { type: Type.STRING },
                glucoseFasting: { type: Type.STRING },
                egfr: { type: Type.STRING },
                sodium: { type: Type.STRING },
                crp: { type: Type.STRING },
                vitaminB12: { type: Type.STRING },
                tsh: { type: Type.STRING },
                creatinine: { type: Type.STRING }
              },
              required: ["hemoglobin", "albumin", "vitaminD", "glucoseFasting", "egfr", "sodium", "crp", "vitaminB12", "tsh", "creatinine"]
            },
            recommendations: {
              type: Type.ARRAY,
              items: { type: Type.STRING }
            }
          },
          required: ["summary", "biomarkers", "recommendations"]
        }
      }
    });
    return JSON.parse(response.text || '{}');
  } catch (error) {
    throw new Error("No se pudo procesar el informe.");
  }
};

export const analyzeFoodPhoto = async (file: File): Promise<NutritionalAnalysisResult> => {
    try {
        const imagePart = await fileToGenerativePart(file);
        const prompt = `
          Eres un nutricionista geriátrico experto, extremadamente cálido, motivador y alentador.
          Analiza esta foto de comida.

          REGLA CRÍTICA PARA 'portions': No seas técnico ni frío. Tu objetivo es MOTIVAR al paciente. 
          Escribe un comentario corto (2-3 frases) que destaque lo positivo del plato.
          Ejemplo: "¡Qué maravilla de plato! Ese aporte de proteínas es justo lo que tus músculos necesitan para mantenerte fuerte y con energía. ¡Sigue así, estás cuidándote de maravilla!".
          Usa un lenguaje que genere orgullo en el usuario por su buena elección.

          Estima calorías y nutrientes de forma aproximada.
        `;

        const response = await ai.models.generateContent({
            model: 'gemini-3-pro-preview',
            contents: { parts: [imagePart, { text: prompt }] },
            config: {
              responseMimeType: "application/json",
              responseSchema: {
                type: Type.OBJECT,
                properties: {
                  calories: { type: Type.STRING },
                  macros: {
                    type: Type.OBJECT,
                    properties: {
                      protein: { type: Type.STRING },
                      carbs: { type: Type.STRING },
                      fatsTotal: { type: Type.STRING },
                      fatsSaturated: { type: Type.STRING },
                      fatsUnsaturated: { type: Type.STRING },
                      fatsTrans: { type: Type.STRING },
                      fiber: { type: Type.STRING }
                    },
                    required: ["protein", "carbs", "fatsTotal", "fatsSaturated", "fatsUnsaturated", "fatsTrans", "fiber"]
                  },
                  micros: {
                      type: Type.OBJECT,
                      properties: {
                          calcium: { type: Type.STRING },
                          vitaminD: { type: Type.STRING },
                          vitaminB12: { type: Type.STRING },
                          iron: { type: Type.STRING },
                          sodium: { type: Type.STRING },
                          potassium: { type: Type.STRING }
                      },
                      required: ["calcium", "vitaminD", "vitaminB12", "iron", "sodium", "potassium"]
                  },
                  portions: { type: Type.STRING, description: "Comentario motivador y entusiasta sobre el plato." },
                  suggestions: {
                    type: Type.ARRAY,
                    items: { type: Type.STRING }
                  }
                },
                required: ["calories", "macros", "micros", "portions", "suggestions"]
              }
            }
        });
        return JSON.parse(response.text || '{}');
    } catch (error) {
        throw new Error("Error al analizar la fotografía nutricional.");
    }
};

export const generateHealthRecommendations = async (healthData: HealthData, vigsScore: VigsScore): Promise<{ title: string; justification: string; }[]> => {
  try {
    const prompt = `Genera 2 recomendaciones de salud para un paciente senior. JSON con clave "recommendations".`;
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: { responseMimeType: "application/json" }
    });
    return JSON.parse(response.text || '{"recommendations": []}').recommendations;
  } catch (error) {
    return [];
  }
};

