const getVigsColorClass = (category: VigsCategory): string => {
  switch (category) {
    case 'No frágil': return 'text-brand-green bg-brand-soft-green';
    case 'Fragilidad leve': return 'text-emerald-600 bg-emerald-50';
    case 'Fragilidad moderada': return 'text-brand-yellow bg-brand-soft-yellow';
    case 'Fragilidad severa': return 'text-brand-red bg-brand-soft-red';
    default: return 'text-brand-gray-500 bg-brand-gray-100';
  }
};

const getProgressBarColor = (percent: number, inverted: boolean = false): string => {
    if (inverted) {
        if (percent > 70) return 'bg-brand-green';
        if (percent > 40) return 'bg-brand-yellow';
        return 'bg-brand-red';
    }
    if (percent < 30) return 'bg-brand-green';
    if (percent < 60) return 'bg-brand-yellow';
    return 'bg-brand-red';
};

interface ChartDataPoint { date: Date; value: number; }

const MiniSparkline: React.FC<{ data: number[], color: string }> = ({ data, color }) => {
    if (data.length < 2) return <div className="h-4" />;
    const width = 100;
    const height = 24;
    const min = Math.min(...data);
    const max = Math.max(...data);
    const range = max - min || 1;
    const points = data.map((d, i) => ({
        x: (i / (data.length - 1)) * width,
        y: height - ((d - min) / range) * height
    }));
    const d = points.map((p, i) => `${i === 0 ? 'M' : 'L'} ${p.x} ${p.y}`).join(' ');
    return (
        <svg width="100%" height="24" viewBox={`0 0 ${width} ${height}`} className="mt-2 opacity-40">
            <path d={d} fill="none" stroke={color} strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round" />
        </svg>
    );
};

// Componente para el efecto de revelación al hacer scroll
const ScrollReveal: React.FC<{ children: React.ReactNode, delay?: number }> = ({ children, delay = 0 }) => {
  const [isVisible, setIsVisible] = useState(false);
  const domRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const observer = new IntersectionObserver(entries => {
      entries.forEach(entry => {
        if (entry.isIntersecting) {
          setTimeout(() => setIsVisible(true), delay);
        }
      });
    }, { threshold: 0.1 });

    const { current } = domRef;
    if (current) observer.observe(current);
    return () => { if (current) observer.unobserve(current); };
  }, [delay]);

  return (
    <div
      ref={domRef}
      className={`transition-all duration-700 ease-out transform ${
        isVisible ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-8'
      }`}
    >
      {children}
    </div>
  );
};

