const DetailedHistoryChart: React.FC<{ 
    data: ChartDataPoint[]; 
    color: string; 
    metricKey: string;
    unit: string;
    referenceRange?: { min: number; max: number };
}> = ({ data, color, metricKey, unit, referenceRange }) => {
    if (data.length === 0) return <div className="h-64 flex flex-col items-center justify-center bg-brand-gray-50 rounded-3xl"><p className="text-brand-gray-400 text-sm font-black uppercase tracking-wider">Sin historial registrado</p></div>;

    const width = 400; const height = 200; const paddingX = 40; const paddingY = 40;
    const values = data.map(d => d.value);

    let minVal = Math.min(...values);
    let maxVal = Math.max(...values);

    if (referenceRange) {
        minVal = Math.min(minVal, referenceRange.min);
        maxVal = Math.max(maxVal, referenceRange.max);
    }

    const rangeBuffer = (maxVal - minVal) * 0.3 || 10;
    minVal = Math.max(0, minVal - rangeBuffer);
    maxVal = maxVal + rangeBuffer;
    const range = maxVal - minVal || 1;

    const getX = (index: number) => paddingX + (index / Math.max(1, data.length - 1)) * (width - 2 * paddingX);
    const getY = (val: number) => height - paddingY - ((val - minVal) / range) * (height - 2 * paddingY);

    const pathD = data.map((d, i) => `${i === 0 ? 'M' : 'L'} ${getX(i)} ${getY(d.value)}`).join(' ');

    return (
        <div className="w-full bg-white p-6 rounded-[2rem] border border-brand-gray-100 shadow-soft">
            <svg viewBox={`0 0 ${width} ${height}`} className="w-full h-auto overflow-visible">
                {referenceRange && (
                    <rect 
                        x={paddingX} 
                        y={getY(referenceRange.max)} 
                        width={width - 2 * paddingX} 
                        height={Math.max(2, Math.abs(getY(referenceRange.min) - getY(referenceRange.max)))} 
                        fill="rgba(46, 125, 50, 0.15)" 
                        rx="8" 
                    />
                )}

                {[0, 0.5, 1].map(p => (
                    <line key={p} x1={paddingX} y1={paddingY + p * (height - 2 * paddingY)} x2={width - paddingX} y2={paddingY + p * (height - 2 * paddingY)} stroke="#F3F4F6" strokeWidth="1" strokeDasharray="6 6" />
                ))}

                <path d={pathD} fill="none" stroke={color} strokeWidth="5" strokeLinecap="round" strokeLinejoin="round" className="drop-shadow-md" />

                {data.map((d, i) => (
                    <g key={i} className="group cursor-pointer">
                        <circle cx={getX(i)} cy={getY(d.value)} r="7" fill="white" stroke={color} strokeWidth="4" />
                        <text x={getX(i)} y={getY(d.value) - 15} textAnchor="middle" className="text-[11px] font-black fill-brand-gray-900 opacity-0 group-hover:opacity-100 transition-opacity bg-white px-1">{d.value}</text>
                    </g>
                ))}

                {data.length > 0 && (
                    <>
                        <text x={getX(0)} y={height - 5} textAnchor="start" className="text-[10px] font-black fill-brand-gray-400 uppercase tracking-tighter">
                            {data[0].date.toLocaleDateString('es-ES', { day: 'numeric', month: 'short' })}
                        </text>
                        {data.length > 1 && (
                            <text x={getX(data.length - 1)} y={height - 5} textAnchor="end" className="text-[10px] font-black fill-brand-gray-400 uppercase tracking-tighter">
                                {data[data.length - 1].date.toLocaleDateString('es-ES', { day: 'numeric', month: 'short' })}
                            </text>
                        )}
                    </>
                )}
            </svg>
        </div>
    );
};

const HomeScreen: React.FC = () => {
    const { user, signOut } = useAuth();
    const { healthData, setHealthData, setDiaryPreferences, diaryPreferences, setVigsScore, vigsScore } = useContext(AppContext)!;
    const [profile, setProfile] = useState<UserProfile | null>(null);
    const [isProfileOpen, setIsProfileOpen] = useState(false);
    const [isEditing, setIsEditing] = useState(false);
    const [selectedMetric, setSelectedMetric] = useState<{key: keyof HealthData, label: string, unit: string} | null>(null);
    const [historyData, setHistoryData] = useState<ChartDataPoint[]>([]);
    const [fullHistory, setFullHistory] = useState<Record<string, number[]>>({});
    const [isLoading, setIsLoading] = useState(true);
    const [saveLoading, setSaveLoading] = useState(false);

    const [editName, setEditName] = useState("");
    const [editHeight, setEditHeight] = useState("");
    const [editDiaryPrefs, setEditDiaryPrefs] = useState<(keyof HealthData)[]>([]);

    const heightInMeters = (profile?.healthData.height || 170) / 100;
    const imcRange = { min: Math.round(18.5 * heightInMeters ** 2), max: Math.round(24.9 * heightInMeters ** 2) };

    const RECOMMENDED_RANGES: Record<string, { min: number; max: number }> = useMemo(() => ({
        systolicBP: { min: 110, max: 140 },
        diastolicBP: { min: 60, max: 90 },
        pulse: { min: 60, max: 100 },
        oxygenSaturation: { min: 95, max: 100 },
        glucose: { min: 70, max: 110 },
        calfCircumference: { min: 31, max: 45 },
        abdominalCircumference: { min: 70, max: 102 },
        weight: imcRange,
        falls: { min: 0, max: 0 }
    }), [imcRange]);

    const calculatedIndices = useMemo(() => {
        const vigs = vigsScore.index || (vigsScore.score / 25);
        const sys = healthData.systolicBP || 120;
        const dia = healthData.diastolicBP || 80;
        const falls = healthData.falls || 0;

        const prot = Math.max(0, Math.min(100, (1 - vigs) * 100));
        const cvRisk = Math.min(100, ((sys - 120) / 60 + (dia - 80) / 40) * 50);
        const fallRisk = Math.min(100, falls * 25);
        const hospRisk = Math.min(100, vigs * 100);

        return {
            protection: prot,
            cardio: cvRisk,
            falls: fallRisk,
            hospital: hospRisk
        };
    }, [vigsScore, healthData]);

    const loadProfile = async () => {
        if (!user) return;
        setIsLoading(true);
        try {
            const data = await getUserProfile(user.uid);
            if (data) {
                setProfile(data);
                setEditName(data.displayName);
                setEditHeight(data.healthData.height?.toString() || "");
                setEditDiaryPrefs(data.diaryPreferences);
                setHealthData(data.healthData);
                setDiaryPreferences(data.diaryPreferences);
                setVigsScore(data.vigsScore);
            }

            const logs = await getDailyHistory(user.uid);
            const historyMap: Record<string, number[]> = {};
            diaryOptions.forEach(opt => {
                historyMap[opt.id] = logs
                    .map(l => l[opt.id as keyof HealthData] as number | null)
                    .filter(v => v !== null)
                    .reverse() as number[];
            });
            setFullHistory(historyMap);

        } catch (e) { console.error(e); }
        finally { setIsLoading(false); }
    };

    useEffect(() => { loadProfile(); }, [user]);

    const handleMetricClick = async (key: keyof HealthData, label: string, unit: string) => {
        if (!user) return;
        setSelectedMetric({ key, label, unit });
        try {
            const logs = await getDailyHistory(user.uid);
            const chartData = logs
                .map(l => ({ date: l.createdAt, value: l[key] as number | null }))
                .filter(d => d.value !== null)
                .sort((a, b) => a.date.getTime() - b.date.getTime()) as ChartDataPoint[];
            setHistoryData(chartData);
        } catch (e) { console.error(e); }
    };

    const handleSaveProfile = async () => {
        if (!user) return;
        setSaveLoading(true);
        try {
            const updates: Partial<UserProfile> = {
                displayName: editName,
                diaryPreferences: editDiaryPrefs,
                healthData: { ...healthData, height: editHeight ? parseFloat(editHeight) : null }
            };
            await updateUserProfile(user.uid, updates);
            await loadProfile(); 
            setIsEditing(false);
        } catch (e) { alert("Error al actualizar."); }
        finally { setSaveLoading(false); }
    };

    const AvatarComponent = profile ? avatars[profile.avatarId] || avatars[0] : avatars[0];
    const displayVigs = parseFloat(vigsScore.index !== undefined ? vigsScore.index.toFixed(2) : (vigsScore.score / 25.0).toFixed(2));

    if (isLoading) return <div className="flex h-screen items-center justify-center bg-brand-bg"><div className="animate-spin rounded-full h-10 w-10 border-b-2 border-brand-blue"></div></div>;

    return (
        <div className="p-6 max-w-5xl mx-auto pb-32">
            <header className="flex justify-between items-center mb-10 pt-4">
                <ScrollReveal>
                  <div>
                      <p className="text-brand-gray-500 font-black uppercase tracking-[0.4em] text-[10px] mb-2">Monitor de Salud Senior</p>
                      <h1 className="text-4xl font-black text-brand-gray-900 tracking-tighter leading-tight">Buenos días, <br/><span className="text-brand-blue">{profile?.displayName?.split(' ')[0] || 'Usuario'}</span></h1>
                  </div>
                </ScrollReveal>
                <ScrollReveal delay={100}>
                  <button onClick={() => { setIsProfileOpen(true); setIsEditing(false); }} className="bg-white p-1 rounded-full shadow-soft hover:shadow-soft-lg transition-all active:scale-95 border-4 border-brand-blue/5">
                      <AvatarComponent className="w-16 h-16" />
                  </button>
                </ScrollReveal>
            </header>

            <ScrollReveal delay={200}>
              <h2 className="text-[11px] font-black text-brand-gray-400 uppercase tracking-[0.4em] mb-5 ml-2">Resumen de Bienestar</h2>
            </ScrollReveal>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 mb-16">
                <ScrollReveal delay={300}>
                  <IndexCard 
                      title="Fragilidad (VIGS)"
                      value={displayVigs.toFixed(2)}
                      percent={displayVigs * 100}
                      description="Independencia física y autonomía motriz."
                      category={vigsScore.category}
                      categoryClass={getVigsColorClass(vigsScore.category)}
                  />
                </ScrollReveal>
                <ScrollReveal delay={400}>
                  <IndexCard 
                      title="Protección"
                      value={`${calculatedIndices.protection.toFixed(0)}%`}
                      percent={calculatedIndices.protection}
                      invertedColor={true}
                      description="Grado de cobertura ante fragilidad severa."
                  />
                </ScrollReveal>
                <ScrollReveal delay={500}>
                  <IndexCard 
                      title="Riesgo Cardio"
                      value={calculatedIndices.cardio > 20 ? calculatedIndices.cardio.toFixed(0) : "Bien"}
                      percent={calculatedIndices.cardio}
                      description="Riesgo estimado por presión arterial."
                  />
                </ScrollReveal>
            </div>

            <ScrollReveal delay={600}>
              <h2 className="text-[11px] font-black text-brand-gray-400 uppercase tracking-[0.4em] mb-5 ml-2">Constantes Médicas</h2>
            </ScrollReveal>

            <div className="grid grid-cols-2 sm:grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-4">
                {diaryOptions.filter(opt => diaryPreferences.includes(opt.id as any)).map((opt, i) => {
                    const value = healthData[opt.id as keyof HealthData];
                    const unit = opt.label.includes('(') ? opt.label.split('(')[1].replace(')', '') : '';
                    const label = opt.label.split('(')[0].trim();
                    const history = fullHistory[opt.id] || [];

                    return (
                        <ScrollReveal key={opt.id} delay={100 * (i % 4)}>
                          <button 
                              onClick={() => handleMetricClick(opt.id as any, label, unit)}
                              className="bg-white p-6 rounded-[1.5rem] shadow-soft border border-brand-gray-50 text-left hover:shadow-soft-lg transition-all active:scale-95 group flex flex-col justify-between h-full"
                          >
                              <div>
                                  <div className="w-10 h-10 bg-brand-lightblue rounded-xl flex items-center justify-center text-brand-blue mb-4 group-hover:bg-brand-blue group-hover:text-white transition-colors">
                                      <CheckCircleIcon className="w-5 h-5" />
                                  </div>
                                  <h3 className="text-[9px] font-black text-brand-gray-400 uppercase tracking-widest mb-1 leading-tight">{label}</h3>
                                  <div className="flex items-baseline gap-1">
                                      <span className="text-2xl font-black text-brand-gray-900 leading-none">{value ?? '--'}</span>
                                      <span className="text-[9px] font-bold text-brand-gray-400 uppercase">{unit}</span>
                                  </div>
                              </div>
                              <MiniSparkline data={history} color="#005A9C" />
                          </button>
                        </ScrollReveal>
                    );
                })}
            </div>

            {isProfileOpen && (
                <div className="fixed inset-0 z-50 flex items-end sm:items-center justify-center p-0 sm:p-6 bg-brand-gray-900/60 backdrop-blur-sm animate-fade-in">
                    <div className="bg-white w-full max-w-xl h-[90vh] sm:h-auto sm:max-h-[85vh] overflow-y-auto rounded-t-[2rem] sm:rounded-[2rem] shadow-soft-lg border-t border-brand-gray-100">
                        <div className="px-8 py-6 sticky top-0 bg-white/95 backdrop-blur flex justify-between items-center border-b border-brand-gray-50 z-20">
                            <h3 className="text-xl font-black text-brand-gray-900 uppercase tracking-tighter">Mi Perfil</h3>
                            <button onClick={() => setIsProfileOpen(false)} className="bg-brand-gray-100 p-2 rounded-full text-brand-gray-600 hover:text-brand-red transition-all"><XMarkIcon className="w-6 h-6"/></button>
                        </div>

                        <div className="p-8 pb-12">
                            <div className="flex flex-col items-center mb-10">
                                <div className="bg-brand-lightblue p-2 rounded-full ring-6 ring-brand-lightblue/30 mb-6">
                                    <AvatarComponent className="w-24 h-24" />
                                </div>
                                {!isEditing ? (
                                    <div className="text-center">
                                        <h4 className="text-2xl font-black text-brand-gray-900 mb-1">{profile?.displayName}</h4>
                                        <p className="text-sm font-bold text-brand-gray-500 mb-6">{profile?.email}</p>
                                        <button onClick={() => setIsEditing(true)} className="px-8 py-4 bg-brand-lightblue text-brand-blue rounded-xl text-xs font-black uppercase tracking-widest hover:bg-brand-blue hover:text-white transition-all shadow-sm flex items-center gap-2 mx-auto"><PencilSquareIcon className="w-4 h-4" /> Editar Datos</button>
                                    </div>
                                ) : (
                                    <div className="w-full space-y-4">
                                        <input type="text" value={editName} onChange={e => setEditName(e.target.value)} className="w-full p-4 bg-white border-2 border-brand-gray-200 rounded-xl font-black text-lg text-brand-gray-900 focus:border-brand-blue outline-none" placeholder="Nombre completo" />
                                        <input type="number" value={editHeight} onChange={e => setEditHeight(e.target.value)} className="w-full p-4 bg-white border-2 border-brand-gray-200 rounded-xl font-black text-lg text-brand-gray-900 focus:border-brand-blue outline-none" placeholder="Altura en cm" />
                                    </div>
                                )}
                            </div>

                            <div className="space-y-3">
                                <h5 className="text-[11px] font-black text-brand-gray-400 uppercase tracking-widest mb-3 ml-2">¿Qué quiero medir hoy?</h5>
                                {diaryOptions.map(opt => {
                                    const isSel = isEditing ? editDiaryPrefs.includes(opt.id as any) : diaryPreferences.includes(opt.id as any);
                                    return (
                                        <button 
                                            key={opt.id}
                                            disabled={!isEditing}
                                            onClick={() => setEditDiaryPrefs(prev => prev.includes(opt.id as any) ? prev.filter(x => x !== opt.id) : [...prev, opt.id as any])}
                                            className={`w-full flex items-center justify-between p-4 rounded-xl border-2 transition-all ${isSel ? 'border-brand-blue bg-blue-50/50' : 'border-brand-gray-100 bg-white opacity-60'}`}
                                        >
                                            <span className={`font-black uppercase text-[10px] tracking-widest ${isSel ? 'text-brand-blue' : 'text-brand-gray-900'}`}>{opt.label}</span>
                                            {isSel && <CheckCircleIcon className="w-6 h-6 text-brand-blue" />}
                                        </button>
                                    );
                                })}
                            </div>

                            <div className="mt-12 pt-8 border-t border-brand-gray-50 flex gap-4">
                                {isEditing ? (
                                    <>
                                        <button onClick={() => setIsEditing(false)} className="flex-1 py-5 bg-brand-gray-100 text-brand-gray-900 rounded-xl font-black text-xs uppercase tracking-widest">Cancelar</button>
                                        <button onClick={handleSaveProfile} disabled={saveLoading} className="flex-[2] py-5 bg-brand-blue text-white rounded-xl font-black text-xs uppercase tracking-widest shadow-soft">Guardar</button>
                                    </>
                                ) : (
                                    <button onClick={() => signOut()} className="w-full py-5 text-brand-red font-black text-xs uppercase tracking-widest border border-brand-soft-red bg-brand-soft-red rounded-xl shadow-sm">Cerrar Sesión</button>
                                )}
                            </div>
                        </div>
                    </div>
                </div>
            )}

            {selectedMetric && (
                <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-brand-gray-900/80 backdrop-blur-md animate-fade-in">
                    <div className="bg-white w-full max-w-3xl rounded-[2.5rem] shadow-soft-lg overflow-hidden border border-brand-gray-100 flex flex-col max-h-[90vh]">
                        <div className="p-8 border-b border-brand-gray-50 shrink-0">
                            <div className="flex justify-between items-start">
                                <div>
                                    <h3 className="text-3xl font-black text-brand-gray-900 tracking-tighter uppercase leading-none">{selectedMetric.label}</h3>
                                    <p className="text-xs font-black text-brand-blue uppercase tracking-widest mt-3">Historial Clínico</p>
                                </div>
                                <button onClick={() => setSelectedMetric(null)} className="text-brand-gray-500 bg-brand-gray-100 p-3 rounded-full hover:text-brand-red transition-all"><XMarkIcon className="w-7 h-7"/></button>
                            </div>
                        </div>

                        <div className="p-8 overflow-y-auto space-y-12">
                            <DetailedHistoryChart 
                                data={historyData} 
                                color="#005A9C" 
                                metricKey={selectedMetric.key}
                                unit={selectedMetric.unit}
                                referenceRange={RECOMMENDED_RANGES[selectedMetric.key]} 
                            />

                            <div>
                                <h4 className="text-[12px] font-black text-brand-gray-400 uppercase tracking-[0.3em] mb-6 ml-2">Registros Recientes</h4>
                                <div className="space-y-3">
                                    {historyData.slice().reverse().map((record, index) => (
                                        <div key={index} className="bg-brand-gray-50 p-6 rounded-2xl border border-transparent hover:border-brand-blue/20 hover:bg-white flex justify-between items-center transition-all shadow-sm">
                                            <div>
                                                <p className="text-[10px] font-black text-brand-gray-400 uppercase tracking-widest">{record.date.toLocaleDateString('es-ES', { day: 'numeric', month: 'long', year: 'numeric' })}</p>
                                                <p className="text-xs font-bold text-brand-gray-500 mt-1 uppercase">{record.date.toLocaleTimeString('es-ES', { hour: '2-digit', minute: '2-digit' })}</p>
                                            </div>
                                            <div className="text-right">
                                                <span className="text-3xl font-black text-brand-gray-900 tracking-tighter">{record.value}</span>
                                                <span className="text-[10px] font-black text-brand-gray-400 uppercase ml-2">{selectedMetric.unit}</span>
                                            </div>
                                        </div>
                                    ))}
                                    {historyData.length === 0 && (
                                        <div className="text-center py-12 bg-brand-gray-50 rounded-2xl">
                                            <p className="text-brand-gray-400 font-bold text-sm">Sin registros previos.</p>
                                        </div>
                                    )}
                                </div>
                            </div>
                        </div>

                        <div className="p-8 bg-brand-gray-50 border-t border-brand-gray-100 shrink-0">
                            <button onClick={() => setSelectedMetric(null)} className="w-full bg-brand-gray-900 text-white font-black py-5 rounded-2xl text-xs uppercase tracking-widest shadow-soft">Volver al Inicio</button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

export default HomeScreen;

export interface HealthData {
  weight: number | null;
  falls: number | null;
  systolicBP: number | null; // Tensión Alta
  diastolicBP: number | null; // Tensión Baja
  pulse: number | null;
  oxygenSaturation: number | null;
  glucose: number | null;
  calfCircumference: number | null;
  abdominalCircumference: number | null;
  height?: number | null; 
}

export type VigsCategory = 'No frágil' | 'Fragilidad leve' | 'Fragilidad moderada' | 'Fragilidad severa';
export type SmokingStatus = 'Nunca' | 'Ex-fumador' | 'Activo';

export interface VigsScore {
  score: number;
  category: VigsCategory;
  index?: number; // El valor decimal (0.00 - 1.00)
}

export interface Alert {
  id: number;
  type: 'info' | 'warning' | 'success' | 'danger';
  title: string;
  message: string;
  isRecommendation?: boolean;
}

export interface Biomarkers {
    hemoglobin: string;
    albumin: string;
    vitaminD: string;
    glucoseFasting: string;
    egfr: string;
    sodium: string;
    crp: string;
    vitaminB12: string;
    tsh: string;
    creatinine: string;
}

export interface ClinicalAnalysisResult {
  summary: string;
  biomarkers: Biomarkers;
  recommendations: string[];
}

export interface NutritionalAnalysisResult {
    calories: string;
    macros: {
        protein: string;
        carbs: string;
        fatsTotal: string;
        fatsSaturated: string;
        fatsUnsaturated: string;
        fatsTrans: string;
        fiber: string;
    };
