const VoiceAssistantScreen: React.FC<{ onClose: () => void }> = ({ onClose }) => {
    const { user } = useAuth();
    const context = useContext(AppContext)!;
    const [connectionState, setConnectionState] = useState<'idle' | 'connecting' | 'connected' | 'error'>('idle');
    const [conversation, setConversation] = useState<{speaker: string, text: string}[]>([]);

    const sessionRef = useRef<any>(null);
    const inputAudioContextRef = useRef<AudioContext | null>(null);
    const outputAudioContextRef = useRef<AudioContext | null>(null);
    const nextStartTimeRef = useRef(0);
    const outputSourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());

    const startConversation = async () => {
        if (!user) return;
        setConnectionState('connecting');
        try {
            const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
            inputAudioContextRef.current = new AudioContext({ sampleRate: 16000 });
            outputAudioContextRef.current = new AudioContext({ sampleRate: 24000 });
            const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

            const sessionPromise = ai.live.connect({
                model: 'gemini-2.5-flash-native-audio-preview-12-2025',
                callbacks: {
                    onopen: () => {
                        const source = inputAudioContextRef.current!.createMediaStreamSource(stream);
                        const scriptProcessor = inputAudioContextRef.current!.createScriptProcessor(4096, 1, 1);
                        scriptProcessor.onaudioprocess = (e) => {
                            sessionPromise.then(s => s.sendRealtimeInput({ media: createBlob(e.inputBuffer.getChannelData(0)) }));
                        };
                        source.connect(scriptProcessor);
                        scriptProcessor.connect(inputAudioContextRef.current!.destination);
                    },
                    onmessage: async (message: LiveServerMessage) => {
                        if (message.toolCall) {
                            for (const fc of message.toolCall.functionCalls) {
                                if (fc.name === 'saveHealthData') {
                                    const merged = { ...context.healthData, ...fc.args };
                                    await saveDailyLog(user.uid, merged);
                                    context.setHealthData(merged);
                                    setConversation(p => [...p, { speaker: 'system', text: "Datos médicos guardados." }]);
                                } else if (fc.name === 'recordMeal') {
                                    const { mealDescription, estimatedCalories, protein, carbs, fats, healthScore } = fc.args as any;
                                    const newNutri: NutritionalAnalysis = {
                                        id: Date.now().toString(),
                                        imagePreview: 'https://via.placeholder.com/300?text=Comida+Voz',
                                        createdAt: new Date(),
                                        analysis: {
                                            calories: estimatedCalories.toString(),
                                            portions: mealDescription,
                                            macros: { protein: protein.toString(), carbs: carbs.toString(), fatsTotal: fats.toString(), fatsSaturated: '0', fatsUnsaturated: '0', fatsTrans: '0', fiber: '0' },
                                            micros: { calcium: '0', vitaminD: '0', vitaminB12: '0', iron: '0', sodium: '0', potassium: '0' },
                                            suggestions: []
                                        }
                                    };
                                    await saveNutritionLog(user.uid, newNutri);
                                    const newScore = Math.min(100, (context.nutritionalAnalyses.length * 5) + healthScore / 2);
                                    await updateUserProfile(user.uid, { nutritionalScore: newScore });
                                    context.setNutritionalAnalyses(p => [newNutri, ...p]);
                                    setConversation(p => [...p, { speaker: 'system', text: `Comida registrada: ${mealDescription}. Score nutricional actualizado.` }]);
                                }
                                sessionPromise.then(s => s.sendToolResponse({ functionResponses: { id: fc.id, name: fc.name, response: { result: "ok" } } }));
                            }
                        }
                        const audio = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
                        if (audio) {
                            const buffer = await decodeAudioData(decode(audio), outputAudioContextRef.current!, 24000, 1);
                            const source = outputAudioContextRef.current!.createBufferSource();
                            source.buffer = buffer;
                            source.connect(outputAudioContextRef.current!.destination);
                            nextStartTimeRef.current = Math.max(nextStartTimeRef.current, outputAudioContextRef.current!.currentTime);
                            source.start(nextStartTimeRef.current);
                            nextStartTimeRef.current += buffer.duration;
                        }
                    }
                },
                config: {
                    responseModalities: [Modality.AUDIO],
                    tools: [{ functionDeclarations: [saveHealthDataTool, recordMealTool] }],
                    systemInstruction: "Eres un asistente de salud geriátrica. Ayuda al paciente a registrar sus datos médicos y sus comidas. Sé cálido y conciso."
                }
            });
            sessionRef.current = await sessionPromise;
            setConnectionState('connected');
        } catch (e) { setConnectionState('error'); }
    };

    useEffect(() => { startConversation(); return () => sessionRef.current?.close(); }, []);

    return (
        <div className="p-8 flex flex-col h-full bg-brand-bg relative">
            <button onClick={onClose} className="absolute top-8 right-8 p-3 bg-white rounded-full shadow-soft"><XMarkIcon /></button>
            <header className="mb-12 text-center">
                <h1 className="text-4xl font-black text-brand-gray-900 tracking-tighter">Asistente Fisiosilver</h1>
                <p className="text-brand-gray-500 mt-2 font-bold uppercase tracking-widest text-[10px]">Cuénteme sus datos o sus comidas</p>
            </header>
            <div className="flex-1 bg-white rounded-v-xl p-8 overflow-y-auto mb-8 shadow-inner border border-brand-gray-50">
                {conversation.map((t, i) => (
                    <div key={i} className={`mb-4 ${t.speaker === 'user' ? 'text-right' : 'text-left'}`}>
                        <span className={`inline-block p-4 rounded-2xl font-bold text-sm ${t.speaker === 'system' ? 'bg-brand-soft-green text-brand-green' : 'bg-brand-gray-100'}`}>{t.text}</span>
                    </div>
                ))}
            </div>
            <div className="flex justify-center">
                <div className={`p-10 rounded-full bg-brand-blue text-white shadow-soft-lg ${connectionState === 'connected' ? 'animate-pulse' : 'opacity-50'}`}>
                    <MicrophoneIcon />
                </div>
            </div>
        </div>
    );
};

