      fats: { type: Type.NUMBER, description: "Gramos de grasas." },
      healthScore: { type: Type.NUMBER, description: "Puntuación de salud de 0 a 100 para este plato." }
    },
    required: ["mealDescription", "estimatedCalories"]
  }
};

const VoiceAssistantScreen: React.FC<{ onClose: () => void }> = ({ onClose }) => {
    const { user } = useAuth();
    const context = useContext(AppContext)!;
    const [connectionState, setConnectionState] = useState<'idle' | 'connecting' | 'connected' | 'error'>('idle');
    const [conversation, setConversation] = useState<{speaker: string, text: string}[]>([]);

    const sessionRef = useRef<any>(null);
    const inputAudioContextRef = useRef<AudioContext | null>(null);
    const outputAudioContextRef = useRef<AudioContext | null>(null);
    const nextStartTimeRef = useRef(0);
    const scriptProcessorRef = useRef<ScriptProcessorNode | null>(null);

    const startConversation = async () => {
        if (!user) return;
        setConnectionState('connecting');
        try {
            const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
            inputAudioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
            outputAudioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });

            // Forzar reanudación por políticas de autoplay
            await inputAudioContextRef.current.resume();
            await outputAudioContextRef.current.resume();

            const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

            const sessionPromise = ai.live.connect({
                model: 'gemini-2.5-flash-native-audio-preview-12-2025',
                callbacks: {
                    onopen: () => {
                        const source = inputAudioContextRef.current!.createMediaStreamSource(stream);
                        const scriptProcessor = inputAudioContextRef.current!.createScriptProcessor(4096, 1, 1);
                        scriptProcessorRef.current = scriptProcessor;
                        scriptProcessor.onaudioprocess = (e) => {
                            sessionPromise.then(s => s.sendRealtimeInput({ media: createBlob(e.inputBuffer.getChannelData(0)) }));
                        };
                        source.connect(scriptProcessor);
                        scriptProcessor.connect(inputAudioContextRef.current!.destination);
                        setConnectionState('connected');
                        setConversation([{ speaker: 'system', text: "Hola, soy Fisiosilver. ¿En qué puedo ayudarle hoy?" }]);
                    },
                    onmessage: async (message: LiveServerMessage) => {
                        if (message.toolCall) {
                            for (const fc of message.toolCall.functionCalls) {
                                if (fc.name === 'saveHealthData') {
                                    const merged = { ...context.healthData, ...fc.args };
                                    await saveDailyLog(user.uid, merged);
                                    context.setHealthData(merged);
                                    setConversation(p => [...p, { speaker: 'system', text: "Entendido, he guardado sus mediciones en el diario." }]);
                                } else if (fc.name === 'recordMeal') {
                                    const { mealDescription, estimatedCalories, protein, carbs, fats, healthScore } = fc.args as any;
                                    const newNutri: NutritionalAnalysis = {
                                        id: Date.now().toString(),
                                        imagePreview: 'https://via.placeholder.com/300?text=Registro+Voz',
                                        createdAt: new Date(),
                                        analysis: {
                                            calories: estimatedCalories?.toString() || '0',
                                            portions: mealDescription,
                                            macros: { protein: protein?.toString() || '0', carbs: carbs?.toString() || '0', fatsTotal: fats?.toString() || '0', fatsSaturated: '0', fatsUnsaturated: '0', fatsTrans: '0', fiber: '0' },
                                            micros: { calcium: '0', vitaminD: '0', vitaminB12: '0', iron: '0', sodium: '0', potassium: '0' },
                                            suggestions: []
                                        }
                                    };
                                    await saveNutritionLog(user.uid, newNutri);
                                    const newScore = Math.min(100, (context.nutritionalAnalyses.length * 5) + (healthScore || 70) / 2);
                                    await updateUserProfile(user.uid, { nutritionalScore: newScore });
                                    context.setNutritionalAnalyses(p => [newNutri, ...p]);
                                    setConversation(p => [...p, { speaker: 'system', text: `He registrado su comida: ${mealDescription}.` }]);
                                }
                                sessionPromise.then(s => s.sendToolResponse({ functionResponses: { id: fc.id, name: fc.name, response: { result: "ok" } } }));
                            }
                        }
                        const audio = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
                        if (audio) {
                            const buffer = await decodeAudioData(decode(audio), outputAudioContextRef.current!, 24000, 1);
                            const source = outputAudioContextRef.current!.createBufferSource();
                            source.buffer = buffer;
                            source.connect(outputAudioContextRef.current!.destination);
                            nextStartTimeRef.current = Math.max(nextStartTimeRef.current, outputAudioContextRef.current!.currentTime);
                            source.start(nextStartTimeRef.current);
                            nextStartTimeRef.current += buffer.duration;
                        }
                        if (message.serverContent?.interrupted) {
                            // Limpiar buffers si el modelo es interrumpido por el usuario
                            nextStartTimeRef.current = 0;
                        }
                    },
                    onerror: (e) => { console.error("Error en Live Session:", e); setConnectionState('error'); },
                    onclose: () => setConnectionState('idle')
                },
                config: {
                    responseModalities: [Modality.AUDIO],
                    tools: [{ functionDeclarations: [saveHealthDataTool, recordMealTool] }],
                    speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Charon' } } },
                    systemInstruction: "Eres un asistente de salud geriátrica amable y profesional llamado Fisiosilver. Ayuda a los pacientes mayores a registrar sus constantes médicas (peso, tensión, azúcar) y sus comidas. Sé muy conciso en tus respuestas habladas para no cansar al usuario. Saluda al iniciar."
                }
            });
            sessionRef.current = await sessionPromise;
        } catch (e) { 
          console.error("Error al iniciar asistente:", e); 
          setConnectionState('error'); 
        }
    };

    useEffect(() => { 
        startConversation(); 
        return () => {
            sessionRef.current?.close();
            inputAudioContextRef.current?.close();
            outputAudioContextRef.current?.close();
        }; 
    }, []);

    return (
        <div className="p-8 flex flex-col h-full bg-brand-bg relative">
            <button onClick={onClose} className="absolute top-8 right-8 p-3 bg-white rounded-full shadow-soft transition-all active:scale-90"><XMarkIcon /></button>
            <header className="mb-12 text-center">
                <h1 className="text-4xl font-black text-brand-gray-900 tracking-tighter uppercase leading-none">Asistente<br/><span className="text-brand-blue">FISIOSILVER</span></h1>
                <p className="text-brand-gray-500 mt-3 font-bold uppercase tracking-widest text-[10px]">Interactúe usando su voz</p>
            </header>

            <div className="flex-1 bg-white rounded-v-xl p-8 overflow-y-auto mb-8 shadow-inner border border-brand-gray-50 space-y-4">
                {connectionState === 'connecting' && <p className="text-center text-brand-gray-400 font-black uppercase text-[10px] animate-pulse">Iniciando conexión segura...</p>}
                {connectionState === 'error' && <p className="text-center text-brand-red font-black uppercase text-[10px]">Error al conectar. Por favor, reintente.</p>}

                {conversation.map((t, i) => (
                    <div key={i} className={`flex ${t.speaker === 'user' ? 'justify-end' : 'justify-start'}`}>
                        <div className={`max-w-[80%] p-5 rounded-[2rem] shadow-sm ${t.speaker === 'system' ? 'bg-brand-lightblue text-brand-blue font-black' : 'bg-brand-gray-100 text-brand-gray-900 font-bold'}`}>
                            <p className="text-sm leading-relaxed">{t.text}</p>
                        </div>
                    </div>
                ))}
            </div>

            <div className="flex flex-col items-center">
                <div className={`p-10 rounded-full transition-all duration-500 ${connectionState === 'connected' ? 'bg-brand-blue text-white shadow-xl scale-110 animate-pulse' : 'bg-brand-gray-200 text-brand-gray-400 opacity-50'}`}>
                    <MicrophoneIcon />
                </div>
                <p className="mt-6 text-[11px] font-black text-brand-gray-400 uppercase tracking-widest">
                    {connectionState === 'connected' ? 'Escuchando con atención...' : 'Conectando micrófono...'}
                </p>
            </div>
        </div>
    );
};

