```ts
/**
 * Uploads a file to Supabase storage.
 * @param bucket - The storage bucket name.
 * @param file - The file to upload.
 * @returns The public URL of the uploaded file.
 */
export const uploadFile = async (bucket: string, file: File): Promise<string> => {
    if (isDemo) return URL.createObjectURL(file);
    const fileName = `${Date.now()}_${file.name}`;
    const { data, error } = await supabase.storage.from(bucket).upload(fileName, file);
    if (error) throw new Error(getErrorMessage(error));
    const { data: publicUrlData } = supabase.storage.from(bucket).getPublicUrl(fileName);
    return publicUrlData.publicUrl;
};

/**
 * Saves a clinical report analysis to the database.
 * @param uid - The user's unique ID.
 * @param analysis - The clinical analysis object to save.
 */
export const saveClinicalReport = async (uid: string, analysis: ClinicalAnalysis): Promise<void> => {
    if (isDemo) {
        console.warn('Demo mode: Skipping saveClinicalReport');
        return;
    }
    const { data, error } = await supabase
        .from('clinical_reports')
        .insert([{ user_id: uid, analysis: analysis }])
        .select();

    if (error) {
        throw new Error(`Failed to save clinical report: ${getErrorMessage(error)}`);
    }
};

/**
 * Retrieves clinical reports for a given user.
 * @param uid - The user's unique ID.
 * @returns An array of clinical reports.
 */
export const getClinicalReports = async (uid: string): Promise<ClinicalReport[]> => {
    if (isDemo) {
        console.warn('Demo mode: Returning empty clinical reports');
        return [];
    }
    const { data, error } = await supabase
        .from('clinical_reports')
        .select('*')
        .eq('user_id', uid)
        .order('created_at', { ascending: false });

    if (error) {
        throw new Error(`Failed to get clinical reports: ${getErrorMessage(error)}`);
    }

    // Explicitly cast to ClinicalReport[]
    return (data as any[]).map((item) => ({
        id: item.id,
        user_id: item.user_id,
        analysis: item.analysis,
        created_at: new Date(item.created_at) // Ensuring correct date format
    }));
};
```


