    },
  }
};

const recordMealTool: FunctionDeclaration = {
  name: "recordMeal",
  description: "Registra lo que el usuario ha comido. Estima calorías y Nutri-Score.",
  parameters: {
    type: Type.OBJECT,
    properties: {
      mealDescription: { type: Type.STRING, description: "Descripción de la comida." },
